#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // Not strictly needed for this approach, but good practice for general algorithms

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        }
    }

    // To maximize the binary number, we should print all '1's first, then all '0's.
    // Each 'n' corresponds to one '1' (from the word "one").
    // Each 'z' corresponds to one '0' (from the word "zero").
    // The problem guarantees that it's possible to form words, so we don't need to
    // worry about other letters like 'e', 'r', 'o' not matching up.
    // The counts of 'n' and 'z' directly give us the number of '1's and '0's respectively.

    bool first_digit = true;

    for (int i = 0; i < count_n; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < count_z; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }

    std::cout << std::endl;

    return 0;
}

#include <iostream>
