#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks. This takes k trades of type 2.
        // Total sticks required: k * y (for coal) + k (for crafting) = k * (y + 1) sticks.
        // We start with 1 stick.
        // So, we need to acquire (k * (y + 1)) - 1 additional sticks using trade type 1.
        long long sticks_needed_from_trade1 = k * (y + 1) - 1;

        // Each trade of type 1 (1 stick -> x sticks) gives a net gain of (x - 1) sticks.
        long long gain_per_trade1 = x - 1;

        // Number of trades of type 1 required: ceil(sticks_needed_from_trade1 / gain_per_trade1)
        // Using integer division: (A + B - 1) / B for ceil(A / B)
        long long trades_type1 = (sticks_needed_from_trade1 + gain_per_trade1 - 1) / gain_per_trade1;

        // Total trades = trades for coal (type 2) + trades for sticks (type 1)
        long long total_trades = k + trades_type1;

        std::cout << total_trades << "\n";
    }
    return 0;
}

#include <iostream> // Required for input/output operations (cin, cout)

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This is generally good practice in competitive programming.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n; // Number of commands
    std::cin >> n;

    // Variables to store total successful packets and total packets sent for server 'a'
    long long successful_a = 0;
    long long total_sent_a = 0;

    // Variables to store total successful packets and total packets sent for server 'b'
    long long successful_b = 0;
    long long total_sent_b = 0;

    // Loop through each command
    for (int i = 0; i < n; ++i) {
        int type; // Type of server (1 for 'a', 2 for 'b')
        int x, y; // x successful packets, y lost packets
        std::cin >> type >> x >> y;

        if (type == 1) { // Command for server 'a'
            successful_a += x;
            total_sent_a += 10; // Each command sends 10 packets (x + y = 10)
        } else { // Command for server 'b'
            successful_b += x;
            total_sent_b += 10; // Each command sends 10 packets (x + y = 10)
        }
    }

    // Determine if server 'a' is "alive"
    // A server is "alive" if at least half of the packets reached it successfully.
    // This can be checked by successful_packets * 2 >= total_packets_sent.
    if (successful_a * 2 >= total_sent_a) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    // Determine if server 'b' is "alive"
    if (successful_b * 2 >= total_sent_b) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    return 0; // Indicate successful execution
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) { // Only consider numbers up to 2048
            counts[s_val]++;
        }
    }

    long long current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the contribution of this power of two to the current sum
        // We can think of this as having 'count' copies of 'val'.
        // Each 'val' contributes 'val' to the total sum that can be potentially merged.
        current_sum += static_cast<long long>(val) * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

