#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The problem asks for n distinct integers from 1 to 4n.
        // We need to select n numbers such that no two numbers a, b satisfy:
        // 1. gcd(a, b) = 1
        // 2. a divides b or b divides a
        //
        // A simple strategy is to pick numbers that are all even,
        // and specifically, numbers that are multiples of 2 but not multiples of each other.
        //
        // Consider picking numbers from the sequence: 2*n, 2*n-2, ..., 4.
        // This sequence is 2*k for k from 2 to n.
        // The numbers are 4, 6, 8, ..., 2n.
        // There are n-1 such numbers. We need n numbers.
        //
        // Let's try picking numbers in decreasing order, starting from 4n and going down.
        // If we pick only even numbers, gcd(a,b) will always be at least 2, satisfying condition 1.
        //
        // To avoid a divides b or b divides a, we need to be careful.
        //
        // Let's try picking numbers from 2n down to 2.
        // For n=2, range is 1 to 8. We need 2 numbers.
        // Example output: 6 4.
        // gcd(6,4)=2. 6 not div by 4, 4 not div by 6. This works.
        //
        // For n=3, range is 1 to 12. We need 3 numbers.
        // Example output: 4 6 10.
        // gcd(4,6)=2. 4 not div by 6, 6 not div by 4.
        // gcd(4,10)=2. 4 not div by 10, 10 not div by 4.
        // gcd(6,10)=2. 6 not div by 10, 10 not div by 6.
        // This works.
        //
        // For n=4, range is 1 to 16. We need 4 numbers.
        // Example output: 14 10 12 8.
        // All are even, so gcd > 1.
        // 8, 10, 12, 14. No number divides another. This works.
        //
        // It seems the strategy is to pick n distinct even numbers,
        // such that no number is a multiple of another.
        // The example outputs suggest picking numbers like 2*(n+1), 2*(n+2), ..., 2*(2n-1) or similar.
        //
        // Let's try picking numbers from 2n to 4n, but only even numbers.
        // The numbers are 2n, 2n+2, 2n+4, ..., 4n.
        // How many numbers are there in this sequence?
        // (4n - 2n)/2 + 1 = 2n/2 + 1 = n + 1 numbers.
        // We only need n numbers.
        //
        // If we pick n numbers from the sequence 2n, 2n+2, ..., 4n,
        // say we pick the largest n numbers: 4n, 4n-2, ..., 4n - 2*(n-1) = 4n - 2n + 2 = 2n+2.
        // These are n distinct even numbers.
        // For any two numbers a = 2k and b = 2j in this set,
        // if a divides b, then 2k divides 2j, which means k divides j.
        // Since all numbers are in the range [2n+2, 4n],
        // their halves are in the range [n+1, 2n].
        // In this range [n+1, 2n], no number can divide another number.
        // For example, if k divides j, and k, j are in [n+1, 2n],
        // then j >= 2k. But if k >= n+1, then 2k >= 2n+2.
        // This means j must be at least 2n+2, which is outside the range [n+1, 2n].
        // So, no number in [n+1, 2n] can divide another number in the same range.
        //
        // Therefore, picking the n largest even numbers from 1 to 4n,
        // which are 4n, 4n-2, ..., 4n - 2*(n-1) = 2n+2, will satisfy all conditions.
        //
        // Let's verify with examples:
        // n=2: 4n=8. Numbers are 8, 6. (2n+2 = 6, 4n = 8)
        // n=3: 4n=12. Numbers are 12, 10, 8. (2n+2 = 8, 4n = 12)
        // n=4: 4n=16. Numbers are 16, 14, 12, 10. (2n+2 = 10, 4n = 16)
        //
        // The example outputs are slightly different:
        // n=2: 6 4 (my strategy: 8 6)
        // n=3: 4 6 10 (my strategy: 12 10 8)
        // n=4: 14 10 12 8 (my strategy: 16 14 12 10)
        //
        // The example outputs for n=3 and n=4 are not the largest n even numbers.
        // For n=3, example output is 4, 6, 10.
        // Halves are 2, 3, 5. No number divides another.
        // For n=4, example output is 8, 10, 12, 14.
        // Halves are 4, 5, 6, 7. No number divides another.
        //
        // The example outputs seem to pick numbers from 2n to 4n-2, or similar.
        // The key is that the halves of the chosen numbers should be in a range [X, 2X-1] or similar,
        // where no number divides another.
        //
        // The range [n+1, 2n] for the halves works.
        // So, numbers 2*(n+1), 2*(n+2), ..., 2*(2n) = 4n.
        // This is a sequence of n numbers.
        // Let's try this: 2*(n+1), 2*(n+2), ..., 4n.
        //
        // n=2: 2*(2+1)=6, 2*(2+2)=8. Output: 6 8. (Example: 6 4)
        // n=3: 2*(3+1)=8, 2*(3+2)=10, 2*(3+3)=12. Output: 8 10 12. (Example: 4 6 10)
        // n=4: 2*(4+1)=10, 2*(4+2)=12, 2*(4+3)=14, 2*(4+4)=16. Output: 10 12 14 16. (Example: 14 10 12 8)
        //
        // My proposed solution (2*(n+1) to 4n) is valid, even if it doesn't match the example exactly.
        // The problem states "If there are multiple answers, print any of them."
        //
        // Let's re-check the example outputs.
        // n=2: 6 4. Halves: 3, 2. Range [2,3]. No division. OK.
        // n=3: 4 6 10. Halves: 2, 3, 5. Range [2,5]. No division. OK.
        // n=4: 14 10 12 8. Halves: 7, 5, 6, 4. Range [4,7]. No division. OK.
        //
        // The example outputs seem to pick numbers such that their halves are in the range [floor(N/2)+1, N] for some N.
        // For n=2, halves are 2,3. Max is 3. Range [2,3].
        // For n=3, halves are 2,3,5. Max is 5. Range [2,5].
        // For n=4, halves are 4,5,6,7. Max is 7. Range [4,7].
        //
        // It seems the example output picks numbers 2*k where k is in [n, 2n-1] or similar.
        // For n=2, 2*2=4, 2*3=6.
        // For n=3, 2*2=4, 2*3=6, 2*5=10. (Here 5 is not consecutive to 2,3)
        // For n=4, 2*4=8, 2*5=10, 2*6=12, 2*7=14.
        //
        // The simplest approach that works is to pick n numbers such that their halves are in the range [n+1, 2n].
        // These numbers are 2*(n+1), 2*(n+2), ..., 2*(2n).
        // All are even, so gcd is at least 2.
        // Their halves are n+1, n+2, ..., 2n.
        // In the range [n+1, 2n], no number can divide another.
        // Proof: If x divides y, and x, y are in [n+1, 2n], then y = k*x for some integer k.
        // Since x < y, k must be >= 2.
        // So y >= 2x.
        // But x >= n+1, so 2x >= 2(n+1) = 2n+2.
        // This means y >= 2n+2.
        // However, y is in [n+1, 2n], so y <= 2n.
        // This is a contradiction (y >= 2n+2 and y <= 2n).
        // Thus, no number in [n+1, 2n] can divide another number in the same range.
        //
        // So, the numbers 2*(n+1), 2*(n+2), ..., 2*(2n) are a valid set.
        // These are n distinct numbers.
        // The smallest is 2*(n+1). The largest is 2*(2n) = 4n.
        // All numbers are within the range [1, 4n].
        //
        // Let's implement this.
        for (int i = 0; i < n; ++i) {
            std::cout << 2 * (n + 1 + i) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s, t;
    std::cin >> s >> t;

    // If s and t have any common character, then it's possible.
    // Otherwise, it's not.
    // This is because if there's a common character 'c', say s[i] == 'c' and t[j] == 'c'.
    // We can propagate 'c' throughout string s (e.g., s[i] to s[i-1], s[i] to s[i+1], etc.)
    // until s becomes "ccc...c".
    // Similarly, we can propagate 'c' throughout string t until t becomes "ccc...c".
    // Thus, both strings can be transformed into "ccc...c", making them equal.
    // If there is no common character, then no character from s can ever appear in t,
    // and no character from t can ever appear in s.
    // Since the operation only copies adjacent characters within the same string,
    // a character from s can never become a character from t unless it was already present in s,
    // and vice versa.
    // Therefore, if they don't share any character, they can never be made equal.

    std::vector<bool> s_chars(26, false);
    for (char c : s) {
        s_chars[c - 'a'] = true;
    }

    bool common_char_found = false;
    for (char c : t) {
        if (s_chars[c - 'a']) {
            common_char_found = true;
            break;
        }
    }

    if (common_char_found) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

