    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <string>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_duration = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_duration += a[i];
    }

    if (total_duration % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_sum_per_post = total_duration / k;
    std::vector<int> s_values;
    long long current_sum = 0;
    int current_s_count = 0;
    bool possible = true;

    for (int i = 0; i < n; ++i) {
        current_sum += a[i];
        current_s_count++;

        if (current_sum == target_sum_per_post) {
            s_values.push_back(current_s_count);
            current_sum = 0;
            current_s_count = 0;
        } else if (current_sum > target_sum_per_post) {
            possible = false;
            break;
        }
    }

    if (possible && s_values.size() == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < k; ++i) {
            std::cout << s_values[i] << (i == k - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "No\n";
    }

    return 0;
}

