#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_price_suffix with the last element's price
    // This represents the minimum price encountered from the current position to the end of the array.
    // We iterate from right to left, so min_price_suffix will always hold the minimum
    // of elements a[i+1], a[i+2], ..., a[n-1] when we are at index i.
    int min_price_suffix = a[n - 1]; 

    // Iterate from the second to last element (n-2) down to the first element (0)
    for (int i = n - 2; i >= 0; --i) {
        // If the current price a[i] is greater than the minimum price found to its right,
        // then a[i] is a "bad" price.
        if (a[i] > min_price_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_price_suffix, it means a[i] is
            // either equal to or less than min_price_suffix.
            // In this case, a[i] becomes the new minimum for elements to its right
            // (including itself for future comparisons from further left).
            min_price_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

