int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // The first k+1 elements will generate k distinct differences.
    // We use a zig-zag pattern to generate differences k, k-1, ..., 1.
    // Example: if k=3, right=4.
    // Sequence: 1, 4, 2, 3
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. These are 3 distinct differences.
    // The numbers used are 1, 2, 3, 4.

    // The pattern is:
    // p_1 = left
    // p_2 = right
    // p_3 = left + 1
    // p_4 = right - 1
    // ...
    // This generates differences: (right - left), (right - (left+1)), ((right-1) - (left+1)), ...
    // Or more simply, it generates differences k, k-1, k-2, ..., 1.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index (0, 2, 4, ...) corresponds to left side
            std::cout << left++;
        } else { // Odd index (1, 3, 5, ...) corresponds to right side
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these in increasing order to ensure no new distinct differences are created.
    // The last number printed was either `left-1` or `right+1`.
    // If it was `left-1`, the next number is `left`.
    // If it was `right+1`, the next number is `right`.
    // In both cases, `left` now holds the smallest unused number (k+2).
    // So, we just print `left, left+1, ..., n`.
    for (int i = k + 1; i < n; ++i) {
        std::cout << left++;
        std::cout << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

