void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_elements;
    std::vector<int> available_elements;

    // p_1 must be q_1
    p[0] = q[0];
    used_elements.insert(q[0]);

    // Populate available_elements with numbers not used by q_i > q_{i-1}
    // and also check for invalid q_i values
    for (int i = 1; i <= n; ++i) {
        if (used_elements.find(i) == used_elements.end()) {
            available_elements.push_back(i);
        }
    }
    std::sort(available_elements.rbegin(), available_elements.rend()); // Descending order for easy pop_back

    bool possible = true;
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            if (used_elements.count(q[i])) {
                // q_i was already used, which is impossible for a permutation
                possible = false;
                break;
            }
            p[i] = q[i];
            used_elements.insert(q[i]);
            // Remove q[i] from available_elements if it was there
            // This is implicitly handled by how available_elements is constructed
            // and how we use it. We only add numbers not in used_elements initially.
            // If q[i] is a new max, it must be > q[i-1], so it's a new number.
            // If it was already in available_elements, it means it was not used by a previous p_j=q_j.
            // This logic is a bit tricky. Let's refine.
            // The initial available_elements contains all numbers not equal to q_0.
            // When p_i = q_i (new max), q_i is removed from available_elements.
            // A better way: available_elements should be numbers 1..n not yet assigned to p_j where p_j=q_j.
        } else { // q[i] == q[i-1]
            // p_i must be some unused number less than or equal to q[i]
            // To maximize chances of success, pick the largest available number that is <= q[i]
            // This is equivalent to picking the largest available number that is <= q[i-1]

            // Find the largest available number that is <= q[i]
            int chosen_val = -1;
            while (!available_elements.empty() && available_elements.back() > q[i]) {
                // These elements are too large for p_i, but might be needed later.
                // This means we need to be careful with available_elements.
                // The current approach of available_elements containing all unused numbers
                // and picking the largest one that fits is correct.
                // If available_elements.back() (smallest available) is > q[i], then no available element fits.
                // This means we need to iterate from the end (largest) of available_elements.
                // The current `available_elements` is sorted descending.
                // So `available_elements.front()` is the largest.
                // We need to find the largest `x` in `available_elements` such that `x <= q[i]`.
                // Since `available_elements` is sorted descending, we can just take `available_elements.front()`
                // if it's `<= q[i]`. If not, we need to pop elements until we find one or it's empty.
                // This implies `available_elements` should be a min-priority queue or a set for efficient removal.
                // Or, if we iterate from the end (smallest) of `available_elements` (which is sorted ascending),
                // we can find the largest `x <= q[i]`.
                // Let's re-think `available_elements`. It should be a set for efficient removal.
                // Or, if we use a vector, we need to iterate.
                // A `std::set` is better for `available_elements`.
                // Let's restart the logic for `available_elements`.
                possible = false; // This path is incorrect.
                break;
            }
            // Corrected logic for q[i] == q[i-1]:
            // We need to find an unused number `x` such that `x <= q[i]`.
            // To maximize chances for future steps, we should pick the smallest such `x`
            // or the largest such `x`. The problem asks for *any* valid permutation.
            // A common greedy strategy is to pick the smallest available number.
            // Let's use a `std::set` for `available_elements` to keep them sorted and allow efficient removal.
            // The `available_elements` set should contain all numbers from 1 to n that have not been assigned to `p_j` where `p_j = q_j`.
            // This means `available_elements` should be initialized with `1..n` and then `q_0` removed.
            // Then, for each `q_i > q_{i-1}`, `q_i` is removed.
            // For `q_i == q_{i-1}`, we pick from `available_elements`.
        }
    }

    // Re-implementing with a set for available numbers
    std::fill(p.begin(), p.end(), 0); // Reset p
    used_elements.clear(); // Reset used_elements

    p[0] = q[0];
    used_elements.insert(q[0]);

    std::set<int> unused_nums;
    for (int k = 1; k <= n; ++k) {
        if (k != q[0]) {
            unused_nums.insert(k);
        }
    }

    possible = true;
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // p_i must be q_i
            if (used_elements.count(q[i])) {
                // q_i was already used (e.g., q_i = q_j for j < i and p_j = q_j)
                possible = false;
                break;
            }
            p[i] = q[i];
            used_elements.insert(q[i]);
            unused_nums.erase(q[i]); // Remove from unused_nums
        } else { // q[i] == q[i-1]
            // p_i must be some unused number x <= q[i]
            // To maximize chances, we should pick the largest available number that is <= q[i].
            // This is because smaller numbers might be needed for later q_j == q_j-1 where q_j is smaller.
            // Using std::set::upper_bound to find the first element > q[i], then decrement to get largest <= q[i].
            auto it = unused_nums.upper_bound(q[i]);
            if (it == unused_nums.begin()) {
                // No number in unused_nums is <= q[i]
                possible = false;
                break;
            }
            --it; // Now it points to the largest element in unused_nums that is <= q[i]
            p[i] = *it;
            used_elements.insert(*it);
            unused_nums.erase(it);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

