    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This is the longest non-decreasing suffix.
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This is the longest non-increasing suffix before the non-decreasing suffix.
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing.
    // The segment a[j...n-1] is a candidate for a "good" array.
    // The prefix to remove would be a[0...j-1], so its length is j.

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horizontal_moves = std::min(counts['L'], counts['R']);
    int vertical_moves = std::min(counts['U'], counts['D']);

    std::string result = "";

    if (horizontal_moves == 0 && vertical_moves == 0) {
        // No moves possible
    } else if (horizontal_moves == 0) {
        // Only vertical moves possible, must be at least one pair
        result = "UD";
    } else if (vertical_moves == 0) {
        // Only horizontal moves possible, must be at least one pair
        result = "LR";
    } else {
        // Both horizontal and vertical moves possible
        // Construct the path: U...UD...D L...LR...R
        // Or: L...LR...R U...UD...D
        // The problem states "rearrange the remaining instructions as you wish"
        // A common valid pattern is to go up, then down, then left, then right.
        // Or up, left, down, right.
        // The simplest valid path that uses all available pairs is:
        // U...U (vertical_moves times)
        // L...L (horizontal_moves times)
        // D...D (vertical_moves times)
        // R...R (horizontal_moves times)
        // This forms a rectangle.

        for (int i = 0; i < vertical_moves; ++i) {
            result += 'U';
        }
        for (int i = 0; i < horizontal_moves; ++i) {
            result += 'L';
        }
        for (int i = 0; i < vertical_moves; ++i) {
            result += 'D';
        }
        for (int i = 0; i < horizontal_moves; ++i) {
            result += 'R';
        }
    }

    std::cout << result.length() << std::endl;
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

