int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_indexed[i].first;
        b_indexed[i].second = i; // Store original index
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Sort array B in ascending order based on its values
    std::sort(b_indexed.begin(), b_indexed.end());

    // Create the result array A_prime
    std::vector<long long> a_prime(m);

    // The strategy is to pair the smallest A_i with the smallest B_j,
    // the second smallest A_i with the second smallest B_j, and so on.
    // This is because F(n, k) = (n+1)/(k+1).
    // To maximize sum( (A_i' + 1) / (B_i + 1) ), we want to pair larger A_i' with smaller B_i.
    // However, the problem statement implies A_i >= B_j for all i, j.
    // The function F(n, k) = (n+1)/(k+1) is increasing with n and decreasing with k.
    // To maximize the sum, we want to pair the largest A_i with the smallest B_i,
    // the second largest A_i with the second smallest B_i, and so on.
    // This means sorting A ascending and B ascending, then pairing A[i] with B[m-1-i]
    // and placing it at the original index of B[m-1-i].

    // a is sorted ascending: a[0] <= a[1] <= ... <= a[m-1]
    // b_indexed is sorted ascending by value: b_indexed[0].first <= b_indexed[1].first <= ... <= b_indexed[m-1].first

    // We want to pair a[m-1] (largest A) with b_indexed[0].first (smallest B)
    // We want to pair a[m-2] (second largest A) with b_indexed[1].first (second smallest B)
    // ...
    // We want to pair a[0] (smallest A) with b_indexed[m-1].first (largest B)

    // So, a_prime[original_index_of_b_indexed[i]] = a[m-1-i]
    for (int i = 0; i < m; ++i) {
        a_prime[b_indexed[i].second] = a[m - 1 - i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
