#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int count01 = 0; // count of indices i where a[i]='0' and b[i]='1'
    int count10 = 0; // count of indices i where a[i]='1' and b[i]='0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i]='0', b[i]='1'
                if (count10 > 0) { // We have a '1' at some j where b[j]='0'
                    // We can swap a[i] and a[j].
                    // a[i] becomes '1' (correct for b[i])
                    // a[j] becomes '0' (correct for b[j])
                    // This fixes two mismatches with cost 0 (effectively, as we don't add |i-j| here)
                    // The cost |i-j| is implicitly handled by the greedy choice.
                    // We just need to decrement both counts.
                    count10--;
                } else {
                    // No '1' at j where b[j]='0' available for a swap.
                    // This '0' at a[i] must eventually become '1'.
                    // It can either be flipped (cost 1) or swapped with a '1' from a correct position.
                    // The greedy strategy is to pair it with a '1' from a[j] where b[j]='0' if possible.
                    // If not, it contributes to count01.
                    count01++;
                }
            } else { // a[i]='1', b[i]='0'
                if (count01 > 0) { // We have a '0' at some j where b[j]='1'
                    // We can swap a[i] and a[j].
                    // a[i] becomes '0' (correct for b[i])
                    // a[j] becomes '1' (correct for b[j])
                    count01--;
                } else {
                    // No '0' at j where b[j]='1' available for a swap.
                    // This '1' at a[i] must eventually become '0'.
                    count10++;
                }
            }
        }
    }

    // After iterating through all positions, count01 and count10 represent
    // the number of remaining mismatches that could not be resolved by a
    // "free" swap (i.e., swapping a[i]='0' with a[j]='1' where b[i]='1' and b[j]='0').
    // These remaining mismatches must be fixed by flips.
    // Each flip costs 1.
    cost = count01 + count10;

    std::cout << cost << std::endl;

    return 0;
}

