// Function to determine if Box 1 can be the special box
// Box 1: (-inf, -1]
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // If there's only one toy initially, it must be in Box 1.
    if (A + B + C + D == 1) {
        return A == 1;
    }

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors.
    // Negative factors come from Box 1 and Box 2.
    // Total negative factors: A + B
    // If A + B is odd, the final product can be negative.

    // Case 2: Final product has magnitude >= 1.
    // This requires at least one factor with magnitude > 1 (from Box 1 or Box 4)
    // OR all factors have magnitude = 1 (not possible with real numbers in ranges)
    // OR a sequence of multiplications that eventually leads to magnitude >= 1.
    // If there are any toys in Box 1 or Box 4, we can potentially achieve magnitude >= 1.
    // If all toys are in Box 2 and Box 3, the magnitude will always be < 1.

    // If A + B is odd (final product can be negative):
    if ((A + B) % 2 != 0) {
        // If there's at least one toy in Box 1 or Box 4, we can potentially make the magnitude >= 1.
        // We can always arrange multiplications to keep magnitude >= 1 if possible.
        // Example: if we have -3, 0.5, 2. We want -3 * 2 = -6 (Box 1).
        // We can multiply -3 * 2 first, then -6 * 0.5 = -3 (Box 1).
        // If we multiply 0.5 * 2 = 1 (Box 4), then -3 * 1 = -3 (Box 1).
        // The only way to *not* be able to achieve magnitude >= 1 is if all initial toys
        // are in Box 2 and Box 3.
        if (A > 0 || D > 0) { // At least one toy with magnitude >= 1
            return true;
        }
        // If all toys are in Box 2 and Box 3, the final product will have magnitude < 1.
        // So it cannot be in Box 1.
        // (A=0, D=0, B+C > 0)
        return false;
    }
    // If A + B is even (final product can be positive):
    else {
        // To be in Box 1, the product must be negative.
        // If A + B is even, the product is positive.
        // So, Box 1 is not possible if A + B is even.
        return false;
    }
}

// Function to determine if Box 2 can be the special box
// Box 2: (-1, 0)
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // If there's only one toy initially, it must be in Box 2.
    if (A + B + C + D == 1) {
        return B == 1;
    }

    // Case 1: Final product is negative.
    // This requires an odd number of negative factors (A + B is odd).
    // Case 2: Final product has magnitude < 1.
    // This requires that we can arrange multiplications such that the final magnitude is < 1.
    // This is always possible if there's at least one toy in Box 2 or Box 3.
    // If all toys are in Box 1 and Box 4, we can still make it < 1 if we have enough toys.
    // E.g., -3, -2, 0.1. (-3)*(-2) = 6. 6*0.1 = 0.6 (Box 3).
    // E.g., -3, 2, 0.1. (-3)*2 = -6. -6*0.1 = -0.6 (Box 2).

    // If A + B is odd (final product can be negative):
    if ((A + B) % 2 != 0) {
        // We need to be able to make the magnitude < 1.
        // If there are any toys in Box 2 or Box 3, we can use them to reduce magnitude.
        // If B + C > 0, we can always achieve magnitude < 1.
        // Example: -3, 2, 0.1. (-3)*2 = -6. -6*0.1 = -0.6 (Box 2).
        // Example: -3, -2, 0.1. (-3)*(-2) = 6. 6*0.1 = 0.6 (Box 3).
        // If we have only A and D toys, e.g., -3, 2. Product is -6 (Box 1).
        // If we have -3, -2. Product is 6 (Box 4).
        // If we have -3, 2, 4. Product is -24 (Box 1).
        // If we have -3, 2, 0.5. Product is -3 (Box 1).
        // If we have -3, 0.5, 0.5. Product is 0.75 (Box 3).
        // If we have -3, 0.5, 0.2. Product is 0.3 (Box 3).
        // If we have -3, 0.5, 0.2, 0.1. Product is 0.03 (Box 3).

        // The only way we *cannot* make the magnitude < 1 is if all toys have magnitude >= 1
        // AND there are not enough toys to multiply them down.
        // If B + C > 0, we can always achieve magnitude < 1.
        if (B + C > 0) {
            return true;
        }
        // If B + C == 0, all toys are in Box 1 or Box 4.
        // If A + D == 1, then the single toy is either in Box 1 or Box 4, so it cannot be Box 2.
        // If A + D > 1, we can always pick two toys, say x and y.
        // If we have a toy with magnitude < 1 (B or C > 0), we can always make the final product have magnitude < 1.
        // If B + C == 0, all toys are in Box 1 or Box 4.
        // If A + D > 0, and A + B is odd, then the product is negative.
        // Can we make the magnitude < 1?
        // If A + D > 1, we can pick two toys.
        // If we have -3, 2. Product -6 (Box 1).
        // If we have -3, -2. Product 6 (Box 4).
        // If we have -3, 2, 4. Product -24 (Box 1).
        // If we have -3, 2, 0.5. Product -3 (Box 1).
        // If we have -3, 0.5, 0.5. Product 0.75 (Box 3).
        // If we have -3, 0.5, 0.2. Product 0.3 (Box 3).
        // If we have -3, 0.5, 0.2, 0.1. Product 0.03 (Box 3).

        // If B + C == 0, all toys are in Box 1 or Box 4.
        // If A + D == 0, this case is impossible (total toys > 0).
        // If A + D == 1, then the single toy is in Box 1 or Box 4, not Box 2.
        // If A + D > 1, we can always pick two toys.
        // If we have at least two toys with magnitude >= 1, say x and y.
        // We can always pick a very small number (e.g., 0.000001) for one of the B or C toys.
        // And a very large number (e.g., 1000000) for one of the A or D toys.
        // The problem states "fun values, a real number".
        // This implies we can choose specific values.
        // If A+D > 0, we can pick a toy with large magnitude.
        // If B+C > 0, we can pick a toy with small magnitude.
        // If B+C > 0, we can always make the final product have magnitude < 1.
        // If B+C == 0, then all toys are in Box 1 or Box 4.
        // If A+D > 1, we can pick two toys.
        // If we have -3, 2. Product -6 (Box 1).
        // If we have -3, -2. Product 6 (Box 4).
        // If we have -3, 2, 4. Product -24 (Box 1).
        // If we have -3, 2, 0.5. Product -3 (Box 1).
        // If we have -3, 0.5, 0.5. Product 0.75 (Box 3).
        // If we have -3, 0.5, 0.2. Product 0.3 (Box 3).
        // If we have -3, 0.5, 0.2, 0.1. Product 0.03 (Box 3).

        // If B + C == 0, all toys are in Box 1 or Box 4.
        // If A + D == 1, then the single toy is in Box 1 or Box 4, not Box 2.
        // If A + D > 1, then we have at least two toys with magnitude >= 1.
        // The product of any two such toys will have magnitude >= 1.
        // So, if B + C == 0 and A + D > 1, the final product will always have magnitude >= 1.
        // Thus, it cannot be in Box 2.
        return false; // B+C == 0, so all toys are in A or D. Product magnitude will be >= 1.
    }
    // If A + B is even (final product can be positive):
    else {
        // To be in Box 2, the product must be negative.
        // If A + B is even, the product is positive.
        // So, Box 2 is not possible if A + B is even.
        return false;
    }
}

// Function to determine if Box 3 can be the special box
// Box 3: (0, 1)
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // If there's only one toy initially, it must be in Box 3.
    if (A + B + C + D == 1) {
        return C == 1;
    }

    // Case 1: Final product is positive.
    // This requires an even number of negative factors (A + B is even).
    // Case 2: Final product has magnitude < 1.
    // This requires that we can arrange multiplications such that the final magnitude is < 1.
    // This is always possible if there's at least one toy in Box 2 or Box 3.
    // If all toys are in Box 1 and Box 4, we can still make it < 1 if we have enough toys.

    // If A + B is even (final product can be positive):
    if ((A + B) % 2 == 0) {
        // We need to be able to make the magnitude < 1.
        // If B + C > 0, we can always achieve magnitude < 1.
        if (B + C > 0) {
            return true;
        }
        // If B + C == 0, all toys are in Box 1 or Box 4.
        // If A + D == 1, then the single toy is either in Box 1 or Box 4, so it cannot be Box 3.
        // If A + D > 1, then we have at least two toys with magnitude >= 1.
        // The product of any two such toys will have magnitude >= 1.
        // So, if B + C == 0 and A + D > 1, the final product will always have magnitude >= 1.
        // Thus, it cannot be in Box 3.
        return false; // B+C == 0, so all toys are in A or D. Product magnitude will be >= 1.
    }
    // If A + B is odd (final product can be negative):
    else {
        // To be in Box 3, the product must be positive.
        // If A + B is odd, the product is negative.
        // So, Box 3 is not possible if A + B is odd.
        return false;
    }
}

// Function to determine if Box 4 can be the special box
// Box 4: [1, inf)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // If there's only one toy initially, it must be in Box 4.
    if (A + B + C + D == 1) {
        return D == 1;
    }

    // Case 1: Final product is positive.
    // This requires an even number of negative factors (A + B is even).
    // Case 2: Final product has magnitude >= 1.
    // This requires at least one factor with magnitude > 1 (from Box 1 or Box 4)
    // OR a sequence of multiplications that eventually leads to magnitude >= 1.
    // If all toys are in Box 2 and Box 3, the magnitude will always be < 1.

    // If A + B is even (final product can be positive):
    if ((A + B) % 2 == 0) {
        // If there's at least one toy in Box 1 or Box 4, we can potentially make the magnitude >= 1.
        if (A > 0 || D > 0) { // At least one toy with magnitude >= 1
            return true;
        }
        // If all toys are in Box 2 and Box 3, the final product will have magnitude < 1.
        // So it cannot be in Box 4.
        return false;
    }
    // If A + B is odd (final product can be negative):
    else {
        // To be in Box 4, the product must be positive.
        // If A + B is odd, the product is negative.
        // So, Box 4 is not possible if A + B is odd.
        return false;
    }
}

