#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int win_count = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                win_count++;
                if (i == 0 || s[i - 1] == 'L') {
                    initial_score += 1;
                } else {
                    initial_score += 2;
                }
            }
        }

        if (win_count + k >= n) { // Can make all games 'W'
            if (n == 0) { // Edge case for n=0, though constraints say n>=1
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + 2 * (n - 1) << "\n";
            }
            continue;
        }

        if (win_count == 0) { // All 'L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + 2 * (k - 1) << "\n"; // Make k 'W's, forming a single streak
            }
            continue;
        }

        // If we reach here, win_count > 0 and win_count + k < n
        // This means we cannot make all games 'W'.
        // We want to convert 'L's to 'W's to extend existing 'W' streaks or create new ones.
        // Converting 'L's between 'W' streaks is most efficient.

        std::vector<int> gaps;
        int first_W = -1;
        int last_W = -1;

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // Collect gaps between 'W's
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int current_k = k;
        int max_score = initial_score;

        for (int gap_len : gaps) {
            if (current_k >= gap_len) {
                current_k -= gap_len;
                max_score += 2 * gap_len + 1; // Each L in gap becomes W, connecting two W streaks.
                                              // The gap_len L's become W's.
                                              // The first L in the gap connects to the previous W, giving 2 points.
                                              // The remaining gap_len-1 L's connect to the previous W, giving 2 points each.
                                              // The W after the gap now connects to the new W, giving 2 points instead of 1.
                                              // Total change: 2*gap_len for the L's, and +1 for the W after the gap.
                                              // This is equivalent to:
                                              // Each L becomes W: +1 point.
                                              // Each L becoming W also makes the next W (if any) give +1 point.
                                              // So, each L converted in a gap adds 2 points to the score.
                                              // And the connection of the two W-streaks adds 1 point.
                                              // Example: W L L W -> W W W W. Score change: (1+2+2) - (1+1) = 5-2 = 3.
                                              // gap_len = 2. 2*2 + 1 = 5. This is wrong.
                                              // Let's re-evaluate.
                                              // W L W -> W W W. Score change: (1+2+2) - (1+1) = 3. gap_len=1.
                                              // 2*gap_len + 1 = 3. This is correct for gap_len=1.
                                              // W L L W -> W W W W. Score change: (1+2+2+2) - (1+1) = 5. gap_len=2.
                                              // 2*gap_len + 1 = 5. This is correct.
                                              // So, 2*gap_len + 1 is correct for connecting gaps.
            } else {
                break;
            }
        }

        // After filling gaps, use remaining k to convert L's at ends of the string
        // or within existing W-streaks (which is less efficient, but we already have W-streaks).
        // Each remaining k can convert an L to a W.
        // If this L is adjacent to an existing W, it adds 2 points.
        // If it's not adjacent to any W (e.g., at the very beginning or end, or isolated), it adds 1 point.
        // Since we've already connected all possible internal gaps, any remaining k will be used to extend streaks.
        // Each L converted to W adds 2 points if it extends a streak (e.g., LWW -> WWW, score +2).
        // Or 1 point if it starts a new streak (e.g., LLW -> WLW, score +1).
        // But we already have a base score for existing Ws.
        // If we convert an L to W, it adds 1 point. If it's next to a W, it adds another 1 point (by making it a 2-point W).
        // So, each L converted to W adds 2 points if it extends a streak.
        // If it's an isolated L, it adds 1 point.
        // Since we have existing Ws, we can always extend a streak.
        // The only exception is if we have no Ws at all, which is handled above.
        // So, each remaining k adds 2 points.
        max_score += 2 * current_k;

        std::cout << max_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // The condition for a good array is S = 2 * X.
    // We need to append at most 3 elements.
    // Let the current sum be S and current XOR sum be X.
    // We want to find b1, b2, b3 such that (S + b1 + b2 + b3) = 2 * (X ^ b1 ^ b2 ^ b3).

    // Strategy:
    // 1. Append X.
    //    New sum S' = S + X
    //    New XOR sum X' = X ^ X = 0
    //    Condition: S' = 2 * X'  => S + X = 2 * 0 => S + X = 0.
    //    This is generally not true unless S=0 and X=0.
    //    However, if we append X, the XOR sum becomes 0.
    //    Now we need to make the sum 0.
    //    The current sum is S + X.
    //    We need to append another element 'y' such that (S + X + y) = 2 * (0 ^ y) = 2 * y.
    //    So, S + X + y = 2 * y  => S + X = y.
    //    So, we can append X and then (S + X).
    //    The elements to append are X and (S + X).
    //    The new array will have sum S + X + (S + X) = 2 * (S + X).
    //    The new array will have XOR sum X ^ X ^ (S + X) = 0 ^ (S + X) = S + X.
    //    The condition S_new = 2 * X_new becomes 2 * (S + X) = 2 * (S + X), which is always true.
    //    This strategy uses 2 elements: X and (S + X).

    // Output 2 elements: current_xor_sum and current_sum + current_xor_sum
    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

