int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b' (or its descendants).
            // Each 'a' to its left will cause this 'b' to duplicate.
            // The number of 'a's currently to the left (count_a)
            // determines how many times this 'b' will be involved in an 'ab' -> 'bba' operation.
            // Each such operation adds 1 to total_steps.
            total_steps = (total_steps + count_a) % MOD;

            // After all 'a's to its left have processed this 'b',
            // this 'b' effectively doubles itself for future 'a's further left.
            // This is because 'ab' -> 'bba'. The original 'b' is still there,
            // and a new 'b' is created. So, for any 'a's to the left of this 'b',
            // they will eventually interact with *two* 'b's for every original 'b'
            // that was to their right.
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now available
            // to interact with any 'b's to its right.
            // We increment the count of 'a's that are "active" and
            // waiting to interact with 'b's.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
