        long long r = num_zeros % (m + 1);

        long long k = k_minus_1 + 1; // Size of larger blocks
        long long num_larger_blocks = r;
        long long num_smaller_blocks = (m + 1) - r; // Size of smaller blocks is k-1

        // Calculate substrings of all zeros from these blocks
        long long substrings_of_zeros = 0;
        if (k_minus_1 >= 0) { // Ensure k-1 is non-negative
            substrings_of_zeros += num_smaller_blocks * (k_minus_1 * (k_minus_1 + 1) / 2);
        }
