    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n + 1, false);

    // Process vertices in reverse order of removal
    // This means we are adding vertices one by one to an initially empty graph
    // and updating all-pairs shortest paths.
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added" in this step

        active_vertices[k] = true; // Mark vertex k as active

        // Floyd-Warshall update step:
        // Consider paths that go through the newly added vertex k.
        // For any pair of currently active vertices (i, j),
        // the shortest path could now be i -> k -> j.
        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= n; ++j) {
                // Update paths involving k as an intermediate vertex
                dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
            }
        }

        // After updating all paths with k as an intermediate,
        // we also need to consider k as a source or destination for other active vertices.
        // The previous loop already handled dist[i][k] and dist[k][j] updates.
        // Now, we need to ensure all pairs (i, j) among active vertices
        // have their shortest paths updated, potentially using k as an endpoint.
        // The previous loop (dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]))
        // effectively updates all paths.
        // However, the standard Floyd-Warshall structure is:
        // for k:
        //   for i:
        //     for j:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This means k is the *intermediate* vertex.
        //
        // In our reversed approach, when we "add" vertex k, it becomes available
        // as an intermediate vertex for all *currently active* pairs (i, j).
        // It also becomes available as a source/destination.
        //
        // The loop `for (int i = 1; i <= n; ++i) { for (int j = 1; j <= n; ++j) { ... } }`
        // correctly updates `dist[i][j]` for all `i, j` using `k` as an intermediate.
        //
        // Now, we need to sum shortest paths *only* between currently active vertices.
        long long current_sum = 0;
        for (int i = 1; i <= n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 1; j <= n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first removal to last)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

