#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_zeros(n, 0); // left_zeros[i] = count of consecutive zeros ending at i
    std::vector<int> left_ones(n, 0);  // left_ones[i] = count of consecutive ones ending at i

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            left_zeros[i] = (i > 0 ? left_zeros[i - 1] : 0) + 1;
            left_ones[i] = 0;
        } else {
            left_ones[i] = (i > 0 ? left_ones[i - 1] : 0) + 1;
            left_zeros[i] = 0;
        }
    }

    std::vector<int> right_zeros(n, 0); // right_zeros[i] = count of consecutive zeros starting at i
    std::vector<int> right_ones(n, 0);  // right_ones[i] = count of consecutive ones starting at i

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            right_zeros[i] = (i < n - 1 ? right_zeros[i + 1] : 0) + 1;
            right_ones[i] = 0;
        } else {
            right_ones[i] = (i < n - 1 ? right_ones[i + 1] : 0) + 1;
            right_zeros[i] = 0;
        }
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0 && a[i - 1] == 1 && a[i + 1] == 1) { // 101 pattern
            int k_left = left_ones[i - 1];
            int k_right = right_ones[i + 1];
            int k = std::min(k_left, k_right);
            max_steps = std::max(max_steps, k);
            // The 0 at index i will become 1 after k steps.
            // The 1s at i-1, i+1 will remain 1.
            // The 0s at i-k+1 ... i+k-1 will become 1.
            // The 0 at index i will become 1.
            // The 0s at i-k+1 ... i-1 will become 1.
            // The 0s at i+1 ... i+k-1 will become 1.
            // This means the segment [i-k+1, i+k-1] will become all 1s.
            // The final value at index i will be 1.
            // The final values at indices i-k+1 to i+k-1 will be 1.
            for (int j = i - k + 1; j <= i + k - 1; ++j) {
                final_a[j] = 1;
            }
        } else if (a[i] == 1 && a[i - 1] == 0 && a[i + 1] == 0) { // 010 pattern
            int k_left = left_zeros[i - 1];
            int k_right = right_zeros[i + 1];
            int k = std::min(k_left, k_right);
            max_steps = std::max(max_steps, k);
            // The 1 at index i will become 0 after k steps.
            // The 0s at i-1, i+1 will remain 0.
            // The 1s at i-k+1 ... i+k-1 will become 0.
            // This means the segment [i-k+1, i+k-1] will become all 0s.
            // The final value at index i will be 0.
            // The final values at indices i-k+1 to i+k-1 will be 0.
            for (int j = i - k + 1; j <= i + k - 1; ++j) {
                final_a[j] = 0;
            }
        }
    }

    std::cout << max_steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_j to a very large positive value.
    // b_j represents the maximum possible initial value for a_j.
    // If a_j + current_delta_j <= m_i, then a_j <= m_i - current_delta_j.
    // So, a_j must be less than or equal to min(m_i - current_delta_j) over all relevant type 2 ops.
    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    // Calculate b_j values
    std::vector<long long> current_delta(n, 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Initialize a_j_prime to b_j. This is our candidate initial array.
    std::vector<long long> a_prime(n);
    for (int i = 0; i < n; ++i) {
        a_prime[i] = b[i];
    }

    // Verify the candidate array a_prime
    std::vector<long long> current_a(n);
    for (int i = 0; i < n; ++i) {
        current_a[i] = a_prime[i];
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_prime[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

