int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = static_cast<long long>(n) * (n + 1) / 2;
    long long invalid_pairs = 0;

    // last_valid_r[i] stores the maximum r such that the substring s[i...r-1]
    // does NOT contain any (x, x+k, x+2k) pattern.
    // If s[i...r-1] is invalid, then s[i...r] is also invalid.
    // So, last_valid_r[i] is the largest r such that s[i...r-1] is valid.
    // Or, more precisely, last_valid_r[i] is the smallest r_prime such that
    // s[i...r_prime-1] contains an invalid pattern.
    // If no such r_prime exists, it means s[i...n-1] is valid, so we can set r_prime to n+1.
    // Then, the number of valid r's for a fixed l=i+1 is (r_prime - 1) - (i+1) + 1 = r_prime - 1 - i.
    // The number of invalid r's for a fixed l=i+1 is n - (r_prime - 1) = n - r_prime + 1.

    // Let's define `min_r_for_l[i]` as the smallest `r` (1-based) such that
    // the substring `s[i...r-1]` (0-based) contains an invalid pattern.
    // If no such `r` exists for a given `l=i+1`, then `min_r_for_l[i]` can be `n+1`.
    // For a fixed `l=i+1`, any `r` from `min_r_for_l[i]` to `n` will form an invalid pair `(l, r)`.
    // The count of such `r` values is `n - min_r_for_l[i] + 1`.
    // We need to sum this over all `i` from `0` to `n-1`.

    // Initialize min_r_for_l with n+1, meaning initially no invalid pattern found for any l.
    std::vector<int> min_r_for_l(n, n + 1);

    // Iterate through all possible starting positions x (0-based)
    for (int x = 0; x < n; ++x) {
        // Iterate through all possible k values
        // x + 2k must be less than n
        // So, 2k < n - x  => k < (n - x) / 2
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x] == s[x + 2 * k]) {
                // Found a pattern s[x] == s[x+k] == s[x+2k]
                // This pattern makes any (l, r) pair invalid if l <= x+1 and r >= x+2k+1.
                // The smallest r (1-based) that includes this pattern is x+2k+1.
                // The smallest l (1-based) that includes this pattern is x+1.
                // So, for any l_idx from 0 to x (0-based),
                // the pair (l_idx+1, x+2k+1) is an invalid pair.
                // We want to find the *minimum* r for each l.
                // So, for l_idx = x, the minimum r is x+2k+1.
                // For l_idx = x-1, the minimum r is x+2k+1 (if it's smaller than previous min_r_for_l[x-1]).
                // And so on, down to l_idx = 0.

                // The pattern starts at index x and ends at index x+2k.
                // The 1-based indices are x+1 and x+2k+1.
                // For any l_0based from 0 to x, the pair (l_0based+1, x+2k+1) is invalid.
                // We update min_r_for_l[l_0based] with min(current_value, x+2k+1).

                // This loop iterates from x down to 0.
                // For each l_0based, we update min_r_for_l[l_0based].
                // This ensures that min_r_for_l[l_0based] stores the smallest r (1-based)
                // that makes the substring s[l_0based...r-1] contain *any* such pattern.
                for (int l_0based = x; l_0based >= 0; --l_0based) {
                    min_r_for_l[l_0based] = std::min(min_r_for_l[l_0based], x + 2 * k + 1);
                }
            }
        }
    }

    // Sum up the count of invalid r's for each l.
    for (int i = 0; i < n; ++i) {
        // For a fixed l (1-based index i+1),
        // if min_r_for_l[i] is n+1, it means no pattern was found for this l,
        // so all r from i+1 to n are valid.
        // If min_r_for_l[i] is some value R_min <= n,
        // then any r from R_min to n makes the pair (i+1, r) invalid.
        // The count of such r's is n - R_min + 1.
        if (min_r_for_l[i] <= n) {
            invalid_pairs += (n - min_r_for_l[i] + 1);
        }
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

