bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> head_reach_left(n);
    std::vector<long long> head_reach_right(n);
    for (int i = 0; i < n; ++i) {
        head_reach_left[i] = h[i] - T;
        head_reach_right[i] = h[i] + T;
    }

    int p_idx = 0;
    for (int h_idx = 0; h_idx < n && p_idx < m; ++h_idx) {
        // Find the first p_j that this head can reach
        // p_j must be >= head_reach_left[h_idx]
        // And p_j must be <= head_reach_right[h_idx]

        // If current head cannot reach current p_idx, skip this head
        if (p[p_idx] > head_reach_right[h_idx]) {
            continue;
        }

        // If current head can reach p_idx, it must cover it.
        // It will cover p_idx and as many subsequent tracks as possible.
        // The head can cover tracks in range [h_idx_start, h_idx_end]
        // where h_idx_start is max(p[p_idx], head_reach_left[h_idx])
        // and h_idx_end is head_reach_right[h_idx]

        // The actual range covered by this head is [h[h_idx] - T, h[h_idx] + T].
        // We need to cover p[p_idx], p[p_idx+1], ...
        // The first track this head must cover is p[p_idx].
        // So, the head must be positioned such that p[p_idx] is in its range.
        // To cover p[p_idx] and subsequent tracks greedily,
        // the head should be positioned as far right as possible while still covering p[p_idx].
        // The rightmost point it can reach is h[h_idx] + T.
        // The leftmost point it can reach is h[h_idx] - T.

        // If p[p_idx] is to be covered by this head, the head must be able to reach it.
        // This means h[h_idx] - T <= p[p_idx] <= h[h_idx] + T.
        // We already checked p[p_idx] <= h[h_idx] + T.
        // If p[p_idx] < h[h_idx] - T, this head cannot cover p[p_idx] without moving left more than T.
        // But we can move the head to h[h_idx] - T.
        // The actual range covered by this head is [h[h_idx] - T, h[h_idx] + T].

        // The current head h_idx can cover tracks in the range [h[h_idx] - T, h[h_idx] + T].
        // We need to cover p[p_idx].
        // If p[p_idx] is outside this range to the right, this head cannot cover it.
        // If p[p_idx] is outside this range to the left, this head cannot cover it.
        // We already ensured p[p_idx] <= h[h_idx] + T.
        // So we only need to check if p[p_idx] >= h[h_idx] - T.

        if (p[p_idx] < head_reach_left[h_idx]) {
            // This head cannot reach p[p_idx] (it's too far left).
            // This head cannot be used for p[p_idx].
            // We must use a head to its left, or a previous head.
            // Since heads are sorted, and p are sorted, this head is too far right for p[p_idx].
            // This means this head cannot cover p[p_idx].
            // We must use a head to its left, or a previous head.
            // This logic is flawed. We need to find the first head that can cover p[p_idx].
            // The current head h_idx is the first head that *might* cover p[p_idx]
            // because p[p_idx] <= h[h_idx] + T.
            // If p[p_idx] < h[h_idx] - T, then this head cannot cover p[p_idx].
            // This means no head from h_idx onwards can cover p[p_idx] because they are even further right.
            // So, if p[p_idx] < head_reach_left[h_idx], it's impossible to cover p[p_idx] with this head or any subsequent head.
            // This implies that p[p_idx] must be covered by a previous head.
            // But we are iterating through heads to cover p_idx.
            // This means the current head h_idx is the *earliest* head that can cover p[p_idx] (or potentially later p_j's).
            // If p[p_idx] is too far left for h[h_idx], then h[h_idx] cannot cover p[p_idx].
            // And since h is sorted, h[h_idx+1], h[h_idx+2], ... are even further right, so they also cannot cover p[p_idx].
            // This means p[p_idx] cannot be covered by any head from h_idx onwards.
            // This implies that p[p_idx] must have been covered by a head before h_idx.
            // But we are processing p_idx sequentially.
            // So, if p[p_idx] < head_reach_left[h_idx], it means we failed to cover p[p_idx].
            return false;
        }

        // This head can cover p[p_idx].
        // It will cover all tracks from p[p_idx] up to head_reach_right[h_idx].
        long long current_head_coverage_end = head_reach_right[h_idx];
        while (p_idx < m && p[p_idx] <= current_head_coverage_end) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: 10^10 (max p_j) - 1 (min h_i) + 10^10 (max T)
                                    // A safe upper bound is max(p_j) - min(h_i) or max(h_i) - min(p_j)
                                    // Max p_j is 10^10, min h_i is 1. So 10^10 is a good upper bound.
                                    // If n=1, m=2, h={1}, p={1, 10^10}, T would be 10^10 - 1.
                                    // If h={10^10}, p={1, 10^10}, T would be 10^10 - 1.
                                    // So 10^10 is a reasonable upper bound. Let's use 2 * 10^10 for safety.

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

