    // Goodness = `(a[0].value + a[n-1].value + h) - (a[1].value + a[2].value)`
    // This is `goodness2`.

    // Let's consider the partition where `a[n-1]` is in group 1, and `a[0], ..., a[n-2]` are in group 2.
    // min_f: `a[0].value + a[1].value` (from group 2)
    // max_f: `a[n-2].value + a[n-1].value + h` (from group 1 and group 2)
    // Goodness = `(a[n-2].value + a[n-1].value + h) - (a[0].value + a[1].value)`
    // This is `goodness3`.

    // The problem is that `a[0].value + a[1].value` is always the absolute minimum possible sum.
    // If we put `a[0]` and `a[1]` in the same group, this minimum is achieved.
    // If we put `a[0]` and `a[1]` in different groups, then `a[0].value + a[1].value + h` is a possible value.
    // This would increase the minimum `f` value.

    // Let's consider the two main candidates for the optimal partition:
    // 1. All elements in one group (e.g., all 1s).
    //    min_f = a[0].value + a[1].value
    //    max_f = a[n-2].value + a[n-1].value
    //    Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    //    This is `goodness1`.

    // 2. Split the elements such that `a[0]` is in one group and `a[n-1]` is in another.
    //    This ensures that `a[0].value + a[n-1].value + h` is one of the `f` values.
    //    To minimize the goodness, we want to make the minimum `f` value as large as possible.
    //    The largest possible minimum `f` value is `a[0].value + a[1].value + h` (if `a[0]` and `a[1]` are split)
    //    or `a[1].value + a[2].value` (if `a[0]` is alone and `a[1], a[2]` are together).

    // Let's consider the partition where `a[0]` is in group 1, and `a[1], ..., a[n-1]` are in group 2.
    // Values from group 1: None (if n=1, but n>=2)
    // Values from group 2: `a[1].value + a[2].value` (min), `a[n-2].value + a[n-1].value` (max)
    // Values across groups: `a[0].value + a[i].value + h` for `i=1...n-1`.
    // The minimum of these is `a[0].value + a[1].value + h`.
    // The maximum of these is `a[0].value + a[n-1].value + h`.
    // So, for this partition:
    // min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    // This is the correct logic for this specific partition.

    // However, the problem is simpler. The minimum possible `f` value is always `a[0].value + a[1].value`.
    // The maximum possible `f` value is always `a[n-1].value + a[n-2].value + h`.
    // This is because we can always construct a partition that achieves these.
    // To achieve `a[0].value + a[1].value`: put `a[0]` and `a[1]` in the same group.
    // To achieve `a[n-1].value + a[n-2].value + h`: put `a[n-1]` and `a[n-2]` in different groups.
    // For example, put `a[n-1]` in group 1, and all other elements in group 2.
    // Then `a[0].value + a[1].value` is in group 2.
    // And `a[n-2].value + a[n-1].value + h` is across groups.
    // This partition gives goodness = `(a[n-2].value + a[n-1].value + h) - (a[0].value + a[1].value)`.
    // This is `goodness3`.

    // Let's compare `goodness1` and `goodness3`.
    // `goodness1 = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)`
    // `goodness3 = (a[n-2].value + a[n-1].value + h) - (a[0].value + a[1].value)`
    // Clearly, `goodness1 <= goodness3` because `h >= 0`.
    // So, if we can achieve `goodness1`, it's better than `goodness3`.
    // `goodness1` is achieved when all elements are in the same group.

    // What if `h` is very large?
    // Example: 5 10, 0 1 0 2 1 (sorted: 0 0 1 1 2)
    // a[0]=0, a[1]=0, a[2]=1, a[3]=1, a[4]=2
    // n=5, h=10
    // goodness1 = (a[3]+a[4]) - (a[0]+a[1]) = (1+2) - (0+0) = 3 - 0 = 3.
    // Partition: 1 1 1 1 1 (all in group 1).
    // Output: 3, 2 2 2 2 2 (all in group 2, same as all in group 1).

    // Let's consider the partition where `a[0]` is in group 1, and `a[1], ..., a[n-1]` are in group 2.
    // min_f = a[1].value + a[2].value (from group 2) = 0 + 1 = 1
    // max_f = a[0].value + a[n-1].value + h (from group 1 and group 2) = 0 + 2 + 10 = 12
    // Goodness = 12 - 1 = 11.
    // This is worse than 3.

    // The example output suggests that the optimal partition can be all elements in one group.
    // This happens when `h` is large enough that splitting elements always results in a larger goodness.

    // Let's re-examine the definition of min/max f values.
    // Let S1 and S2 be the two subsequences.
    // min_f = min( {a_i+a_j | a_i,a_j in S1, i!=j} U {a_i+a_j | a_i,a_j in S2, i!=j} U {a_i+a_j+h | a_i in S1, a_j in S2} )
    // max_f = max( {a_i+a_j | a_i,a_j in S1, i!=j} U {a_i+a_j | a_i,a_j in S2, i!=j} U {a_i+a_j+h | a_i in S1, a_j in S2} )

    // Consider the partition where all elements are in group 1.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    // This is `goodness_all_same_group`.

    // Consider the partition where `a[0]` is in group 1, and `a[1], ..., a[n-1]` are in group 2.
    // If n=2: a[0] in S1, a[1] in S2. Only one f value: a[0]+a[1]+h. Goodness = 0.
    // If n > 2:
    //   Pairs within S2: `a[1]+a[2]` (min), `a[n-2]+a[n-1]` (max)
    //   Pairs across S1 and S2: `a[0]+a[1]+h` (min), `a[0]+a[n-1]+h` (max)
    //   min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //   max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)
    //   Goodness = max_f - min_f
    // This is `goodness_split_a0`.

    // Let's compare `goodness_all_same_group` with `goodness_split_a0`.
    // `goodness_all_same_group = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)`

    // For `goodness_split_a0`:
    // `min_f_split_a0 = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h)`
    // `max_f_split_a0 = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)`
    // `goodness_split_a0 = max_f_split_a0 - min_f_split_a0`

    // The optimal solution must be one of these two.
    // Why?
    // The minimum possible value of `a_i + a_j` is `a[0].value + a[1].value`.
    // The maximum possible value of `a_i + a_j` is `a[n-2].value + a[n-1].value`.
    // The minimum possible value of `a_i + a_j + h` is `a[0].value + a[1].value + h`.
    // The maximum possible value of `a_i + a_j + h` is `a[n-2].value + a[n-1].value + h`.

    // Let `min_sum = a[0].value + a[1].value`.
    // Let `max_sum = a[n-2].value + a[n-1].value`.

    // If all elements are in the same group:
    // `min_f = min_sum`
    // `max_f = max_sum`
    // `Goodness = max_sum - min_sum`

    // If elements are split into two groups:
    // There must be at least one pair `(a_i, a_j)` in different groups, so `a_i + a_j + h` values exist.
    // The overall `min_f` will be `min(min_sum_in_group, min_sum_across_groups + h)`.
    // The overall `max_f` will be `max(max_sum_in_group, max_sum_across_groups + h)`.

    // Consider the partition where `a[0]` is in group 1, and all other `n-1` elements are in group 2.
    // If `n=2`: `a[0]` in S1, `a[1]` in S2. Only `f(a[0], a[1]) = a[0]+a[1]+h`. `min_f = max_f = a[0]+a[1]+h`. Goodness = 0.
    // If `n > 2`:
    //   Pairs within S2: `a[1]+a[2]` (min), `a[n-2]+a[n-1]` (max)
    //   Pairs across S1 and S2: `a[0]+a[1]+h` (min), `a[0]+a[n-1]+h` (max)
    //   `min_f = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h)`
    //   `max_f = std::max(a[n-2].value + a[n-1].value, a[0].value + a[n-1].value + h)`
    //   `Goodness = max_f - min_f`

    // Let's test the example 1: 3 2, 1 2 3
    // Sorted: a[0]=1, a[1]=2, a[2]=3
    // n=3, h=2

    // Case 1: All in one group (e.g., all 1s)
    // min_f = a[0]+a[1] = 1+2 = 3
    // max_f = a[1]+a[2] = 2+3 = 5
    // Goodness = 5 - 3 = 2
    // Partition: 1 1 1

    // Case 2: a[0] in group 1, a[1], a[2] in group 2.
    // S1 = {1}, S2 = {2, 3}
    // Pairs within S2: (2,3) -> 2+3 = 5
    // Pairs across S1, S2: (1,2) -> 1+2+h = 1+2+2 = 5; (1,3) -> 1+3+h = 1+3+2 = 6
    // min_f = std::min(5, 5, 6) = 5
    // max_f = std::max(5, 5, 6) = 6
    // Goodness = 6 - 5 = 1
    // Partition: 1 2 2 (original indices: a[0] is 1, a[1] is 2, a[2] is 2)
    // This matches the example output!

    // So the two candidates are:
    // 1. All elements in one group.
    // 2. `a[0]` in group 1, `a[1]...a[n-1]` in group 2.

    // Let's implement this.

    long long min_goodness = -1;
    std::vector<int> result_partition(n);

    // Candidate 1: All elements in one group
    long long current_min_f1 = a[0].value + a[1].value;
    long long current_max_f1 = a[n - 2].value + a[n - 1].value;
    long long current_goodness1 = current_max_f1 - current_min_f1;

    min_goodness = current_goodness1;
    for (int i = 0; i < n; ++i) {
        result_partition[a[i].original_index] = 1;
    }

    // Candidate 2: a[0] in group 1, a[1]...a[n-1] in group 2
    // This only makes sense if n >= 2.
    // If n=2, S1={a[0]}, S2={a[1]}. Only f(a[0],a[1]) = a[0]+a[1]+h. min_f=max_f, goodness=0.
    // For n=2, current_goodness1 = (a[0]+a[1]) - (a[0]+a[1]) = 0. So both give 0.
    // The logic below for n>2 will work for n=2 too if we handle indices carefully.
    // For n=2, a[1].value + a[2].value would be out of bounds.
    // So special case n=2.
    if (n == 2) {
        // Both partitions give goodness 0.
        // All in one group: f(a[0],a[1]) = a[0]+a[1]. min_f=max_f=a[0]+a[1]. Goodness=0.
        // a[0] in S1, a[1] in S2: f(a[0],a[1]) = a[0]+a[1]+h. min_f=max_f=a[0]+a[1]+h. Goodness=0.
        // So min_goodness is 0. The partition can be all 1s.
        min_goodness = 0;
        for (int i = 0; i < n; ++i) {
            result_partition[a[i].original_index] = 1;
        }
    } else { // n > 2
        long long current_min_f2;
        long long current_max_f2;

        // min_f for this partition:
        // It's the minimum of:
        // 1. a[1].value + a[2].value (from S2)
        // 2. a[0].value + a[1].value + h (from S1 and S2)
        current_min_f2 = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);

        // max_f for this partition:
        // It's the maximum of:
        // 1. a[n-2].value + a[n-1].value (from S2)
        // 2. a[0].value + a[n-1].value + h (from S1 and S2)
        current_max_f2 = std::max(a[n - 2].value + a[n - 1].value, a[0].value + a[n - 1].value + h);

        long long current_goodness2 = current_max_f2 - current_min_f2;

        if (current_goodness2 < min_goodness) {
            min_goodness = current_goodness2;
            result_partition[a[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                result_partition[a[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    int consecutive_sequences_starting_with_one = 0;
    int total_elements_in_consecutive_sequences = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        if (m == 0) continue; // Should not happen based on constraints (1 <= m_i)

        int first_doll;
        std::cin >> first_doll;

        if (first_doll == 1) {
            consecutive_sequences_starting_with_one++;
            total_elements_in_consecutive_sequences++;
            int prev_doll = first_doll;
            for (int j = 1; j < m; ++j) {
                int current_doll;
                std::cin >> current_doll;
                if (current_doll == prev_doll + 1) {
                    total_elements_in_consecutive_sequences++;
                    prev_doll = current_doll;
                } else {
                    // The sequence of consecutive numbers is broken
                    // We still need to read the rest of the chain elements
                    for (int l = j + 1; l < m; ++l) {
                        std::cin >> current_doll;
                    }
                    break; // Exit inner loop, this chain's contribution to consecutive sequence is done
                }
            }
        } else {
            // Read the rest of the chain elements if the first doll is not 1
            for (int j = 1; j < m; ++j) {
                int dummy;
                std::cin >> dummy;
            }
        }
    }

    // Operations to disassemble:
    // Each chain needs to be disassembled.
    // If a chain has m elements, it has m-1 nestings.
    // To get all elements out, we need m-1 operations.
    // Total initial nestings = n - k (since sum of m_i = n, and each chain has m_i-1 nestings)
    // So, total disassemble operations = (n - k)

    // Operations to assemble:
    // We need to form n-1 nestings in total (1->2, 2->3, ..., n-1->n).
    // We already have `total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one`
    // of these nestings formed within the initial chain starting with 1.
    // For example, if we have 1->2->3, this means 2 nestings (1,2) and (2,3).
    // `total_elements_in_consecutive_sequences` is 3. `consecutive_sequences_starting_with_one` is 1.
    // So, 3 - 1 = 2 nestings are already formed.
    // The number of new nestings we need to create is (n - 1) - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one).
    // Each new nesting costs 1 operation.

    // Total operations = (disassemble operations) + (assemble operations)
    // Disassemble operations: (n - k)
    // Assemble operations: (n - 1) - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)

    // Let's simplify.
    // The number of elements that are *not* part of the desired 1->2->...->N sequence
    // and are not 1 itself, need to be taken out.
    // The number of elements that are part of the desired 1->2->...->N sequence
    // and are not 1 itself, but are not correctly nested, need to be taken out.
    // This is equivalent to saying:
    // We have `n` dolls. We want `n-1` specific connections.
    // We have `k` chains.
    // The number of existing connections is `n-k`.
    // The number of *correct* existing connections is `total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one`.
    // The number of *incorrect* existing connections is `(n-k) - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)`.
    // Each incorrect connection must be broken: `(n-k) - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)` operations.
    // Each missing correct connection must be made: `(n-1) - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)` operations.

    // Total operations = (incorrect connections to break) + (correct connections to make)
    // Total operations = (n - k - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one))
    //                  + (n - 1 - (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one))

    // This simplifies to:
    // (n - k) + (n - 1) - 2 * (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)

    // Let's re-evaluate the logic based on the example.
    // Example 1: n=3, k=2. Chains: 2 1 2; 1 3.
    // Chain 1: 1->2. first_doll=1. total_elements_in_consecutive_sequences=2. consecutive_sequences_starting_with_one=1.
    // Chain 2: 3. first_doll=3.
    // Result: total_elements_in_consecutive_sequences = 2. consecutive_sequences_starting_with_one = 1.
    // Formula: (3 - 2) + (3 - 1) - 2 * (2 - 1)
    //        = 1 + 2 - 2 * 1
    //        = 3 - 2 = 1. Correct.

    // Example 2: n=7, k=3. Chains: 3 1 3 7; 2 2 5; 2 4 6.
    // Chain 1: 1->3->7. first_doll=1.
    //   1 is read. total_elements_in_consecutive_sequences=1. consecutive_sequences_starting_with_one=1.
    //   3 is read. Not 1+1. Loop breaks.
    // Chain 2: 2->5. first_doll=2.
    // Chain 3: 4->6. first_doll=4.
    // Result: total_elements_in_consecutive_sequences = 1. consecutive_sequences_starting_with_one = 1.
    // Formula: (7 - 3) + (7 - 1) - 2 * (1 - 1)
    //        = 4 + 6 - 2 * 0
    //        = 10. Correct.

    // The formula seems correct.
    // (n - k) is the number of "take out" operations needed to break all existing chains into individual dolls.
    // (n - 1) is the number of "put in" operations needed to form the final 1->2->...->n chain from individual dolls.
    // However, some dolls are already correctly nested.
    // The number of correctly nested pairs is `total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one`.
    // Each such pair (i, i+1) means:
    // 1. We don't need to "take out" doll `i` from `i+1`. (Saves 1 operation from `n-k`)
    // 2. We don't need to "put in" doll `i` into `i+1`. (Saves 1 operation from `n-1`)
    // So, for each correctly nested pair, we save 2 operations.

    // Total operations = (n - k) + (n - 1) - 2 * (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one)

    long long result = (long long)(n - k) + (long long)(n - 1) - 2LL * (total_elements_in_consecutive_sequences - consecutive_sequences_starting_with_one);
    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Operation 1: Make all elements except the last one multiples of n.
    // Select segment [1, n-1] (0-indexed: [0, n-2])
    // Length is n-1.
    // For each a[i] in this segment, we want to add a multiple of (n-1) such that a[i] becomes a multiple of n.
    // If n = 1, this segment is empty.
    if (n > 1) {
        std::cout << 1 << " " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = a[i] % n;
            long long add_val = (n - remainder) % n; // This is the value needed to make a[i] a multiple of n
            // We need to add a multiple of (n-1) that equals add_val (mod n)
            // (n-1) * k = add_val (mod n)
            // -1 * k = add_val (mod n)
            // k = -add_val (mod n)
            // k = (n - add_val % n) % n
            long long k = (n - add_val % n) % n;
            long long b_i = k * (n - 1);
            a[i] += b_i;
            std::cout << b_i << (i == n - 2 ? "" : " ");
        }
        std::cout << "\n";
    } else { // n = 1 case
        // For n=1, the first two operations are trivial or empty.
        // Operation 1: segment [1, 1], length 1. Add -a[0].
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        a[0] = 0; // a[0] is now 0
        // Operation 2: segment [1, 1], length 1. Add 0.
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
        // Operation 3: segment [1, 1], length 1. Add 0.
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
        return 0;
    }

    // Operation 2: Make the last element a multiple of n.
    // Select segment [n, n] (0-indexed: [n-1, n-1])
    // Length is 1.
    // For a[n-1], we want to add a multiple of 1 such that a[n-1] becomes a multiple of n.
    // This is always possible by adding (n - a[n-1]%n)%n.
    std::cout << n << " " << n << "\n";
    long long remainder_last = a[n - 1] % n;
    long long add_val_last = (n - remainder_last) % n;
    a[n - 1] += add_val_last;
    std::cout << add_val_last << "\n";

    // Operation 3: Make all elements zero.
    // At this point, all a[i] are multiples of n.
    // Select segment [1, n] (0-indexed: [0, n-1])
    // Length is n.
    // For each a[i], we want to add a multiple of n such that a[i] becomes 0.
    // This is simply adding -a[i]. Since a[i] is a multiple of n, -a[i] is also a multiple of n.
    std::cout << 1 << " " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

