int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To form 'one': needs 'o', 'n', 'e'
    // To form 'zero': needs 'z', 'e', 'r', 'o'

    // Prioritize '1's to make the number as large as possible
    int num_ones = 0;
    // 'n' is unique to 'one' (among 'n', 'z', 'r')
    // 'o' and 'e' are shared.
    // The number of '1's is limited by 'n'.
    // Each 'one' uses one 'o', one 'n', one 'e'.
    // So, num_ones = count_n.
    // This is because 'n' only appears in 'one'.
    // If we have 'n' 'n's, we can make 'n' 'one's, provided we have enough 'o's and 'e's.
    // The problem guarantees that it's possible to form a sequence of "zero" and "one".
    // This implies that the counts of 'o' and 'e' will be sufficient for the 'n's and 'z's.
    // So, the number of '1's is simply the count of 'n's.
    num_ones = count_n;

    // The number of '0's is simply the count of 'z's.
    // This is because 'z' only appears in 'zero'.
    int num_zeros = count_z;

    std::vector<int> result;
    for (int i = 0; i < num_ones; ++i) {
        result.push_back(1);
    }
    for (int i = 0; i < num_zeros; ++i) {
        result.push_back(0);
    }

    for (size_t i = 0; i < result.size(); ++i) {
        std::cout << result[i] << (i == result.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

