            total_sent_a += 10; // Each ping sends 10 packets.
            total_successful_a += x; // Add successful packets to server 'a's total.
        } else { // If the command is for server 'b' (type == 2).
            total_sent_b += 10; // Each ping sends 10 packets.
            total_successful_b += x; // Add successful packets to server 'b's total.
        }
    }

    // Determine if server 'a' is "alive".
    // A server is "alive" if at least half of the packets sent to it were successful.
