    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k sticks and k coal.
        // We start with 1 stick.
        // We need k coal. Each coal costs y sticks. So, k coal costs k * y sticks.
        // Total sticks required for coal: k * y
        // Total sticks required for torches (excluding the initial one): k - 1
        // Total sticks we need to acquire through trades: (k * y) + (k - 1)
        long long sticks_to_acquire = k * y + k - 1;

        // Each trade of type 1 (1 stick for x sticks) effectively gives us x - 1 sticks.
        // Number of stick trades needed: ceil(sticks_to_acquire / (x - 1))
        // Using integer division: (sticks_to_acquire + (x - 1) - 1) / (x - 1)
        long long num_stick_trades = (sticks_to_acquire + (x - 1) - 1) / (x - 1);

        // Total trades = number of stick trades + number of coal trades
        // Number of coal trades is k (since we need k coal, and each coal is 1 trade)
        long long total_trades = num_stick_trades + k;

        std::cout << total_trades << std::endl;
    }
