#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this specific element.
        // The presence of 1 or -1 before index i is still relevant for subsequent elements.

        // Update has_one and has_minus_one for elements up to current index i
        // This is crucial because operations can only use a[k] where k < j.
        // So, for a[i], we can only use a[0]...a[i-1].
        // The initial scan for has_one/has_minus_one is for the *entire* array a,
        // but for a[i], we only care about elements a[0]...a[i-1].
        // However, the problem states "Choose any pair of indexes (i, j) such that 1 <= i < j <= n".
        // This means the *original* values of a[k] (k < j) are used.
        // The values of a[k] themselves don't change unless k is the 'j' in an operation.
        // So, the presence of 1 or -1 *anywhere* before the current index `i` is what matters.
        // The `has_one` and `has_minus_one` flags should track if a 1 or -1 has appeared
        // in `a[0]...a[i-1]`.
        // The current logic of updating `has_one` and `has_minus_one` *after* checking `a[i]` vs `b[i]`
        // means that for `a[i]`, we are considering `a[0]...a[i-1]`.
        // This is correct.
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }

    std::cout << "YES\n";
}

