#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and all other elements are less than n-1.
    // If so, it means the actual value for that p[i] should be n.
    // This happens if the original p[i] was n, and all other p[j] were < n.
    // In that case, max_val_in_row would be max(p[j] for j!=i) which is n-1.
    // If there are multiple such elements, it means the permutation was not unique
    // in its maximum value, which contradicts the problem statement (permutation of 1 to n).
    // However, the problem guarantees a solution exists.
    // So, if all p[i] are less than n, it means one of them should be n.
    // The one that is currently n-1 (and all others are smaller) should be n.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // This means the maximum value found in any row was n-1.
        // This implies that the actual maximum element 'n' was present in the permutation,
        // and for the row corresponding to 'n', the max of min(n, p_j) would be n-1.
        // So, we need to find one element that is currently n-1 and change it to n.
        // Since it's a permutation of 1 to n, there must be exactly one element that should be n.
        // If all p[i] are < n, then the one that is currently n-1 must be the one that should be n.
        // If there are multiple n-1s, it means the input was inconsistent, but the problem guarantees consistency.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin/cout from stdio and prevents flushing cout before cin.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) { // Loop through each test case
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // For N up to 150,000, a vector is efficient.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n == 0) { // Handle edge case where n is 0 (though constraints say n >= 1)
            std::cout << 0 << "\n";
            continue;
        }
        if (n == 1) { // A single day's price can never be bad
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last price.
        // The last price a[n-1] is never bad, as there are no prices after it.
        int min_suffix = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // For each day i, we compare its price a[i] with the minimum price
        // found so far in the suffix a[i+1...n-1].
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix) {
                // If the current price is greater than the minimum price
                // found in any subsequent day, it's a bad price.
                bad_prices_count++;
            } else {
                // If the current price is not greater than min_suffix,
                // it means a[i] <= min_suffix.
                // This price a[i] now becomes a new candidate for the minimum
                // in the suffix for days before i.
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0; // Indicate successful execution
