int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos is -1, it means the frog is at cell 0.
                             // If last_r_pos is i, it means the frog is at cell i.

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_r_pos.
                // The gap is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // Or, more simply, the distance from last_r_pos to current cell (i+1) is (i+1) - last_r_pos.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1) + 1); // Distance from last_r_pos+1 to i+1
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1.
        // If there were no 'R's, last_r_pos is -1. The jump is from 0 to n+1.
        // If last_r_pos is i, the jump is from cell i+1 to n+1.
        // The distance is (n+1) - (last_r_pos + 1) + 1.
        max_gap = std::max(max_gap, (static_cast<int>(s.length()) + 1) - (last_r_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

