#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> available_numbers;
    for (int i = 1; i <= n; ++i) {
        available_numbers.insert(i);
    }

    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    if (available_numbers.count(p[0])) {
        available_numbers.erase(p[0]);
    } else {
        // This case should ideally not happen if q_1 is valid (1 <= q_1 <= n)
        // but good to check for robustness.
        possible = false;
    }

    for (int i = 1; i < n; ++i) {
        if (!possible) break;

        if (q[i] > q[i-1]) {
            // If q[i] is a new maximum, then p[i] must be q[i].
            p[i] = q[i];
            if (available_numbers.count(p[i])) {
                available_numbers.erase(p[i]);
            } else {
                // q[i] was already used or is out of range [1, n].
                // Since q_i is guaranteed to be <= n, it must be already used.
                possible = false;
            }
        } else { // q[i] == q[i-1]
            // p[i] must be some number less than or equal to q[i-1] (which is q[i]).
            // To ensure we can form a permutation, we should pick the smallest available number
            // that is not greater than q[i].
            // The smallest available number is *available_numbers.begin().
            // If *available_numbers.begin() > q[i], then no valid p[i] can be chosen.
            // Otherwise, we pick *available_numbers.begin().
            if (available_numbers.empty() || *available_numbers.begin() > q[i]) {
                possible = false;
            } else {
                p[i] = *available_numbers.begin();
                available_numbers.erase(available_numbers.begin());
            }
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

