    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;
    int count_01 = 0; // Number of positions where a[i] = '0' and b[i] = '1'
    int count_10 = 0; // Number of positions where a[i] = '1' and b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            // This position needs to be fixed.
            // We have two options: flip it, or swap it with another differing bit.
            // The key insight is that a swap operation (cost |i-j|) can fix two differing bits
            // if one is '0'->'1' and the other is '1'->'0'.
            // For example, if a[i]='0', b[i]='1' and a[j]='1', b[j]='0'.
            // Swapping a[i] and a[j] makes a[i]='1' and a[j]='0'.
            // Both positions are now correct. The cost is |i-j|.
            // This is equivalent to flipping a[i] (cost 1) and flipping a[j] (cost 1)
            // if |i-j| <= 2.
            // If |i-j| = 1, swap cost is 1. Two flips cost 2. Swap is better.
            // If |i-j| = 2, swap cost is 2. Two flips cost 2. Both are equal.
            // If |i-j| > 2, swap cost is > 2. Two flips cost 2. Flips are better.

            // We can greedily pair up adjacent differing bits that can be fixed by a swap.
            // If a[i] = '0' and b[i] = '1', and a[i+1] = '1' and b[i+1] = '0',
            // we can swap a[i] and a[i+1] for cost 1. This fixes both.
            // This is better than two flips (cost 2).
            // So, we check if the current position `i` and the next position `i+1`
            // form such a pair.

            if (i + 1 < n && a[i] != a[i+1] && a[i+1] != b[i+1] && a[i] == b[i+1] && a[i+1] == b[i]) {
                // This condition means:
                // a[i] != b[i] (current position needs fixing)
                // a[i+1] != b[i+1] (next position needs fixing)
                // a[i] and a[i+1] are different (e.g., '0' and '1')
                // a[i] is the target for b[i+1] (e.g., if a[i]='0', then b[i+1] must be '0')
                // a[i+1] is the target for b[i] (e.g., if a[i+1]='1', then b[i] must be '1')
                // This simplifies to: a[i] != b[i] AND a[i+1] != b[i+1] AND a[i] == b[i+1] AND a[i+1] == b[i]
                // Example: a="01", b="10". Here a[0]='0', b[0]='1' and a[1]='1', b[1]='0'.
                // a[0] != a[1] ('0' != '1')
                // a[0] == b[1] ('0' == '0')
                // a[1] == b[0] ('1' == '1')
                // This is exactly the case where swapping a[i] and a[i+1] fixes both.
                total_cost += 1; // Cost of swap is |i - (i+1)| = 1
                i++; // Skip next position as it's now fixed
            } else {
                // If we can't find an adjacent swap that fixes two positions for cost 1,
                // then the best we can do for this single differing position is to flip it.
                total_cost += 1; // Cost of flip is 1
            }
        }
    }

    std::cout << total_cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::upper_bound

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;

    // Iterate through each point as the first point of a potential triplet (x_i)
    for (int i = 0; i < n; ++i) {
        // For a fixed x[i], we need to find points x[j] and x[k] such that i < j < k
        // and x[k] - x[i] <= d.
        // This means x[k] <= x[i] + d.

        // Find the rightmost index 'k_max_idx' such that x[k_max_idx] <= x[i] + d.
        // std::upper_bound returns an iterator to the first element greater than (x[i] + d).
        // So, we need to decrement the iterator to get the last element less than or equal to (x[i] + d).
        // The search range for k is from i+1 to n-1.
        auto it = std::upper_bound(x.begin() + i + 1, x.end(), x[i] + d);

        // The elements from x[i+1] up to *(it-1) are potential candidates for x[j] or x[k].
        // The number of such candidates is (it - x.begin()) - (i + 1).
        // Let this count be 'num_candidates'.
        // These candidates are at indices from (i+1) to (it - x.begin() - 1).

        // If it points to x.begin() + i + 1, it means no element in the range is <= x[i] + d.
        // In this case, num_candidates would be 0 or negative, which is handled correctly.

        // The index of the last valid point for k is (it - x.begin() - 1).
        // Let's call this index 'k_upper_bound_idx'.
        // All points x[j] and x[k] must be chosen from the range [x[i+1], ..., x[k_upper_bound_idx]].
        // The number of points in this range is (k_upper_bound_idx - (i+1) + 1).
        // Let m be the number of points available after x[i] that satisfy the distance condition.
        // m = (it - x.begin()) - (i + 1);
        // These 'm' points are x[i+1], x[i+2], ..., x[i+m].
        // We need to choose 2 points from these 'm' points to form x[j] and x[k].
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = (it - x.begin()) - (i + 1);

        if (m >= 2) { // We need at least 2 points (for x_j and x_k)
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // 2. Ensure elements to the left of median_idx are <= s
    // These elements are already sorted, so we only need to check those that are > s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median_idx are >= s
    // These elements are already sorted, so we only need to check those that are < s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i; // Not strictly needed for A, but good practice
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means if A is sorted ascending and B is sorted ascending,
    // A'[b_elements[i].original_index] = a_elements[i].value
    // This effectively pairs a_elements[0] with b_elements[0], a_elements[1] with b_elements[1], etc.
    // Since F(n, k) = k / (n + 1), we want to maximize sum(k_i / (n_i + 1)).
    // To maximize sum(k_i / (n_i + 1)), we should pair larger k_i with smaller (n_i + 1)
    // and smaller k_i with larger (n_i + 1).
    // This means pairing larger B_i with smaller A_i, and smaller B_i with larger A_i.
    //
    // Let's re-evaluate the pairing.
    // We have sorted A: a_0 <= a_1 <= ... <= a_{m-1}
    // We have sorted B: b_0 <= b_1 <= ... <= b_{m-1}
    //
    // The sum is sum(b_i / (a'_i + 1)).
    // To maximize this sum, we want to pair the largest b_i with the smallest (a'_i + 1),
    // and the smallest b_i with the largest (a'_i + 1).
    // This means pairing b_elements[m-1] with a_elements[0],
    // b_elements[m-2] with a_elements[1], and so on.
    // In general, b_elements[m-1-i] should be paired with a_elements[i].
    //
    // The output array `result_a_prime` needs to be constructed such that
    // `result_a_prime[original_index_of_b_elements[m-1-i]] = a_elements[i].value`.

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // b_elements[m-1-i] is the (i+1)-th largest B value.
        // a_elements[i] is the (i+1)-th smallest A value.
        // We pair the (i+1)-th largest B value with the (i+1)-th smallest A value.
        // The original index of this B value is b_elements[m-1-i].original_index.
        // This is where the A value a_elements[i].value should go.
        result_a_prime[b_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a subarray is a permutation
bool is_permutation(const std::vector<int>& arr, int start_idx, int end_idx, int length) {
    if (length == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
                     // This case should not be hit for p1 or p2 due to l1, l2 >= 1.
    }
    if (length > arr.size()) { // Should not happen if start_idx, end_idx are valid
        return false;
    }

    std::vector<bool> seen(length + 1, false); // Use 1-based indexing for values
    int max_val = 0;

    for (int i = start_idx; i < end_idx; ++i) {
        int val = arr[i];
        if (val < 1 || val > length || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // Check if all numbers from 1 to length are present
    // This is implicitly checked by `seen[val]` and `val > length` conditions
    // combined with `max_val == length`.
    // If all numbers from 1 to length are present, then max_val must be length.
    // And if max_val is length, and all numbers are distinct and within [1, length],
    // then all numbers from 1 to length must be present.
    return max_val == length;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> max_prefix(n + 1, 0); // max_prefix[k] stores max value in a[0...k-1]
    std::vector<bool> seen_prefix(n + 1, false); // seen_prefix[val] is true if val is in a[0...k-1]
    bool is_prefix_perm[n + 1]; // is_prefix_perm[k] is true if a[0...k-1] is a permutation of length k
    std::fill(is_prefix_perm, is_prefix_perm + n + 1, false);
    is_prefix_perm[0] = true; // Empty prefix is a permutation of length 0

    int current_max_prefix = 0;
    bool current_prefix_valid = true;
    for (int k = 1; k <= n; ++k) {
        int val = a[k - 1];
        if (val < 1 || val > k || seen_prefix[val]) {
            current_prefix_valid = false;
        }
        if (current_prefix_valid) {
            seen_prefix[val] = true;
            if (val > current_max_prefix) {
                current_max_prefix = val;
            }
            if (current_max_prefix == k) {
                is_prefix_perm[k] = true;
            }
        }
    }

    std::vector<int> max_suffix(n + 2, 0); // max_suffix[k] stores max value in a[k-1...n-1]
    std::vector<bool> seen_suffix(n + 1, false); // seen_suffix[val] is true if val is in a[k-1...n-1]
    bool is_suffix_perm[n + 2]; // is_suffix_perm[k] is true if a[k-1...n-1] is a permutation of length n-k+1
    std::fill(is_suffix_perm, is_suffix_perm + n + 2, false);
    is_suffix_perm[n + 1] = true; // Empty suffix is a permutation of length 0

    int current_max_suffix = 0;
    bool current_suffix_valid = true;
    std::fill(seen_suffix.begin(), seen_suffix.end(), false); // Reset for suffix check
    for (int k = n; k >= 1; --k) {
        int val = a[k - 1];
        int len = n - k + 1; // Length of suffix a[k-1...n-1]
        if (val < 1 || val > len || seen_suffix[val]) {
            current_suffix_valid = false;
        }
        if (current_suffix_valid) {
            seen_suffix[val] = true;
            if (val > current_max_suffix) {
                current_max_suffix = val;
            }
            if (current_max_suffix == len) {
                is_suffix_perm[k] = true;
            }
        }
    }

    std::vector<std::pair<int, int>> solutions;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be >= 1 and l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l1 + 1]) {
            solutions.push_back({l1, l2});
        }
    }

    std::cout << solutions.size() << "\n";
    for (const auto& p : solutions) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

