    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case: if N=2, taking 1 is optimal for Chanek
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0) { // N/2 is odd
                    // If Chanek takes N/2, opponent faces odd N/2. Opponent takes 1.
                    // If Chanek takes 1, opponent faces N-1 (odd). Opponent takes 1.
                    // In this specific scenario, taking N/2 is better for Chanek.
                    // Example: N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                    // Chanek: 3+1=4. Opponent: 1+1=2.
                    // If Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                    // Chanek: 1+2+1=4. Opponent: 1+1=2.
                    // It seems taking N/2 is generally better if N/2 is odd.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    // If Chanek takes N/2, opponent faces even N/2. Opponent can take (N/2)/2 = N/4.
                    // If Chanek takes 1, opponent faces N-1 (odd). Opponent takes 1.
                    // Taking 1 coin is better here to force opponent into an odd state.
