#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char move : s) {
            counts[move]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking if needed,
        // though any tie-breaking is fine as per problem statement.
        // R, P, S order is arbitrary but consistent.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // If all counts are 0 (empty string, not possible by constraints),
        // or if there's a tie, the first one encountered in the above order wins.
        // For example, if R=2, P=2, S=1, then P would be chosen.
        // If R=2, P=1, S=2, then R would be chosen.
        // This is fine as any optimal answer is accepted.

        char our_winning_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w to handle w_i=1 first, then w_i>1

    long long total_happiness = 0;

    // First, handle friends who get w_i = 1 integer.
    // They should get the largest available integers, as their happiness is 2 * integer.
    // These are the k largest integers from 'a'.
    int a_ptr_large = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_large];
            a_ptr_large--;
        } else {
            // Since w is sorted, all remaining w[i] will be > 1.
            // We can break here and handle them in the next loop.
            break;
        }
    }

    // Now, handle friends who get w_i > 1 integers.
    // For these friends, happiness is max_val + min_val.
    // To maximize this, they should get the largest remaining available integers as their max_val.
    // The smallest available integers should be used as their min_val.
    // The w_i values are sorted, so w[0] is the smallest w_i > 1.
    // We iterate through w from smallest w_i to largest w_i (excluding w_i=1 already handled).

    int a_ptr_small = 0; // Pointer for the smallest available integers
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            // The largest remaining integer for this friend's max_val
            total_happiness += a[a_ptr_large];
            a_ptr_large--;

            // The smallest available integer for this friend's min_val
            // This friend needs w[i] integers. One is the max_val (a[a_ptr_large+1]),
            // one is the min_val (a[a_ptr_small]), and w[i]-2 integers in between.
            // We use the smallest available a[a_ptr_small] for min_val.
            // Then we skip w[i]-2 integers from the small end.
            total_happiness += a[a_ptr_small];
            a_ptr_small += (w[i] - 1); // Move pointer past the w[i]-1 smallest integers used
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

