int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we'll use in the zigzag part to generate k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers.
    // The sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // Differences: (k+1)-1 = k, (k+1)-2 = k-1, (k)-2 = k-2, (k)-3 = k-3, ...
    // Or more precisely:
    // p_1 = 1
    // p_2 = k+1. Diff = k+1-1 = k
    // p_3 = 2. Diff = (k+1)-2 = k-1
    // p_4 = k. Diff = k-2
    // p_5 = 3. Diff = k-3
    // ...
    // This generates differences k, k-1, k-2, ..., 1.
    // It uses numbers from 1 to k+1.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index (0-based) means we take from left
            std::cout << left << " ";
            left++;
        } else { // Odd index means we take from right
            std::cout << right << " ";
            right--;
        }
    }

    // After generating k distinct differences using numbers from 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these in increasing order to ensure no new distinct differences are introduced.
    // The last number printed was either `left-1` or `right+1`.
    // If `k+1` is odd, the last number printed was `(k+1)/2 + 1` (from `left`).
    // If `k+1` is even, the last number printed was `k+1 - (k+1)/2 + 1` (from `right`).
    // In both cases, the numbers used are `1, ..., (k+1)/2` and `(k+1)/2 + 1, ..., k+1`.
    // The next available number is `k+2`.
    // Appending `k+2, k+3, ..., n` will result in differences of 1.
    // Since 1 is already among the k distinct differences generated (e.g., if k=1, 1 2 3... diff is 1),
    // this won't add new distinct differences.

    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

