    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    // This ensures that when an 'a' is processed,
    // all 'b's to its right have already been accounted for.
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means this 'b' is to the right
            // of any 'a's we've counted so far.
            // Each such 'a' will eventually need to "jump over" this 'b'.
            // When an 'a' jumps over a 'b' ("ab" -> "bba"), it costs 1 step
            // and effectively doubles the number of 'a's that still need
            // to jump over subsequent 'b's (because the 'a' remains,
            // and a new 'b' is inserted, but the logic here is about
            // how many 'a's are *currently* to the left of this 'b').
            // The 'count_a' represents the number of 'a's that are to the
            // left of the current 'b' and have not yet been "processed"
            // (i.e., they haven't formed an "ab" pair with a 'b' to their right
            // that has already been processed).
            // Each of these 'count_a' 'a's will interact with this 'b'.
            // The total steps increase by 'count_a'.
            // After this 'b' is processed, it effectively "doubles" the
            // potential for future 'a's to interact with 'b's further left.
            // This is because the 'b' itself remains, and the 'a' moves past it.
            // The key insight is that when 'ab' -> 'bba', the 'a' effectively
            // moves past the 'b', and the 'b' remains.
            // The 'count_a' represents the number of 'a's that are currently
            // "active" and need to move past 'b's.
            // When an 'a' moves past a 'b', it costs 1 step.
            // The 'a' then becomes available to move past the next 'b'.
            // The 'b' that was just moved past effectively creates a new 'b'
            // for 'a's further to the left to interact with.
            // So, the number of 'a's that need to move past 'b's effectively doubles.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is to the left
            // of all 'b's we've processed so far.
            // This 'a' is now an "active" 'a' that needs to move past
            // any 'b's to its right.
            // So, we increment the count of active 'a's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long operations = 0;
    int consecutive_sequence_length = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;

        if (m == 0) { // Should not happen based on constraints (m_i >= 1) but good for robustness
            continue;
        }

        int first_doll;
        std::cin >> first_doll;

        if (first_doll == 1) {
            consecutive_sequence_length = 1;
            for (int j = 1; j < m; ++j) {
                int current_doll;
                std::cin >> current_doll;
                if (current_doll == consecutive_sequence_length + 1) {
                    consecutive_sequence_length++;
                } else {
                    // Sequence 1 -> 2 -> ... -> consecutive_sequence_length is broken
                    // All remaining dolls in this chain need to be disassembled and reassembled.
                    // The current doll and all subsequent dolls in this chain are "misplaced".
                    // Each of these (m - 1 - j + 1) dolls needs 1 disassembly and 1 reassembly.
                    // The current doll (current_doll) is not part of the target sequence 1..N
                    // at its current position.
                    operations += (m - j) * 2; // (m - j) dolls need to be taken out and put back in
                    for (int l = j + 1; l < m; ++l) {
                        std::cin >> current_doll; // Consume remaining input for this chain
                    }
                    consecutive_sequence_length = 0; // Reset as the sequence is broken
                    break; // Move to the next chain
                }
            }
        } else {
            // This chain does not start with 1.
            // All dolls in this chain need to be disassembled and reassembled.
            operations += (long long)m * 2; // m dolls need 1 disassembly and 1 reassembly
            for (int j = 1; j < m; ++j) {
                int current_doll;
                std::cin >> current_doll; // Consume remaining input for this chain
            }
        }
    }

    // Total operations:
    // 1. Disassemble all dolls that are not part of the initial 1->2->...->X sequence.
    //    This is already counted in 'operations'. Each such doll costs 1 to take out.
    // 2. Reassemble all dolls into the final 1->2->...->N chain.
    //    There are N-1 required nestings.
    //    The first 'consecutive_sequence_length - 1' nestings (1->2, 2->3, ..., (X-1)->X)
    //    are already present and don't need to be done.
    //    So, (N-1) - (consecutive_sequence_length - 1) = N - consecutive_sequence_length
    //    new nestings are required. Each costs 1.

    // Total operations = (disassembly operations) + (reassembly operations)
    // Disassembly operations:
    // Each doll not in the initial 1->...->X sequence needs to be taken out.
    // If a chain is not 1->...->X, all its 'm' dolls need to be taken out. Cost: m.
    // If a chain starts 1->...->X but then breaks, say 1->2->4, then 4 and subsequent
    // dolls need to be taken out. Cost: (m - X).
    // The 'operations' variable currently counts (disassembly + reassembly) for these dolls.
    // So, 'operations' = (disassembly for non-initial-sequence dolls) + (reassembly for non-initial-sequence dolls).
    // This means 'operations' already includes the cost of taking out dolls that are not part of the 1->...->X prefix.

    // Let's re-evaluate:
    // Total dolls to be moved (disassembled and reassembled): n - consecutive_sequence_length
    // Each of these dolls requires 1 disassembly and 1 reassembly. So (n - consecutive_sequence_length) * 2 operations.
    // This is the number of operations to get all dolls into individual pieces, except for the 1->...->X prefix.
    // Then, we need to assemble the remaining N - consecutive_sequence_length dolls into the chain.
    // This requires N - consecutive_sequence_length operations.
    // So, total = (n - consecutive_sequence_length) * 2 + (n - consecutive_sequence_length)
    // This simplifies to (n - consecutive_sequence_length) * 3.
    // This is incorrect. The problem states "In one second, you can perform one of the two following operations".
    // The cost is simply the count of operations.

    // Let's use the formula derived in thought process:
    // Total operations = (N - 1) + (N - K_good) * 2
    // Where K_good is the length of the longest prefix 1->2->...->K_good.
    // In our code, consecutive_sequence_length is K_good.

    long long result = (long long)(n - 1) + (long long)(n - consecutive_sequence_length) * 2;

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
