    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;

        // Initialize bounds for the reachable region
        // The problem guarantees that if a solution exists, there's one with |X|, |Y| <= 10^5.
        // So, we can use these as initial bounds.
        int min_x = -100000;
        int max_x = 100000;
        int min_y = -100000;
        int max_y = 100000;

        for (int i = 0; i < n; ++i) {
            int x, y, f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // Robot can move left (f1=1)
            // If it cannot move left (f1=0), it means it cannot reach any point to its left.
            // So, the target X must be >= its current X.
            if (f1 == 0) { // Cannot move left (x_c - 1)
                min_x = std::max(min_x, x);
            }

            // Robot can move up (f2=1)
            // If it cannot move up (f2=0), it means it cannot reach any point above it.
            // So, the target Y must be <= its current Y.
            if (f2 == 0) { // Cannot move up (y_c + 1)
                max_y = std::min(max_y, y);
            }

            // Robot can move right (f3=1)
            // If it cannot move right (f3=0), it means it cannot reach any point to its right.
            // So, the target X must be <= its current X.
            if (f3 == 0) { // Cannot move right (x_c + 1)
                max_x = std::min(max_x, x);
            }

            // Robot can move down (f4=1)
            // If it cannot move down (f4=0), it means it cannot reach any point below it.
            // So, the target Y must be >= its current Y.
            if (f4 == 0) { // Cannot move down (y_c - 1)
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. We can pick any point within the intersection.
            // For example, (min_x, min_y)
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            // No common reachable point.
            std::cout << 0 << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate known characters based on s[i] == s[i+k] property
    for (int i = 0; i < n - k; ++i) {
        if (s[i] != '?' && s[i+k] != '?') {
            if (s[i] != s[i+k]) {
                std::cout << "NO\n";
                return;
            }
        } else if (s[i] != '?') {
            s[i+k] = s[i];
        } else if (s[i+k] != '?') {
            s[i] = s[i+k];
        }
    }

    // Step 2: Check the first k characters for consistency and count 0s, 1s, and ?s
    int count0 = 0;
    int count1 = 0;
    int countQ = 0;

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            count0++;
        } else if (s[i] == '1') {
            count1++;
        } else { // s[i] == '?'
            countQ++;
        }
    }

    // Check if it's possible to make the first k-length substring balanced
    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we can fill '?'s to make the first k-length substring balanced,
    // then all subsequent k-length substrings will also be balanced due to s[i] == s[i+k].
    // We need to ensure there are enough '?'s to fill the deficit.
    // The number of '0's needed is k/2 - count0.
    // The number of '1's needed is k/2 - count1.
    // The total '?'s available must be at least the sum of needed '0's and '1's.
    if (countQ < (k / 2 - count0) + (k / 2 - count1)) {
        // This condition is actually redundant if count0 <= k/2 and count1 <= k/2.
        // Because (k/2 - count0) + (k/2 - count1) = k - (count0 + count1).
        // And countQ = k - (count0 + count1).
        // So countQ will always be exactly equal to the needed amount.
        // This check is implicitly covered by count0 <= k/2 and count1 <= k/2.
        // However, it's good for clarity.
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    // We need to handle division by 2 with modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, b-1=0, sum is 0.

    sum_r_term = (sum_r_term % MOD * (b % MOD)) % MOD;
    sum_r_term = (sum_r_term * 500000004) % MOD;

    // Calculate sum_k = sum_{k=1 to a} (k * b + 1)
    // sum_k = sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // sum_k = b * sum_{k=1 to a} k + a
    // sum_k = b * (a * (a+1) / 2) + a
    long long sum_k_term = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_term = (sum_k_term * 500000004) % MOD; // (a * (a+1) / 2)
    sum_k_term = (sum_k_term * (b % MOD)) % MOD; // b * (a * (a+1) / 2)
    sum_k_term = (sum_k_term + (a % MOD)) % MOD; // + a

    // Total sum = sum_k * sum_r
    long long total_sum = (sum_k_term * sum_r_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

