    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // For each a[i], we want to add a multiple of n such that a[i] becomes 0 (mod n).
    // The value to add is (n - (a[i] % n)) % n.
    // If a[i] % n == 0, we add 0.
    // If a[i] % n != 0, we add n - (a[i] % n).
    // This value is always positive or zero.
    // To make it negative if a[i] is negative, we can use:
    // long long remainder = a[i] % n;
    // long long to_add = (remainder == 0) ? 0 : (n - remainder);
    // This works for positive a[i]. For negative a[i], C++ % operator can return negative.
    // A robust way to get positive modulo: ((a[i] % n) + n) % n.
    // Then, we want to add `k * n` such that `a[i] + k * n` is a multiple of `n`.
    // We want `a[i] + k * n = 0 (mod n)`. This is always true.
    // We want `a[i] + k * n = 0`. This is not what we are doing.
    // We want `a[i] + b_i` to be a multiple of `n`.
    // So `b_i = (k * n) - a[i]`.
    // The simplest is to make `a[i]` a multiple of `n`.
    // We want `a[i] + b_i` to be `0 (mod n)`.
    // So `b_i = -a[i] (mod n)`.
    // Let `rem = a[i] % n`. If `rem` is negative, add `n` to make it positive.
    // `rem = (a[i] % n + n) % n`.
    // We need to add `(n - rem) % n` to `a[i]`.
    // Let `x = a[i]`. We want to add `b_i` such that `(x + b_i) % n == 0`.
    // The simplest `b_i` is `(n - (x % n + n) % n) % n`.
    // This makes `x` a multiple of `n`.
    // We can add `(n - (a[i] % n + n) % n) * (n-1)` to `a[i]`.
    // This is `(n - (a[i] % n + n) % n)` times `n-1`.
    // This is `(n - (a[i] % n + n) % n)` times `len`.
    // This makes `a[i]` a multiple of `n`.
    // The problem states we can add `k * len`.
    // We want to make `a[i]` a multiple of `n`.
    // So we add `(n - (a[i] % n + n) % n) * n`.
    // This is `(n - (a[i] % n + n) % n)` times `n`.
    // This is `(n - (a[i] % n + n) % n)` times `len`.
    // This makes `a[i]` a multiple of `n`.
    // This is for `a[0]` to `a[n-2]`.

    if (n == 1) {
        // Special case for n=1
        // Op 1: [1,1], add -a[0]
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Op 2: [1,1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";

        // Op 3: [1,1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Modify elements a[0] to a[n-2]
    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n; // Ensure positive remainder
        long long to_add = remainder * (n - 1); // Add (n-1) * remainder to make a[i] a multiple of n
        std::cout << to_add << (i == n - 2 ? "" : " ");
        a[i] += to_add;
    }
    std::cout << "\n";

    // Operation 2: Modify element a[n-1]
    std::cout << n << " " << n << "\n";
    long long to_add_last = -a[n - 1]; // Make a[n-1] zero
    std::cout << to_add_last << "\n";
    a[n - 1] += to_add_last;

    // Operation 3: Modify all elements a[0] to a[n-1]
    // At this point, a[0]...a[n-2] are multiples of n. a[n-1] is 0.
    // We want to make all of them 0.
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        long long to_add_final = -a[i]; // Make a[i] zero
        std::cout << to_add_final << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int initial_wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                initial_wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
            }
        }

        if (initial_wins == n) { // All games are already wins
            std::cout << initial_score << "\n";
            continue;
        }

        if (k == 0) { // No changes allowed
            std::cout << initial_score << "\n";
            continue;
        }

        // If there are no wins initially, and we have k changes, we can make k wins.
        // The best way is to make them consecutive.
        // If n=1, k=1, L -> W, score 1.
        // If n=5, k=2, LLLLL -> WWLLL, score 1+2=3.
        // If n=5, k=5, LLLLL -> WWWWW, score 1+2+2+2+2=9.
        if (initial_wins == 0) {
            int wins_to_make = std::min(n, k);
            if (wins_to_make == 0) { // Should not happen if k > 0
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + (wins_to_make - 1) * 2 << "\n";
            }
            continue;
        }

        // Strategy:
        // 1. Convert 'L's to 'W's that are adjacent to existing 'W's. This gives +2 points per 'L' converted.
        // 2. Convert 'L's to 'W's in gaps between 'W's. This gives +2 points per 'L' converted, and potentially merges segments.
        // 3. Convert 'L's to 'W's that are not adjacent to any 'W'. This gives +1 point per 'L' converted.

        // Find gaps of 'L's between 'W's
        std::vector<int> gap_lengths;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }

        if (first_W != -1) { // There is at least one 'W'
            int current_gap = 0;
            for (int i = first_W + 1; i <= last_W - 1; ++i) {
                if (s[i] == 'L') {
                    current_gap++;
                } else { // s[i] == 'W'
                    if (current_gap > 0) {
                        gap_lengths.push_back(current_gap);
                    }
                    current_gap = 0;
                }
            }
            if (current_gap > 0) {
                gap_lengths.push_back(current_gap);
            }
        }

        std::sort(gap_lengths.begin(), gap_lengths.end());

        int current_k = k;
        int current_score = initial_score;
        int wins_added = 0;

        // Fill smallest gaps first
        for (int gap_len : gap_lengths) {
            if (current_k >= gap_len) {
                current_k -= gap_len;
                current_score += gap_len * 2 + 1; // Each L becomes W (+2), and gap merge (+1)
                wins_added += gap_len;
            } else {
                current_score += current_k * 2; // Each L becomes W (+2)
                wins_added += current_k;
                current_k = 0;
                break;
            }
        }

        // After filling gaps, we might have remaining k.
        // These remaining k can be used to convert 'L's outside the first_W to last_W range,
        // or 'L's adjacent to existing 'W's.
        // Each such conversion adds 2 points (1 for the W itself, 1 for making it consecutive).
        // Or, if it's not adjacent to a W, it adds 1 point.
        // Since we already have wins, any new W will either be adjacent to an existing W (score +2)
        // or it will be a standalone W (score +1).
        // The best way to use remaining k is to make new W's adjacent to existing W's.
        // This means converting 'L's to 'W's at the ends of the current 'W' segments.
        // Each such conversion adds 2 points.
        // The number of 'L's available for this is (n - initial_wins - sum of gap_lengths).
        // This is equivalent to just adding 2 points for each remaining k.
        current_score += std::min(current_k, n - initial_wins - wins_added) * 2;

        std::cout << current_score << "\n";
    }
    return 0;
}

