            continue;
        }

        // Total possible substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If m ones are placed, they divide the string into at most m+1 segments.
        // To minimize substrings of all zeros, we want to distribute the zeros
        // as evenly as possible among these segments.
        // The '1's act as separators.
        // We can think of placing m '1's and then distributing n-m '0's into m+1 bins.
        // The bins are before the first '1', between any two '1's, and after the last '1'.
        // Example: _ 1 _ 1 _ ... _ 1 _
        // There are m+1 possible places for blocks of zeros.

        // Number of blocks of zeros that will have floor(num_zeros / (m+1)) zeros
        long long k_small = num_zeros / (m + 1);
        // Number of blocks of zeros that will have ceil(num_zeros / (m+1)) zeros
        long long k_large = k_small + 1;

        // Number of blocks that get k_large zeros
        long long count_large_blocks = num_zeros % (m + 1);
        // Number of blocks that get k_small zeros
        long long count_small_blocks = (m + 1) - count_large_blocks;

        // Calculate the number of substrings consisting only of zeros
        long long zero_substrings_count = 0;
        if (k_small > 0) {
            zero_substrings_count += count_small_blocks * (k_small * (k_small + 1) / 2);
        }
        if (k_large > 0) {
            zero_substrings_count += count_large_blocks * (k_large * (k_large + 1) / 2);
        }

        // The maximum value of f(s) is total_substrings - minimum_zero_substrings_count
        std::cout << total_substrings - zero_substrings_count << "\n";
    }
    return 0;
}

