#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n + 1, std::vector<long long>(n + 1));
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n + 1, false);

    // Process vertices in reverse order of removal (i.e., addition)
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added" back to the graph
        active_vertices[k] = true;

        // Update shortest paths using vertex k as an intermediate
        // This is the core of Floyd-Warshall
        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= n; ++j) {
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After updating paths with k, calculate the sum of shortest paths
        // between all currently active vertices.
        long long current_sum = 0;
        for (int i = 1; i <= n; ++i) {
            if (active_vertices[i]) {
                for (int j = 1; j <= n; ++j) {
                    if (active_vertices[j] && i != j) { // Only consider distinct active vertices
                        current_sum += dist[i][j];
                    }
                }
            }
        }
        results.push_back(current_sum);
    }

    // Output results in the correct order (reverse of how they were collected)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

