    // For $s_x = s_{x+k} = s_{x+2k}$, the length of the pattern is $2k+1$.
    // If $2k+1 \ge 15$, i.e., $k \ge 7$, then it is guaranteed that if such a pattern exists,
    // there must be a pattern with $k' \le 6$ within the same range.
    // This is a result from combinatorics on words, related to "squares" or "cubes".
    // For example, if $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$, then the substring $s[x \dots x+2k]$ is "good".
    // It is known that if a string contains a 3-term arithmetic progression of identical characters,
    // it must contain one where the common difference is at most 6.
    // This means we only need to check $k \in \{1, 2, 3, 4, 5, 6\}$.
    // This significantly reduces the complexity.

    std::vector<int> min_r_idx_for_l_idx(n, n); // min_r_idx_for_l_idx[l_idx] = min r_idx such that s[l_idx...r_idx] is good.

    for (int i = 0; i < n; ++i) { // i is the 0-indexed x'
        for (int k = 1; k <= 6; ++k) { // k is the step
            if (i + 2 * k < n) { // Check if x'+2k is within bounds
                if (s[i] == s[i + k] && s[i] == s[i + 2 * k]) {
                    // Found a triple match starting at i with step k, ending at i+2k.
                    // This means for any l_idx <= i, the substring s[l_idx ... i+2k] is good.
                    // So, we can update min_r_idx_for_l_idx[l_idx] to min(current, i+2k).
                    // Since we iterate i from 0 to n-1, and for each i, we update for l_idx <= i,
                    // we can simply update min_r_idx_for_l_idx[i] = min(current, i+2k).
                    // The propagation to smaller l_idx will be handled in the next step.
                    min_r_idx_for_l_idx[i] = std::min(min_r_idx_for_l_idx[i], i + 2 * k);
                }
            }
        }
    }

    // Now, propagate the minimum r_idx backwards.
    // If s[l_idx ... r_idx] is good, then s[l_idx-1 ... r_idx] is also good.
    // So, min_r_idx_for_l_idx[l_idx-1] must be less than or equal to min_r_idx_for_l_idx[l_idx].
    // Specifically, min_r_idx_for_l_idx[l_idx-1] = min(min_r_idx_for_l_idx[l_idx-1], min_r_idx_for_l_idx[l_idx]).
    for (int l_idx = n - 2; l_idx >= 0; --l_idx) {
        min_r_idx_for_l_idx[l_idx] = std::min(min_r_idx_for_l_idx[l_idx], min_r_idx_for_l_idx[l_idx + 1]);
    }

    long long good_pairs_count = 0;
    for (int l_idx = 0; l_idx < n; ++l_idx) {
        if (min_r_idx_for_l_idx[l_idx] < n) {
            // If min_r_idx_for_l_idx[l_idx] is less than n, it means there is at least one
            // valid r_idx for this l_idx.
            // The valid r_idx values are from min_r_idx_for_l_idx[l_idx] up to n-1.
            // The number of such r_idx values is (n-1) - min_r_idx_for_l_idx[l_idx] + 1.
            good_pairs_count += (n - min_r_idx_for_l_idx[l_idx]);
        }
    }

    std::cout << good_pairs_count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if all target tracks can be covered within time 't'
bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        long long current_h = h[h_idx];
        long long left_reach = current_h - t;
        long long right_reach = current_h + t;

        // Skip target tracks already covered by previous heads
        // or tracks that are too far to the left for the current head
        while (p_idx < m && p[p_idx] < left_reach) {
            // This p[p_idx] cannot be reached by current_h within time t.
            // If it's not covered by any previous head, then it's impossible.
            // Since we iterate h_idx from left to right, and p_idx from left to right,
            // if p[p_idx] < left_reach, it means p[p_idx] is to the left of current_h's reach.
            // If it wasn't covered by h[h_idx-1], it won't be covered by current_h or any h[h_idx+k].
            // So, if p[p_idx] < left_reach, it must have been covered by a previous head.
            // If it wasn't, then this 't' is not enough.
            // However, the logic for `p_idx` advancement handles this implicitly.
            // We only advance `p_idx` if `p[p_idx]` is covered.
            // If `p[p_idx]` is not covered by `current_h` and `p[p_idx] < left_reach`,
            // it means `p[p_idx]` was not covered by any `h_k` where `k <= h_idx`.
            // This implies `check` should return false.
            // But the problem is about covering *all* `p_j`.
            // The `p_idx` should only advance if `p[p_idx]` is covered by `current_h`.
            // If `p[p_idx]` is not covered by `current_h` and `p[p_idx] < left_reach`,
            // it means `p[p_idx]` is not covered by `current_h` and cannot be covered by any `h_k` where `k > h_idx` either.
            // So, if `p[p_idx] < left_reach`, it must have been covered by a previous head.
            // If it wasn't, then `t` is not enough.
            // The current loop structure implicitly handles this: if `p_idx` doesn't advance past `p[p_idx]`,
            // it means `p[p_idx]` was not covered.
            // The `while (p_idx < m && p[p_idx] <= right_reach)` loop below will cover all `p_j` that `current_h` can reach.
            // If `p[p_idx]` is not covered by `current_h` and `p[p_idx] < left_reach`, it means `p[p_idx]` is too far left.
            // This `p_idx` should have been covered by a previous head.
            // If `p_idx` is still pointing to such a `p[p_idx]`, it means it wasn't covered.
            // So, if `p[p_idx] < left_reach`, it means `p[p_idx]` is not covered by `current_h` and it's to the left.
            // This implies `p[p_idx]` must have been covered by a previous head.
            // If `p_idx` is still pointing to `p[p_idx]` and `p[p_idx] < left_reach`, it means `p[p_idx]` was not covered.
            // This `check` function should return false.
            // Let's refine the logic:
            // We need to cover p[p_idx].
            // If p[p_idx] is to the left of current_h's reach (p[p_idx] < left_reach),
            // then current_h cannot cover it. Since h and p are sorted, no future head can cover it either.
            // So, if p[p_idx] < left_reach, it means p[p_idx] was not covered by any previous head, and cannot be covered by current or future heads.
            // Thus, 't' is not enough.
            return false;
        }

        // Advance p_idx to cover all tracks reachable by current_h
        while (p_idx < m && p[p_idx] <= right_reach) {
            p_idx++;
        }
    }
    // All target tracks are covered if p_idx reached the end of p
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible distance: (max_p - min_h) or (max_h - min_p)
    // A safe upper bound is the maximum possible coordinate value.
    // 10^10 is the max coordinate, so 2 * 10^10 is a safe upper bound for distance.
    long long high = 20000000000LL; 
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string result(n, ' ');
    bool found_solution = false;

    for (int split_val = 0; split_val <= 9; ++split_val) {
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        std::string current_coloring(n, ' ');

        bool possible_split = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < split_val) {
                current_coloring[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > split_val) {
                current_coloring[i] = '2';
                s2_digits.push_back(d[i]);
            } else { // d[i] == split_val
                // Try to assign to color 1 if it maintains non-decreasing order for S1
                // and if it's not "too late" (i.e., we haven't started S2 with a digit > split_val)
                if (!s2_digits.empty() && s2_digits.back() < split_val) { // This condition is actually impossible if s2_digits only contains digits > split_val
                    // This branch should ideally not be taken if s2_digits only contains digits > split_val
                    // However, if we are forced to put split_val into S2, it must be >= s2_digits.back()
                    // For now, let's simplify: if we've already put a digit > split_val into S2,
                    // then this split_val must go into S2.
                    current_coloring[i] = '2';
                    s2_digits.push_back(d[i]);
                } else {
                    // Prefer color 2 for split_val digits to allow more flexibility for later digits
                    // that are also split_val.
                    // If s1_digits is empty or s1_digits.back() <= d[i], we can put it in S1.
                    // If s2_digits is empty or s2_digits.back() <= d[i], we can put it in S2.
                    // The strategy is to put it in S2 if possible, otherwise S1.
                    // This is a greedy choice.
                    // A better greedy choice: put it in S2 if it doesn't violate S2's order.
                    // If it violates S2's order, try S1. If it violates S1's order, then impossible.
                    // The current logic for split_val is:
                    // If we have already placed a digit into S2 (meaning it was > split_val),
                    // then this split_val must go into S2.
                    // Otherwise, we can place it into S1.
                    // This is not quite right. The rule is:
                    // All digits < split_val go to S1.
                    // All digits > split_val go to S2.
                    // Digits == split_val can go to S1 or S2.
                    // To make the combined sequence sorted, all S1 digits must be <= all S2 digits.
                    // This means the last S1 digit must be <= the first S2 digit.
                    // If we put a `split_val` into S1, it must be >= `s1_digits.back()`.
                    // If we put a `split_val` into S2, it must be >= `s2_digits.back()`.
                    // And importantly, `s1_digits.back()` (if any) must be <= `s2_digits.front()` (if any).
                    //
                    // A simpler greedy approach for `d[i] == split_val`:
                    // If `s2_digits` is not empty, it means we've already started placing digits into S2.
                    // These digits must be `split_val` or greater.
                    // If `s2_digits` is not empty, then `d[i]` must go into S2 to maintain the `S1_max <= S2_min` property.
                    // If `s2_digits` is empty, we can put `d[i]` into S1. This keeps `S2_min` potentially higher.
                    // This strategy is: put `split_val` into S2 if S2 has already started, otherwise put into S1.
                    if (!s2_digits.empty()) {
                        current_coloring[i] = '2';
                        s2_digits.push_back(d[i]);
                    } else {
                        current_coloring[i] = '1';
                        s1_digits.push_back(d[i]);
                    }
                }
            }
        }

        // Check if S1 is sorted
        bool s1_sorted = true;
        for (size_t i = 1; i < s1_digits.size(); ++i) {
            if (s1_digits[i] < s1_digits[i-1]) {
                s1_sorted = false;
                break;
            }
        }
        if (!s1_sorted) continue;

        // Check if S2 is sorted
        bool s2_sorted = true;
        for (size_t i = 1; i < s2_digits.size(); ++i) {
            if (s2_digits[i] < s2_digits[i-1]) {
                s2_sorted = false;
                break;
            }
        }
        if (!s2_sorted) continue;

        // Check if max(S1) <= min(S2)
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                continue;
            }
        }

        found_solution = true;
        result = current_coloring;
        break;
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
