int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, subsequent values will be current_val + d + 1

    // Iterate from largest possible power of 2 down to 1
    // The maximum power of 2 for X up to 10^9 is around 2^29 (since 2^30 > 10^9)
    // So we can iterate k from 29 down to 1.
    // For each k, we check if X has 2^k - 1 as a component.
    // This is equivalent to checking the k-th bit of X+1.
    // If X+1 has a 1 at bit k, it means X has a 2^k-1 component.
    // Example: X=10. X+1=11 (binary 1011).
    // k=3: (1<<3)-1 = 7. X=10. 10 >= 7. X -= 7. X=3. Add 3 elements.
    // k=2: (1<<2)-1 = 3. X=3. 3 >= 3. X -= 3. X=0. Add 2 elements.
    // This greedy approach works because 2^k - 1 is always greater than the sum of all smaller 2^j - 1 terms (for j < k).
    // Sum_{j=0 to k-1} (2^j - 1) = (2^k - 1) - k.
    // We need to be careful with the exact powers.
    // The number of subsequences from k identical elements is 2^k - 1.
    // We want to decompose X into sum of (2^k_i - 1).
    // This is equivalent to decomposing X+1 into sum of 2^k_i.
    // If X+1 = sum(2^k_i), then X = sum(2^k_i - 1) + (number of k_i terms - 1).
    // This is not quite right.
    // Let's use the standard binary representation of X.
    // If X = sum(b_i * 2^i), then we can think of it as having b_i groups of 2^i subsequences.
    // A group of 2^i subsequences can be formed by taking one element and i other elements that are "far" from it.
    // This is getting complicated.

    // Let's re-evaluate the strategy:
    // We want to represent X as a sum of (2^k - 1) terms.
    // X = (2^k1 - 1) + (2^k2 - 1) + ...
    // This is equivalent to X + (number of terms) = 2^k1 + 2^k2 + ...
    // Let's try to build the array by adding blocks of identical elements.
    // If we add `k` identical elements `C`, they contribute `2^k - 1` subsequences.
    // If we then add a new element `C'` such that `C' - C >= d`, then `C'` forms its own set of subsequences.
    // And any subsequence containing both `C` and `C'` will be discarded.
    // So, if we have `k` elements `C`, and then add `m` elements `C'`, where `C' - C >= d`,
    // the total number of valid subsequences is `(2^k - 1) + (2^m - 1)`.
    // This means we can decompose X into a sum of `(2^k - 1)` terms.
    // This is equivalent to finding the binary representation of `X+1`.
    // If `X+1 = sum(2^p_i)`, then `X = sum(2^p_i - 1) + (number of p_i terms - 1)`.
    // This is not correct.

    // The correct approach for X = sum (2^k_i - 1) is to iterate k from largest to smallest.
    // For each k, if X >= (2^k - 1), we take this block.
    // This is a greedy approach.
    // Max k such that 2^k - 1 <= 10^9 is k=29 (2^29 - 1 approx 5*10^8).
    // 2^30 - 1 approx 10^9.
    // So k can go up to 30.

    for (int k = 30; k >= 1; --k) {
        long long num_subsequences_from_k_elements = (1LL << k) - 1;
        while (X >= num_subsequences_from_k_elements) {
            // Add k identical elements to the array
            for (int i = 0; i < k; ++i) {
                result_array.push_back(current_val);
            }
            X -= num_subsequences_from_k_elements;
            // Increment current_val by d+1 to ensure new elements are "far" enough
            current_val += (d + 1);
            if (result_array.size() > 10000) {
                // This case should ideally not be reached if X <= 10^9 and k >= 1.
                // Max elements: X=10^9. Smallest block is k=1, contributes 1 subsequence.
                // So max elements is 10^9. This is too large.
                // The problem states n <= 10^4.
                // This implies that we cannot use k=1 for too many times.
                // The sum of k's must be <= 10^4.
                // If X = 10^9, and we use k=1, we need 10^9 elements.
                // This means we must use larger k values.
                // The greedy approach of taking largest possible k first is optimal for minimizing number of elements.
                // Example: X=10.
                // k=4: 2^4-1 = 15. 10 < 15. Skip.
                // k=3: 2^3-1 = 7. 10 >= 7. Add 3 elements (current_val). X = 10-7 = 3. current_val += d+1.
                // k=2: 2^2-1 = 3. 3 >= 3. Add 2 elements (current_val). X = 3-3 = 0. current_val += d+1.
                // k=1: 2^1-1 = 1. 0 < 1. Skip.
                // Total elements: 3+2 = 5. This is fine.
                // The maximum number of elements is when X is just below 2^30-1, say X = (2^29-1) + (2^28-1) + ... + (2^1-1).
                // This is sum of k from 1 to 29. Sum(k) = 29*30/2 = 435. This is well within 10^4.
                // The worst case for number of elements is when X is a sum of many small (2^k-1) terms.
                // For example, if X = 10^9, and we use k=1 (2^1-1=1) for all of them, we would need 10^9 elements.
                // But the greedy strategy ensures we use the largest possible k.
                // The sum of k's for X up to 10^9 will be at most around 30 * log2(X) / 2.
                // More precisely, the sum of k's is bounded by sum of k for X = 2^30 - 1.
                // This is sum of k for k from 1 to 30. Sum(k) = 30*31/2 = 465.
                // This is well within 10^4. So no need for this check.
            }
        }
    }

    if (X != 0) {
        // This should not happen if the logic is correct, as X should be fully decomposed.
        // If X is not 0, it means we couldn't form X using the (2^k - 1) blocks.
        // This implies there's no solution with this construction method.
        // However, the greedy decomposition of X into sum of (2^k-1) terms is always possible.
        // For example, X=10.
        // k=30: (2^30-1) > 10.
        // ...
        // k=4: (2^4-1) = 15 > 10.
        // k=3: (2^3-1) = 7. X=10 >= 7. Add 3 elements. X = 10-7 = 3. current_val += d+1.
        // k=2: (2^2-1) = 3. X=3 >= 3. Add 2 elements. X = 3-3 = 0. current_val += d+1.
        // k=1: (2^1-1) = 1. X=0 < 1.
        // Final X=0.
        // So X should always become 0.
        // If it doesn't, it's an error in reasoning or implementation.
        // The problem statement implies a solution always exists if X is positive.
        // The only case where it might not be possible is if n > 10000.
        // But we've established that n will be small.
        // So, this `if (X != 0)` block is likely unreachable.
    }

    std::cout << result_array.size() << std::endl;
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
