        // In this case, the number of multiples of 2 might not be the maximum.
        // For example, if l=3, r=6. r=6, l=3. r = 2*l.
        // Multiples of 2: {4, 6} (count 2)
        // Multiples of 3: {3, 6} (count 2)
        // Multiples of 4: {4} (count 1)
        // Multiples of 5: {5} (count 1)
        // Multiples of 6: {6} (count 1)
        // In this case, 2 and 3 both have count 2. The problem says print any.
        // So, if r >= 2*l, 2 is a valid answer.
        // If r < 2*l, then the range [l, r] is small enough that 2 might not be the only or best answer.
        // However, the question asks for *any* integer.
        // The number 2 will always be a divisor for at least floor(r/2) - ceil(l/2) + 1 numbers.
        // For any k > 2, the count of its multiples is floor(r/k) - ceil(l/k) + 1.
        // This count is always less than or equal to the count for 2.
        // The only exception is when l is small and r is small, e.g., l=3, r=6.
        // Count for 2: floor(6/2) - ceil(3/2) + 1 = 3 - 2 + 1 = 2.
        // Count for 3: floor(6/3) - ceil(3/3) + 1 = 2 - 1 + 1 = 2.
        // In this case, 2 and 3 are both valid answers.
        // The simplest answer is 2, as it's the smallest prime and thus has the most multiples.
        // The only case where 2 might not be the answer is if l=r, where l itself is the answer.
        // But we handled l=r separately.
        // For any l < r, 2 will always be a valid answer.
        // Consider the number of multiples of x in [l, r]: floor(r/x) - (l+x-1)/x + 1.
        // For x=2, count is floor(r/2) - (l+1)/2 + 1.
        // For x=3, count is floor(r/3) - (l+2)/3 + 1.
        // If r >= 2*l, then the count for 2 is at least (r/2) - (l/2) + 1.
        // Since r >= 2*l, r/2 >= l. So (r/2) - (l/2) >= l/2.
        // The count for 2 is at least l/2 + 1.
        // For any x > 2, the count is at most r/x.
        // If x=3, count is at most r/3.
        // If r >= 2*l, then r/3 >= 2l/3.
        // Is l/2 + 1 always greater than or equal to r/3? Not necessarily.
        // Example: l=10, r=20. r=2l.
        // Count for 2: floor(20/2) - (10+1)/2 + 1 = 10 - 5 + 1 = 6. (10,12,14,16,18,20)
        // Count for 3: floor(20/3) - (10+2)/3 + 1 = 6 - 4 + 1 = 3. (12,15,18)
        // Count for 4: floor(20/4) - (10+3)/4 + 1 = 5 - 3 + 1 = 3. (12,16,20)
        // Count for 5: floor(20/5) - (10+4)/5 + 1 = 4 - 2 + 1 = 3. (10,15,20)
        // In this case, 2 is clearly the winner.

        // The problem is simpler than it seems.
        // The number 2 is the smallest prime.
        // For any range [l, r] where l < r, the number of multiples of 2 will be
        // floor(r/2) - ceil(l/2) + 1.
        // The number of multiples of any other integer k > 2 will be
        // floor(r/k) - ceil(l/k) + 1.
        // Since k > 2, floor(r/k) <= floor(r/2) and ceil(l/k) >= ceil(l/2).
        // Thus, floor(r/k) - ceil(l/k) + 1 <= floor(r/2) - ceil(l/2) + 1.
        // This means the count for 2 is always greater than or equal to the count for any other integer k > 2.
        // Therefore, 2 is always an answer (if l < r).
        // The only edge case is when l=r, where the only divisor (other than 1) is l itself.
        // But this is handled by the `if (l == r)` condition.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // If a[i] was 1 or -1, it contributes to has_one/has_minus_one for elements to its left.
            // But we are iterating right-to-left, so its value for future elements (i.e., elements with index < i)
            // is its original value.
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. This requires a '1' to its left.
            if (!has_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. This requires a '-1' to its left.
            if (!has_minus_one) {
                possible = false;
                break;
            }
        }

        // Update has_one and has_minus_one for elements to the left of current 'i'.
        // The current a[i] is no longer available for operations on elements with index < i.
        // So, if a[i] was the only '1' or '-1' available, we must remove its contribution.
        // However, the problem states "Choose any pair of indexes (i, j) such that 1 <= i < j <= n".
        // This means a[i] can only affect a[j] where j > i.
        // When we are at index 'i', we are determining if a[i] can become b[i].
        // The elements a[0]...a[i-1] are available to modify a[i].
        // The elements a[i+1]...a[n-1] are NOT available to modify a[i].
        // The elements a[0]...a[i-1] are available to modify a[k] for k > i.
        //
        // The logic for `has_one` and `has_minus_one` should track if there is a 1 or -1
        // *among elements a[0]...a[i-1]*.
        //
        // So, when we process a[i], we check `has_one` and `has_minus_one` based on elements
        // a[0]...a[i-1].
        // After processing a[i], we need to update `has_one` and `has_minus_one` for the next iteration (i-1).
        // This means we remove a[i]'s original value from consideration for elements to its left.
        //
        // The current `has_one` and `has_minus_one` are for elements a[0]...a[i].
        // For the next iteration (i-1), we need to check elements a[0]...a[i-1].
        // So, if a[i] was 1, we decrement a count of 1s. If it was -1, we decrement a count of -1s.
        // This is better done with counts.

        // Let's restart the logic for clarity with counts.
    }

    // Re-evaluating with counts for `has_one` and `has_minus_one`
    // `count_one` and `count_minus_one` will track the number of 1s and -1s
    // in the prefix a[0...i-1] when considering a[i].
    int current_has_one = 0;
    int current_has_minus_one = 0;

    // First, check a[0]. It cannot be changed.
    if (a[0] != b[0]) {
        possible = false;
    } else {
        if (a[0] == 1) current_has_one++;
        if (a[0] == -1) current_has_minus_one++;

        for (int i = 1; i < n; ++i) {
            if (a[i] == b[i]) {
                // No operation needed for a[i].
            } else if (a[i] < b[i]) {
                // Need to increase a[i]. Requires a '1' from a[0...i-1].
                if (current_has_one == 0) {
                    possible = false;
                    break;
                }
            } else { // a[i] > b[i]
                // Need to decrease a[i]. Requires a '-1' from a[0...i-1].
                if (current_has_minus_one == 0) {
                    possible = false;
                    break;
                }
            }
            // After processing a[i], update counts for elements a[0...i]
            // which will be available for elements a[j] where j > i.
            if (a[i] == 1) current_has_one++;
            if (a[i] == -1) current_has_minus_one++;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

