    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum_duration = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum_duration += a[i];
    }

    if (total_sum_duration % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_post_duration = total_sum_duration / k;
    std::vector<int> s_values;
    long long current_post_duration = 0;
    int current_post_videos_count = 0;
    int posts_formed = 0;

    for (int i = 0; i < n; ++i) {
        current_post_duration += a[i];
        current_post_videos_count++;

        if (current_post_duration == target_post_duration) {
            s_values.push_back(current_post_videos_count);
            current_post_duration = 0;
            current_post_videos_count = 0;
            posts_formed++;
        } else if (current_post_duration > target_post_duration) {
            // This post's duration exceeded the target, so no solution.
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_formed == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be caught by current_post_duration > target_post_duration
        // or if the loop finishes and current_post_duration != 0 (meaning last post incomplete)
        // or if posts_formed < k (meaning not enough posts could be formed).
        // The logic ensures that if current_post_duration == target_post_duration, it's added.
        // If it's not equal at the end, it means the last segment didn't sum up correctly.
        // If posts_formed != k, it means either too few or too many posts were formed.
        // Too many posts would imply target_post_duration was too small, which is impossible
        // given total_sum_duration / k. So it must be too few.
        std::cout << "No\n";
    }

    return 0;
}

