    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks.
        // So, total sticks required for coal and torches = k * y + k.
        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks
        // using the first trade offer.
        // Each trade of type 1 (1 stick -> x sticks) gives a net gain of (x - 1) sticks.
        // Number of trades to get enough sticks:
        // (total_sticks_required - 1) / (x - 1)
        // Since we need to round up, use (A + B - 1) / B for ceil(A/B).
        long long trades_for_sticks = (total_sticks_required - 1 + (x - 1) - 1) / (x - 1);

        // Number of trades to get k coal:
        // Each trade of type 2 (y sticks -> 1 coal) gives 1 coal.
        // So, k trades are needed to get k coal.
        long long trades_for_coal = k;

        // Total trades = trades for sticks + trades for coal
        long long total_trades = trades_for_sticks + trades_for_coal;

        std::cout << total_trades << "\n";
    }
    return 0;
}

