                // i=4, s[4]='R'. current_cell = 5. last_r_pos = 3 (cell 4). Gap = 5 - 4 = 1. max_gap = 2. last_r_pos = 4.
                // i=5, s[5]='L'. last_r_pos = 4.
                // i=6, s[6]='L'. last_r_pos = 4.
                // End of loop.
                // Final gap to n+1: (n+1) - (last_r_pos + 1) = (7+1) - (4+1) = 8 - 5 = 3.
                // max_gap = max(2, 3) = 3.

                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1));
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' to cell n+1.
        // The last 'R' was at index `last_r_pos`, which corresponds to cell `last_r_pos + 1`.
        // The target is cell `s.length() + 1`.
        max_gap = std::max(max_gap, (int)s.length() + 1 - (last_r_pos + 1));

        std::cout << max_gap << "\n";
    }
    return 0;
}

