// Function to determine if Box 1 can be the special box
// Box 1: (-inf, -1] (Negative, magnitude >= 1)
bool can_be_box1(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return A == 1;
    }

    // Final product must be negative. This means an odd number of negative values were multiplied.
    // Initial negative count: A + B
    // If A+B is odd, it's possible.
    // If A+B is even, we need to introduce an odd number of negative values through multiplication.
    // This can only happen if we multiply a positive value by a negative value.
    // However, the sign of the final product is determined by the parity of initial negative toys.
    // If A+B is odd, the final product is negative.
    // If A+B is even, the final product is positive.
    // So, for Box 1, A+B must be odd.
    if ((A + B) % 2 == 0) {
        return false; // Final product must be positive
    }

    // Now consider magnitude. Final product must be <= -1.
    // This means the magnitude must be >= 1.
    //
    // Case 1: All toys are N_L (A > 0, B=C=D=0)
    // If A is odd, final product is N_L. Possible.
    //
    // Case 2: All toys are N_S (B > 0, A=C=D=0)
    // If B is odd, final product is N_S. Not possible for Box 1.
    //
    // Case 3: All toys are P_S (C > 0, A=B=D=0)
    // If C is odd, final product is P_S. Not possible for Box 1.
    //
    // Case 4: All toys are P_L (D > 0, A=B=C=0)
    // If D is odd, final product is P_L. Not possible for Box 1.
    //
    // General case:
    // To get magnitude >= 1:
    // We need at least one toy with magnitude >= 1 (A or D).
    // If A+D == 0, then all initial toys have magnitude < 1.
    // Multiplying numbers with magnitude < 1 always results in a number with magnitude < 1.
    // So, if A+D == 0, the final product will have magnitude < 1.
    // Thus, if A+D == 0, Box 1 is not possible.
    if (A + D == 0) {
        return false;
    }

    // If A+B is odd (final product negative) AND A+D > 0 (possible to get magnitude >= 1),
    // then Box 1 is possible.
    // We can always arrange multiplications to keep magnitude >= 1 if there's at least one large toy.
    // Example: If we have a large toy (A or D) and a small toy (B or C), we can multiply the small toy
    // with another small toy to make it even smaller, or multiply it with a large toy.
    // The key is that if we have at least one large toy, we can ensure the final product's magnitude
    // is large by strategically multiplying small toys together first, or by multiplying large toys
    // with other large toys.
    //
    // Consider the "magnitude state":
    // M_S: current product has magnitude < 1
    // M_L: current product has magnitude >= 1
    //
    // If we have A+D > 0, we start with at least one M_L toy.
    // If we have only one M_L toy and many M_S toys:
    // We can multiply all M_S toys together. The result will be M_S.
    // Then multiply this M_S result with the M_L toy.
    // The final magnitude can be M_S or M_L depending on the specific values.
    //
    // However, the problem asks "can be".
    // If A+D > 0, it means there is at least one toy with magnitude >= 1.
    // If we have a toy with value $X \ge 1$ (from Box 4) or $X \le -1$ (from Box 1).
    // And we have other toys.
    // We can always pick values such that the magnitude remains large.
    // For example, if we have $X=2$ and $Y=0.1$, $Z=0.1$.
    // $(0.1 \times 0.1) \times 2 = 0.01 \times 2 = 0.02$ (small)
    // $(2 \times 0.1) \times 0.1 = 0.2 \times 0.1 = 0.02$ (small)
    //
    // This logic is flawed. The "can be" implies we can choose specific values.
    // If A+D > 0, we can choose values such that the magnitude remains >= 1.
    // For example, if we have $A=1, B=1, C=0, D=0$. Toys: $\{-2, -0.5\}$.
    // Product is $(-2) \times (-0.5) = 1$. This is P_L.
    //
    // The condition for magnitude >= 1 is:
    // If A+D > 0, it is possible to get a final product with magnitude >= 1.
    // This is because we can choose the values for toys in Box 1 and Box 4 to be arbitrarily large (e.g., 1000).
    // And values in Box 2 and Box 3 to be arbitrarily close to 1 (e.g., 0.99).
    // If we have at least one toy with magnitude >= 1, say $X$.
    // And we have $k$ toys with magnitude < 1.
    // We can choose the $k$ toys to have values like $0.999...$ or $-0.999...$.
    // Then $X \times (0.999...)^k$ will still have magnitude >= 1 if $X$ is large enough.
    // So, if A+D > 0, it is always possible to get a final product with magnitude >= 1.

    return true;
}

// Function to determine if Box 2 can be the special box
// Box 2: (-1, 0) (Negative, magnitude < 1)
bool can_be_box2(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return B == 1;
    }

    // Final product must be negative. So A+B must be odd.
    if ((A + B) % 2 == 0) {
        return false;
    }

    // Final product must have magnitude < 1.
    // This means it must be possible to get magnitude < 1.
    // If A+D == 0, all initial toys have magnitude < 1.
    // Multiplying numbers with magnitude < 1 always results in a number with magnitude < 1.
    // So if A+D == 0, the final product will always have magnitude < 1.
    if (A + D == 0) {
        return true;
    }

    // If A+D > 0, it is still possible to get magnitude < 1.
    // Example: A=1, B=0, C=0, D=1. Toys: {-2, 3}. Product = -6 (Box 1).
    // Example: A=1, B=1, C=0, D=0. Toys: {-2, -0.1}. Product = 0.2 (Box 3).
    // Example: A=1, B=1, C=0, D=0. Toys: {-2, -0.5}. Product = 1 (Box 4).
    //
    // If A+D > 0, we can choose values such that the magnitude becomes small.
    // For example, if we have a toy with value $X \ge 1$ (from Box 4) or $X \le -1$ (from Box 1).
    // And we have other toys.
    // We can choose the values for toys in Box 2 and Box 3 to be very small (e.g., 0.001).
    // If we have at least one toy with magnitude < 1 (B > 0 or C > 0), we can multiply it with a large toy.
    // For example, if we have $X=100$ (from D) and $Y=0.001$ (from B or C).
    // $100 \times 0.001 = 0.1$. This is magnitude < 1.
    // So, if B+C > 0, we can always make the final magnitude small.
    //
    // What if B+C == 0? This means all toys are from Box 1 or Box 4.
    // If B+C == 0, then all toys have magnitude >= 1.
    // Multiplying numbers with magnitude >= 1 always results in a number with magnitude >= 1.
    // So if B+C == 0, the final product will always have magnitude >= 1.
    // In this case, Box 2 is not possible.
    if (B + C == 0) {
        return false;
    }

    // If A+B is odd (final product negative) AND B+C > 0 (possible to get magnitude < 1),
    // then Box 2 is possible.
    return true;
}

// Function to determine if Box 3 can be the special box
// Box 3: (0, 1) (Positive, magnitude < 1)
bool can_be_box3(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return C == 1;
    }

    // Final product must be positive. So A+B must be even.
    if ((A + B) % 2 != 0) {
        return false;
    }

    // Final product must have magnitude < 1.
    // Similar to Box 2, if A+D == 0, then magnitude is always < 1.
    if (A + D == 0) {
        return true;
    }

    // If A+D > 0, we need to be able to make magnitude < 1.
    // This requires B+C > 0 (at least one small toy).
    if (B + C == 0) {
        return false; // All toys have magnitude >= 1, so final product will have magnitude >= 1.
    }

    // If A+B is even (final product positive) AND B+C > 0 (possible to get magnitude < 1),
    // then Box 3 is possible.
    return true;
}

// Function to determine if Box 4 can be the special box
// Box 4: [1, inf) (Positive, magnitude >= 1)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    long long total_toys = A + B + C + D;
    if (total_toys == 1) {
        return D == 1;
    }

    // Final product must be positive. So A+B must be even.
    if ((A + B) % 2 != 0) {
        return false;
    }

    // Final product must have magnitude >= 1.
    // Similar to Box 1, if A+D == 0, then magnitude is always < 1.
    if (A + D == 0) {
        return false;
    }

    // If A+B is even (final product positive) AND A+D > 0 (possible to get magnitude >= 1),
    // then Box 4 is possible.
    return true;
}

