    // Iterate through each point as the first point of a potential triplet
    for (int i = 0; i < n; ++i) {
        // For a fixed x[i], we need to find points x[j] and x[k] such that
        // i < j < k and x[k] - x[i] <= d.
        // This means x[k] must be less than or equal to x[i] + d.

        // Find the upper bound for k.
        // std::upper_bound returns an iterator to the first element greater than x[i] + d.
        // We want elements less than or equal to x[i] + d.
        // So, the valid indices for k are from i+1 up to (it - x.begin() - 1).
        auto it = std::upper_bound(x.begin() + i + 1, x.end(), x[i] + d);

        // The number of points (including x[j] and x[k]) that can be chosen
        // after x[i] and satisfy x_p <= x[i] + d.
        // These points are x[i+1], x[i+2], ..., x[idx_k_max].
        // The count of such points is (idx_k_max - (i+1) + 1) = idx_k_max - i.
        // Let m be the number of such points.
