        // These m points are candidates for x[j] and x[k].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long num_candidates_after_i = (it - x.begin()) - (i + 1);

        if (num_candidates_after_i >= 2) {
            count += num_candidates_after_i * (num_candidates_after_i - 1) / 2;
        }
