#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as minimums.
            // The remaining students are (c - mid) coders, (m - mid) mathematicians, and x unspecialized.
            // These remaining students must fill the remaining 'mid' slots in the teams.
            // Each team needs 3 members. 'mid' teams need 3 * 'mid' members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, 3 * 'mid' - 'mid' - 'mid' = 'mid' additional members are needed.
            // These 'mid' additional members can come from (c - mid) coders, (m - mid) mathematicians, or x unspecialized.
            // Total available for these additional 'mid' slots: (c - mid) + (m - mid) + x
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate the first k differences

    // Generate the first k+1 elements to produce k distinct differences
    // The differences will be k, k-1, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // The remaining elements are simply consecutive integers
    // starting from the next available number (which is 'left' after the loop)
    // This ensures no new differences are introduced, as |x - (x+1)| = 1
    // and 1 is already among the k differences generated.
    for (int i = k + 1; i < n; ++i) {
        p[i] = left;
        left++;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

