// Function to check if a subarray is a permutation of length 'len'
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0, though problem states non-zero.
                     // For this problem, l1, l2 >= 1.
    }
    if (start_idx + len > arr.size()) {
        return false;
    }

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n + 1, false); // prefix_is_perm[k] means a[0...k-1] is perm of length k
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    int distinct_count = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] < 1 || seen_prefix[a[i]]) { // a[i] > n is technically not possible given constraints a_i <= n-1
            // This prefix cannot be a permutation of any length
            // We can stop checking for this prefix path, but we need to continue for suffix checks
            // For simplicity, just mark it false and continue.
            // The max_val check will handle it.
        } else {
            seen_prefix[a[i]] = true;
            distinct_count++;
        }
        if (a[i] > current_max) {
            current_max = a[i];
        }
        prefix_max[i] = current_max;
        if (distinct_count == i + 1 && current_max == i + 1) {
            prefix_is_perm[i + 1] = true;
        }
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n + 1, false); // suffix_is_perm[k] means a[n-k...n-1] is perm of length k
    std::vector<bool> seen_suffix(n + 1, false);
    current_max = 0;
    distinct_count = 0;
    for (int i = n - 1; i >= 0; --i) {
        int len_from_end = n - i;
        if (a[i] > n || a[i] < 1 || seen_suffix[a[i]]) {
            // This suffix cannot be a permutation of any length
        } else {
            seen_suffix[a[i]] = true;
            distinct_count++;
        }
        if (a[i] > current_max) {
            current_max = a[i];
        }
        suffix_max[i] = current_max;
        if (distinct_count == len_from_end && current_max == len_from_end) {
            suffix_is_perm[len_from_end] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

