    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        if (current_sum == 2 * current_xor_sum) {
            std::cout << 0 << "\n\n";
        } else {
            // We need to append elements b1, b2, ... such that
            // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))

            // Strategy: Append two elements.
            // Let the two elements be X and Y.
            // New sum: S' = current_sum + X + Y
            // New XOR sum: X' = current_xor_sum ^ X ^ Y
            // We want S' = 2 * X'

            // Let's try to make X' equal to current_xor_sum.
            // This means X ^ Y should be 0, so X = Y.
            // If we append X and X, then X' = current_xor_sum ^ X ^ X = current_xor_sum.
            // The condition becomes: current_sum + X + X = 2 * current_xor_sum
            // current_sum + 2*X = 2 * current_xor_sum
            // 2*X = 2 * current_xor_sum - current_sum
            // X = current_xor_sum - current_sum / 2
            // This requires (2 * current_xor_sum - current_sum) to be non-negative and even.
            // This is not guaranteed.

            // Let's try to make X' equal to current_xor_sum.
            // This means we need to append elements whose XOR sum is 0.
            // The simplest way is to append two identical elements, say P and P.
            // Then the new XOR sum is current_xor_sum ^ P ^ P = current_xor_sum.
            // The new sum is current_sum + P + P.
            // We need current_sum + 2P = 2 * current_xor_sum.
            // 2P = 2 * current_xor_sum - current_sum.
            // This implies P = current_xor_sum - current_sum / 2.
            // This P must be non-negative.
            // Also, (2 * current_xor_sum - current_sum) must be an even number.
            // The parity of (2 * current_xor_sum - current_sum) is the parity of (-current_sum).
            // The parity of (2 * current_xor_sum - current_sum) is the parity of current_sum.
            // If current_sum is odd, then (2 * current_xor_sum - current_sum) is odd, so P cannot be an integer.
            // This strategy works only if current_sum is even.

            // A more general strategy:
            // Append two elements: current_xor_sum and current_sum + current_xor_sum.
            // Let b1 = current_xor_sum.
            // Let b2 = current_sum + current_xor_sum.
            // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
            //                 = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
            //                 = 0 ^ (current_sum + current_xor_sum)
            //                 = current_sum + current_xor_sum
            // New sum: S' = current_sum + b1 + b2
            //              = current_sum + current_xor_sum + (current_sum + current_xor_sum)
            //              = 2 * current_sum + 2 * current_xor_sum
            // We need S' = 2 * X'.
            // So, 2 * current_sum + 2 * current_xor_sum = 2 * (current_sum + current_xor_sum).
            // This is always true!
            // The elements to append are current_xor_sum and current_sum + current_xor_sum.
            // Both are non-negative since current_sum and current_xor_sum are non-negative.
            // current_xor_sum can be up to 2^60 (approx 10^18) if current_sum is large.
            // current_sum can be up to 10^5 * 10^9 = 10^14.
            // current_xor_sum can be up to 2^30 (approx 10^9).
            // So current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.

            std::cout << 2 << "\n";
            std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
        }
    }
    return 0;
}

