    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;

    // Find prime factors of q
    long long temp_q = q;
    std::vector<long long> prime_factors_q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    for (long long factor_q : prime_factors_q) {
        long long current_p = p;
        while (current_p % factor_q == 0) {
            current_p /= factor_q;
        }
        // Now current_p is p with all occurrences of factor_q removed.
        // This current_p is a divisor of original p.
        // Is current_p divisible by q?
        // If current_p is not divisible by q, then it's a candidate for max_x.
        // If current_p is still divisible by q, it means q has other prime factors
        // that are still present in current_p.
        // However, we are looking for the largest x such that x % q != 0.
        // The strategy is to remove just enough factors from p to make it not divisible by q.
        // For each prime factor `f` of `q`, we can try to remove all occurrences of `f` from `p`.
        // Let `p_prime = p / f^k` where `f^k` is the highest power of `f` that divides `p`.
        // This `p_prime` is a divisor of `p`.
        // If `p_prime` is not divisible by `q`, then `p_prime` is a candidate for `max_x`.
        // We want the largest such `p_prime`.

        // Let's refine:
        // For each prime factor `f` of `q`:
        // Calculate `p_candidate = p`.
        // While `p_candidate` is divisible by `q` AND `p_candidate` is divisible by `f`:
        //   `p_candidate /= f`.
        // If `p_candidate` is not divisible by `q`, then `p_candidate` is a valid `x`.
        // We take the maximum of all such `p_candidate`s.

        long long p_candidate = p;
        while (p_candidate % q == 0) {
            p_candidate /= factor_q;
        }
        max_x = std::max(max_x, p_candidate);
    }

    return max_x;
}

