#include <iostream>
#include <algorithm> // For std::abs, std::max, std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: Not enough moves to reach the target
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        long long diagonal_moves_needed = abs_m;
        long long straight_moves_needed = abs_n - abs_m;

        long long remaining_moves = k - (diagonal_moves_needed + straight_moves_needed);

        // Case 2: All moves are used to reach the target efficiently
        // and remaining_moves is 0.
        if (remaining_moves == 0) {
            std::cout << k << "\n";
            continue;
        }

        // Case 3: We have remaining_moves > 0.
        // These remaining moves must be used to go back and forth.
        // Each pair of moves (e.g., (1,0) then (-1,0)) uses 2 moves
        // and results in no net change in position.
        // Each pair of moves (e.g., (1,1) then (-1,-1)) uses 2 moves
        // and results in no net change in position.
        // The parity of the coordinates (abs_n, abs_m) and k matters.

        long long ans;
        if ((abs_n % 2) == (abs_m % 2)) { // Both even or both odd
            // If abs_n and abs_m have the same parity, then (abs_n - abs_m) is even.
            // The minimum number of moves (abs_n) has the same parity as abs_n.
            // If k has the same parity as abs_n, then remaining_moves must be even.
            // We can use remaining_moves / 2 pairs of (1,0) and (-1,0) moves.
            // These are non-diagonal moves.
            // So, the number of diagonal moves is k.
            if ((k % 2) == (abs_n % 2)) {
                ans = k;
            } else {
                // If k has different parity than abs_n, then remaining_moves must be odd.
                // We need to make one move that changes parity.
                // Example: (0,0) -> (1,0) -> (0,0) -> (1,0) ...
                // If we are at (X,Y) and need to reach (N,M) in K moves.
                // If (N,M) and K have different parity, we must make an odd number of "wasted" moves.
                // The minimum number of moves to reach (N,M) is abs_n.
                // If abs_n and k have different parity, we must make at least one "wasted" move that changes parity.
                // A non-diagonal move (e.g., (1,0)) changes parity of one coordinate.
                // A diagonal move (e.g., (1,1)) changes parity of both coordinates, so (x+1, y+1) has same parity sum as (x,y).
                // The total number of moves must have the same parity as abs_n.
                // If k and abs_n have different parities, it means we need to make an odd number of "wasted" moves.
                // We can use one move to go (X,Y) -> (X+1,Y) (non-diagonal) and then (X+1,Y) -> (X,Y) (non-diagonal).
                // This uses 2 moves, but we need to adjust for parity.
                // If k and abs_n have different parities, we must use at least one non-diagonal move that is not cancelled out.
                // This means we lose 1 diagonal move for the parity adjustment.
                // And then we lose another diagonal move because we use a non-diagonal move.
                // So, k - 2 diagonal moves.
                ans = k - 2;
            }
        } else { // One even, one odd (abs_n % 2 != abs_m % 2)
            // If abs_n and abs_m have different parities, then (abs_n - abs_m) is odd.
            // The minimum number of moves (abs_n) has the same parity as abs_n.
            // If k has the same parity as abs_n, then remaining_moves must be even.
            // We can use remaining_moves / 2 pairs of (1,0) and (-1,0) moves.
            // These are non-diagonal moves.
            // So, the number of diagonal moves is k.
            if ((k % 2) == (abs_n % 2)) {
                ans = k;
            } else {
                // If k has different parity than abs_n, then remaining_moves must be odd.
                // This is impossible.
                // The parity of the sum of coordinates (x+y) changes with each move.
                // A diagonal move changes x by +/-1 and y by +/-1. So (x+y) changes by +/-2 or 0. Parity of (x+y) remains same.
                // A straight move changes x by +/-1 or y by +/-1. So (x+y) changes by +/-1. Parity of (x+y) flips.
                // Starting at (0,0), sum is 0 (even).
                // After K moves, we are at (N,M). Sum is (N+M).
                // If K is even, we must have made an even number of straight moves. So (N+M) must be even.
                // If K is odd, we must have made an odd number of straight moves. So (N+M) must be odd.
                // In other words, K and (N+M) must have the same parity.
                // Here, (abs_n % 2 != abs_m % 2) means (abs_n + abs_m) is odd.
                // If k is even, and (abs_n + abs_m) is odd, then it's impossible.
                // If k is odd, and (abs_n + abs_m) is odd, then it's possible.
                // The condition (k % 2) != (abs_n % 2) implies (k % 2) != ((abs_n + abs_m) % 2) because (abs_n % 2) != (abs_m % 2).
                // So, if (abs_n % 2 != abs_m % 2) and (k % 2 != abs_n % 2), it means k and (abs_n + abs_m) have different parities.
                // This is impossible.
                std::cout << -1 << "\n";
                continue;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>

long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long modInverse(long long n) {
    return power(n, 1000000007 - 2);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // If b=1, sum_r = 0.
    long long sum_r = 0;
    if (b > 1) {
        sum_r = (b - 1);
        sum_r = (sum_r * b) % MOD;
        sum_r = (sum_r * modInverse(2)) % MOD;
    }

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // sum_k_term = b * sum_{k=1 to a} k + a
    // sum_k_term = b * (a * (a+1) / 2) + a
    long long sum_k_term = (a * (a + 1)) % MOD;
    sum_k_term = (sum_k_term * modInverse(2)) % MOD;
    sum_k_term = (sum_k_term * b) % MOD;
    sum_k_term = (sum_k_term + a) % MOD;

    long long total_sum = (sum_r * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

