    if (n == 1) {
        std::cout << h[0] << std::endl;
        return 0;
    }

    std::vector<long long> left_max_dist(n);
    left_max_dist[0] = 1;
    for (int i = 1; i < n; ++i) {
        left_max_dist[i] = std::min(h[i], left_max_dist[i - 1] + 1);
    }

    std::vector<long long> right_max_dist(n);
    right_max_dist[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        right_max_dist[i] = std::min(h[i], right_max_dist[i + 1] + 1);
    }

    long long max_k = 0;
    for (int i = 0; i < n; ++i) {
        max_k = std::max(max_k, std::min(left_max_dist[i], right_max_dist[i]));
    }

    std::cout << max_k << std::endl;

    return 0;
}

