        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Initially no vertices are active

    // Process vertices in reverse order of removal
    // This means we are adding vertices one by one to an empty graph
    // and calculating APSP sum for the current active set.
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added in this step

        active[k] = true; // Mark vertex k as active

        // Floyd-Warshall update: consider paths through k
        // d[i][j] = min(d[i][j], d[i][k] + d[k][j])
