        // For any pair of *already active* vertices `i` and `j`:
        //   `dist[i][j]` might improve via `i -> k -> j`.
        //   `dist[i][k]` might improve via `i -> j -> k`.
        //   `dist[k][j]` might improve via `k -> i -> j`.
        //
        // The order of loops matters for Floyd-Warshall.
        // The standard Floyd-Warshall algorithm iterates `k` (intermediate) as the outermost loop.
        // This means that after `k` is processed, `dist[i][j]` contains the shortest path
        // using only intermediate vertices from `0` to `k`.
        //
        // In our reverse process, `x[n-1]` is the first vertex added (let's call it `k_0`).
        // Then `x[n-2]` is added (let's call it `k_1`).
        //
        // When `k` is added:
        // 1. Update all `dist[i][k]` and `dist[k][j]` using other active vertices `p`.
        //    This means `dist[i][k] = min(dist[i][k], dist[i][p] + dist[p][k])`
        //    and `dist[k][j] = min(dist[k][j], dist[k][p] + dist[p][j])`.
        //    This ensures that paths *to* or *from* `k` are shortest using existing active nodes.
        // 2. Update all `dist[i][j]` using `k` as an intermediate.
        //    This means `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`.
        //
        // The correct set of loops for adding vertex `k` is:
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                // Update paths involving k as an endpoint
                // Path i -> j -> k
                if (dist[i][j] + dist[j][k] < dist[i][k]) {
                    dist[i][k] = dist[i][j] + dist[j][k];
                }
                // Path k -> j -> i
                if (dist[k][j] + dist[j][i] < dist[k][i]) {
                    dist[k][i] = dist[k][j] + dist[j][i];
                }
            }
        }
        // After the above, dist[i][k] and dist[k][i] are shortest paths
        // using only previously active vertices as intermediates.
        // Now, update all paths i -> j using k as an intermediate.
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                // Path i -> k -> j
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }


        // Calculate sum of shortest paths for currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Output results in the correct order (reverse of how they were collected)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

