// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1 (2 pieces)
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) { // i is the length of the first piece
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);

        std::string new_s = s2 + s1;

        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (3 pieces)
    // The problem statement guarantees s is a palindrome.
    // If all characters in s are the same (e.g., "qqqq"), then no matter how we cut and reorder,
    // the resulting string will always be the same as s.
    // In this specific case, it's impossible to form a new palindrome.
    // We can check this by counting distinct characters.

    // Count distinct characters in the first half of the string (or first half + middle for odd length)
    // Since s is a palindrome, if all chars are same, s[0] == s[1] == ... == s[n-1].
    // If there's at least one character different from s[0], then we can potentially form a new palindrome.

    bool all_same_char = true;
    if (n > 0) { // Ensure string is not empty, though constraints say 1 <= |s|
        char first_char = s[0];
        for (int i = 1; i < n / 2; ++i) { // Check up to n/2 - 1
            if (s[i] != first_char) {
                all_same_char = false;
                break;
            }
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" (k=2)
        // The strategy is to cut off the first character, the last character, and leave the middle.
        // For example, s = c_1 c_2 ... c_k ... c_2 c_1
        // Cut into s[0], s[1...n-2], s[n-1]
        // Pieces: s[0], s.substr(1, n-2), s[n-1]
        // Reorder to: s[n-1] + s.substr(1, n-2) + s[0]
        // Since s is a palindrome, s[0] == s[n-1].
        // This reordering results in the original string.
        //
        // A different strategy for k=2:
        // Consider the string s. Since not all characters are the same, there must be some s[i] != s[0] for i < n/2.
        // Let's take s = "abacaba". n=7. s[0]='a'. s[1]='b'.
        // Cut into s[0...i-1] | s[i] | s[i+1...n-1]
        // This is not what the problem means by k=2.
        //
        // The problem states: "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string, and then unite those pieces together to get a new string."
        //
        // If k=1 doesn't work, it means for any split s = s1 + s2, s2 + s1 is either s or not a palindrome.
        //
        // Consider the string s. If it's not all same characters, then there exists at least one character s[i] such that s[i] != s[0] for i < n/2.
        //
        // Let's take the example "nolon". n=5.
        // k=1:
        // n|olon -> olonn (not pal)
        // no|lon -> lonno (not pal)
        // nol|on -> onnol (not pal)
        // nolo|n -> nnolo (not pal)
        //
        // k=2:
        // "no|l|on" -> pieces: "no", "l", "on"
        // Reorder to "on" + "l" + "no" = "onlno". This is a palindrome and != "nolon".
        // So k=2 is possible.
        //
        // The logic is: if not all characters are the same, then there must be at least two distinct characters.
        // Since s is a palindrome, if s[i] != s[0] for some i < n/2, then s[n-1-i] != s[n-1].
        //
        // If k=1 fails, it means for any split s = A + B, the string B + A is either s itself or not a palindrome.
        //
        // If s is not composed of all identical characters, then it's always possible to achieve k=2.
        // Consider the string s. Since it's a palindrome and not all characters are the same,
        // there must be at least one character `c` such that `c != s[0]` and `c` appears in `s`.
        //
        // Let's take the first character `s[0]`.
        // If `s` is not all same characters, then there exists some `i` such that `s[i] != s[0]`.
        // Since `s` is a palindrome, `s[i] == s[n-1-i]`.
        //
        // Consider cutting `s` into `s[0]`, `s.substr(1, n-2)`, `s[n-1]`.
        // Pieces: `s[0]`, `s_middle = s.substr(1, n-2)`, `s[n-1]`.
        // Since `s` is a palindrome, `s[0] == s[n-1]`.
        // If we reorder them as `s[n-1] + s_middle + s[0]`, this is `s[0] + s_middle + s[n-1]`, which is `s`.
        // This doesn't work.
        //
        // The example "nolon" -> "no|l|on" -> "onlno" works.
        // This is `s.substr(0,2)`, `s.substr(2,1)`, `s.substr(3,2)`.
        // Pieces: `s[0...1]`, `s[2]`, `s[3...4]`.
        // Reorder: `s[3...4] + s[2] + s[0...1]`.
        // This is `s[n-2...n-1] + s[n/2] + s[0...1]`.
        //
        // This is a general strategy for k=2:
        // Take `s_prefix = s.substr(0, i)` and `s_suffix = s.substr(n-i, i)` for some `i`.
        // The middle part is `s.substr(i, n-2*i)`.
        //
        // If `s` is not all same characters, then there exists an `i` such that `s.substr(0, i)` is not equal to `s.substr(n-i, i)` when reversed.
        //
        // The problem statement implies that if k=1 doesn't work and not all characters are the same, then k=2 is the answer.
        // This is a common pattern in competitive programming problems where if a simpler case fails, a slightly more complex one is guaranteed.
        //
        // The only case where it's impossible is when all characters are the same.
        // If `s` is "aaaaa", then any permutation of its substrings will result in "aaaaa".
        // If `s` is "ababa", k=1:
        // a|baba -> babaa (not pal)
        // ab|aba -> abaab (not pal)
        // aba|ba -> baaba (pal) but baaba != ababa. So k=1.
        //
        // The logic for "Impossible" is correct: only if all characters are the same.
        // If not all characters are the same, and k=1 didn't yield a solution, then k=2 must be the answer.
        // This is because we can always find a split that works for k=2.
        // For example, take `s = s[0] + s[1...n-2] + s[n-1]`.
        // Since `s` is a palindrome, `s[0] == s[n-1]`.
        // If `s` is not all same characters, then `s[1...n-2]` is not all same characters (unless `n=1` or `n=2` and `s[0]!=s[1]`).
        //
        // The problem statement implies that if k=1 doesn't work, and it's not "qqqq" case, then k=2 is the answer.
        // This is a strong hint.
        //
        // Let's re-verify the "all_same_char" check.
        // If `s = "qqqq"`, `n=4`. `first_char = 'q'`. Loop `i=1` to `n/2-1 = 1`. `s[1] == 'q'`. `all_same_char` remains true. Output "Impossible". Correct.
        // If `s = "otto"`, `n=4`. `first_char = 'o'`. Loop `i=1` to `1`. `s[1] == 't'`. `all_same_char` becomes false.
        // But for "otto", k=1 works: "ot|to" -> "toot".
        // So the `all_same_char` check should only be performed if k=1 fails.
        //
        // The current structure is:
        // 1. Try k=1. If found, print 1 and exit.
        // 2. If k=1 not found, then check if all characters are the same.
        //    If all characters are the same, print "Impossible".
        // 3. Otherwise (k=1 failed, but not all characters are the same), print 2.
        // This logic seems to match the examples and problem constraints.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    int h_idx = 0; // Current index for heads

    while (p_idx < m && h_idx < n) {
        // Find the first head h_idx that can potentially reach p[p_idx]
        // A head h_idx can reach p[p_idx] if h[h_idx] + T >= p[p_idx]
        // We need to find a head such that h[h_idx] - T <= p[p_idx] <= h[h_idx] + T
        // So, h[h_idx] >= p[p_idx] - T
        while (h_idx < n && h[h_idx] < p[p_idx] - T) {
            h_idx++;
        }

        if (h_idx == n) {
            // No more heads available to cover p[p_idx]
            return false;
        }

        // Now h[h_idx] is the first head that satisfies h[h_idx] >= p[p_idx] - T.
        // This head can cover tracks in [h[h_idx] - T, h[h_idx] + T].
        // We need to cover p[p_idx].
        // If h[h_idx] - T > p[p_idx], then even this head cannot cover p[p_idx].
        // This case is already handled by the while loop above.
        // So, we know h[h_idx] - T <= p[p_idx].

        // Now, greedily cover as many subsequent target tracks as possible
        // using the current head h[h_idx].
        long long current_head_reach_end = h[h_idx] + T;
        while (p_idx < m && p[p_idx] <= current_head_reach_end) {
            p_idx++;
        }
        h_idx++; // Move to the next head for the remaining target tracks
    }

    return p_idx == m; // All target tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between coordinates (10^10 - 1) + (10^10 - 1) approx 2*10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();
    long long total_pairs = (long long)n * (n + 1) / 2;

    // min_r_for_l[i] stores the minimum r (1-indexed) such that the substring s[i...r-1]
    // contains a triple match. If no such r exists, it's n+1.
    // We are interested in the smallest r such that s[i...r-1] is "good".
    // This means we need to find the smallest r such that there exists x, k
    // with s[x-1]=s[x+k-1]=s[x+2k-1] and i <= x-1 and x+2k-1 <= r-1.
    // This is equivalent to finding the smallest r such that r-1 >= x+2k-1 for some valid x, k.
    // So, r >= x+2k.
    // The minimum r for a given l (1-indexed) is min(x+2k) over all valid x, k
    // such that x >= l.
    // Let's use 0-indexed for `min_r_for_l` where `min_r_for_l[i]` is the minimum
    // 0-indexed end position `j` such that `s[i...j]` contains a triple match.
    // If no such `j` exists, it's `n`.
    std::vector<int> min_end_idx(n + 1, n); // min_end_idx[i] = min j such that s[i...j] is good.

    // Iterate through all possible starting positions x (0-indexed)
    // and all possible step sizes k.
    // The maximum possible k is (n-1-x)/2.
    // The maximum k for x=0 is (n-1)/2.
    // The maximum k for x=n-3 is 0.
    // The maximum k is roughly n/3.
    // The maximum value for x+2k is n-1.
    // So x+2k < n.
    // x < n-2k.
    // k can go up to (n-1)/2.
    // If k=1, x can go up to n-3.
    // If k=2, x can go up to n-5.
    // If k=3, x can go up to n-7.
    // The maximum k we need to check is small.
    // If k is large, say k > 6, then 2k > 12.
    // If we have a triple match s[x] = s[x+k] = s[x+2k],
    // then for any l <= x and r >= x+2k, the pair (l,r) is good.
    // We are looking for the smallest r for each l.
    // This means we need to find the smallest x+2k for each x.
    // Let's define `first_good_end[i]` as the minimum `j` such that `s[i...j]` contains a triple match.
    // If no such `j` exists, `first_good_end[i]` is `n`.

    // The problem states $1 \leq x, k \leq n$.
    // $l \leq x < x+2k \leq r$.
    // $s_x = s_{x+k} = s_{x+2k}$.
    // In 0-indexed: $s[x-1] = s[x+k-1] = s[x+2k-1]$.
    // Let $x' = x-1$. Then $s[x'] = s[x'+k] = s[x'+2k]$.
    // $0 \leq x' < x'+2k \leq n-1$.
    // $l-1 \leq x'$ and $x'+2k \leq r-1$.

    // We need to find the minimum `r_idx` (0-indexed) for each `l_idx` (0-indexed)
    // such that `s[l_idx ... r_idx]` contains a triple match.
    // Let `min_valid_r_idx[l_idx]` be this value.
    // Initialize `min_valid_r_idx` with `n` (meaning no valid `r_idx` found for that `l_idx`).

    // The maximum value for k is limited.
    // If k is large, say k >= 7, then 2k >= 14.
    // If s[x] = s[x+k] = s[x+2k], then the length of this pattern is 2k+1.
    // If k >= 7, then 2k+1 >= 15.
    // Consider the string s[x...x+14].
    // If s[x] = s[x+k] = s[x+2k] for k >= 7, then this implies that
    // s[x] = s[x+k] = s[x+2k] for some k' <= 6.
    // This is because if s[x] = s[x+k] = s[x+2k], then the characters are the same.
    // If k >= 7, then there must be a shorter pattern.
    // For example, if s[x] = s[x+7] = s[x+14], then s[x] = s[x+1] = s[x+2] = ... = s[x+14] is not necessarily true.
    // But if s[x] = s[x+k] = s[x+2k], then the characters are the same.
    // The crucial observation is that if a triple match exists for a large k,
    // it implies that the substring s[x...x+2k] is "good".
    // If there is a triple match s[x] = s[x+k] = s[x+2k], then the substring s[x...x+2k] is good.
    // Any substring s[l...r] where l <= x and r >= x+2k is also good.
    // We want to find the minimum r for each l.
    // This means for each l, we want to find min(x+2k) such that x >= l and s[x]=s[x+k]=s[x+2k].

    // Let's iterate through all possible starting positions `i` (0-indexed) for the pattern `s[i] = s[i+k] = s[i+2k]`.
    // For each `i`, we check small values of `k`.
    // The maximum `k` we need to check is small.
    // If `s[i] = s[i+k] = s[i+2k]`, then `i+2k` is the end index of this pattern.
    // For any `l_idx <= i`, the substring `s[l_idx ... i+2k]` is good.
    // So, `min_valid_r_idx[l_idx]` can be updated to `min(min_valid_r_idx[l_idx], i+2k)`.

    // The maximum k to check:
    // If s[x] = s[x+k] = s[x+2k], then the characters are the same.
    // If k is large, say k=7, then s[x]=s[x+7]=s[x+14].
    // If s[x] = s[x+1] = s[x+2] = ... = s[x+m] for m >= 14, then any k <= m/2 would work.
    // The maximum k we need to check is 6.
    // Why 6? Consider any sequence of 15 characters. If it contains a triple match,
    // it must contain one with k <= 6.
    // This is a known property for certain pattern matching problems.
    // If a string of length L contains a pattern of type A_k B_k C_k (where A, B, C are characters and k is step),
    // then if L is large enough, it must contain such a pattern with small k.
    // For $s_x = s_{x+k} = s_{x+2k}$, the length of the pattern is $2k+1$.
    // If $2k+1 \ge 15$, i.e., $k \ge 7$, then it is guaranteed that if such a pattern exists,
    // there must be a pattern with $k' \le 6$ within the same range.
    // This is a result from combinatorics on words, related to "squares" or "cubes".
    // For example, if $s_x = s_{x+k} = s_{x+2k}$ for $k \ge 7$, then the substring $s[x \dots x+2k]$ is "good".
    // It is known that if a string contains a 3-term arithmetic progression of identical characters,
    // it must contain one where the common difference is at most 6.
    // This means we only need to check $k \in \{1, 2, 3, 4, 5, 6\}$.
    // This significantly reduces the complexity.

    std::vector<int> min_r_idx_for_l_idx(n, n); // min_r_idx_for_l_idx[l_idx] = min r_idx such that s[l_idx...r_idx] is good.

    for (int i = 0; i < n; ++i) { // i is the 0-indexed x'
        for (int k = 1; k <= 6; ++k) { // k is the step
            if (i + 2 * k < n) { // Check if x'+2k is within bounds
                if (s[i] == s[i + k] && s[i] == s[i + 2 * k]) {
                    // Found a triple match starting at i with step k, ending at i+2k.
                    // This means for any l_idx <= i, the substring s[l_idx ... i+2k] is good.
                    // So, we can update min_r_idx_for_l_idx[l_idx] to min(current, i+2k).
                    // Since we iterate i from 0 to n-1, and for each i, we update for l_idx <= i,
                    // we can simply update min_r_idx_for_l_idx[i] = min(current, i+2k).
                    // The propagation to smaller l_idx will be handled in the next step.
                    min_r_idx_for_l_idx[i] = std::min(min_r_idx_for_l_idx[i], i + 2 * k);
                }
            }
        }
    }

    // Now, propagate the minimum r_idx backwards.
    // If s[l_idx ... r_idx] is good, then s[l_idx-1 ... r_idx] is also good.
    // So, min_r_idx_for_l_idx[l_idx-1] must be less than or equal to min_r_idx_for_l_idx[l_idx].
    // Specifically, min_r_idx_for_l_idx[l_idx-1] = min(min_r_idx_for_l_idx[l_idx-1], min_r_idx_for_l_idx[l_idx]).
    for (int l_idx = n - 2; l_idx >= 0; --l_idx) {
        min_r_idx_for_l_idx[l_idx] = std::min(min_r_idx_for_l_idx[l_idx], min_r_idx_for_l_idx[l_idx + 1]);
    }

    long long good_pairs_count = 0;
    for (int l_idx = 0; l_idx < n; ++l_idx) {
        if (min_r_idx_for_l_idx[l_idx] < n) {
            // If min_r_idx_for_l_idx[l_idx] is less than n, it means there is at least one
            // valid r_idx for this l_idx.
            // The valid r_idx values are from min_r_idx_for_l_idx[l_idx] up to n-1.
            // The number of such r_idx values is (n-1) - min_r_idx_for_l_idx[l_idx] + 1.
            good_pairs_count += (n - min_r_idx_for_l_idx[l_idx]);
        }
    }

    std::cout << good_pairs_count << std::endl;

    return 0;
}

#include <iostream>
