int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, subsequent values will be current_val + d

    // Iterate from largest possible power of 2 down to 1
    // The maximum possible power of 2 for X up to 10^9 is around 2^29 (since 2^30 > 10^9)
    // So we can iterate from i=29 down to 0.
    // For each i, 2^i represents a block of 2^i - 1 subsequences.
    // We want to find how many times we can subtract 2^i - 1 from X.
    // This is equivalent to finding the binary representation of X+1, but with a slight twist.
