int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total possible substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If m ones are placed to maximize f(s), they should be spread out
        // as evenly as possible to minimize consecutive blocks of zeros.
        // This creates m+1 blocks of zeros (some of which might be empty).
        // Let k be the number of zeros in each of the smaller blocks.
        // Let k+1 be the number of zeros in each of the larger blocks.
        // There will be (m+1) blocks of zeros in total.
        // The number of larger blocks (with k+1 zeros) is num_zeros % (m+1).
        // The number of smaller blocks (with k zeros) is (m+1) - (num_zeros % (m+1)).

        long long num_larger_blocks = num_zeros % (m + 1);
        long long num_smaller_blocks = (m + 1) - num_larger_blocks;

        long long k = num_zeros / (m + 1); // Size of smaller blocks

        // Calculate substrings of all zeros from smaller blocks
        long long zeros_from_smaller_blocks = num_smaller_blocks * k * (k + 1) / 2;

        // Calculate substrings of all zeros from larger blocks
        long long zeros_from_larger_blocks = num_larger_blocks * (k + 1) * (k + 2) / 2;

        long long total_zero_substrings = zeros_from_smaller_blocks + zeros_from_larger_blocks;

        long long max_f_s = total_substrings - total_zero_substrings;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

