        } else if (c == 'o') {
            count_o++;
        }
    }

    // To form "one": needs 'o', 'n', 'e'
    // To form "zero": needs 'z', 'e', 'r', 'o'

    // Prioritize '1's to make the number as large as possible.
    // The number of '1's is limited by the minimum count of 'o', 'n', 'e'.
    int num_ones = count_n; // 'n' is only used by "one"

    // After forming 'num_ones' "one"s, update counts for 'o' and 'e'.
    // 'o' and 'e' are shared with "zero".
    // 'z' and 'r' are only used by "zero".

    // The number of '0's is limited by the minimum count of 'z', 'e', 'r', 'o'.
    // However, 'e' and 'o' might have been used by '1's.
    // Since we want to maximize the number, we should put all '1's first, then all '0's.
    // This means we should form as many '1's as possible, then as many '0's as possible from the remaining letters.

    // The number of '1's is directly limited by 'n'.
    // Each 'n' corresponds to one '1'.
    // So, num_ones = count_n.

    // The number of '0's is directly limited by 'z'.
    // Each 'z' corresponds to one '0'.
    // So, num_zeros = count_z.

    // This simplified logic works because 'n' is unique to "one" and 'z' is unique to "zero".
    // The other letters ('e', 'r', 'o') are either unique to "zero" ('r') or shared ('e', 'o').
    // If we have `k` 'n's, we can form `k` "one"s. This uses `k` 'o's and `k` 'e's.
    // If we have `m` 'z's, we can form `m` "zero"s. This uses `m` 'e's, `m` 'r's, and `m` 'o's.
    // The problem guarantees that it's possible to form a sequence of "zero" and "one".
    // This implies that the counts of 'e' and 'o' will always be sufficient for the number of 'n's and 'z's available.
    // For example, if we have 2 'n's and 1 'z', we need 2 'o's, 2 'e's for "oneone" and 1 'o', 1 'e', 1 'r' for "zero".
    // Total needed: 3 'o's, 3 'e's, 1 'n', 1 'z', 1 'r'.
    // The problem statement guarantees that the input string will have enough letters to form some combination of "zero" and "one".
    // The maximum number is achieved by printing all '1's first, then all '0's.

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
