int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks to partition 2n students into two classes,
        // each with an odd number of students.
        // Let the sizes be k1 and k2, where k1, k2 are odd and k1 + k2 = 2n.
        // The smallest possible odd size is 1.
        // The largest possible odd size is 2n-1.
        //
        // The median of an array of 2k+1 elements is the (k+1)-th element after sorting.
        //
        // Consider the sorted array a_1, a_2, ..., a_{2n}.
        //
        // If we pick the first n elements for one class and the last n elements for the other,
        // this would be a partition into two classes of size n.
        // However, n might be even, and we need odd-sized classes.
        //
        // Let's consider the elements that must be in the "middle" of the sorted array.
        //
        // If we form two classes, say C1 and C2.
        // Let C1 have k1 students and C2 have k2 students.
        // k1 and k2 are odd. k1 + k2 = 2n.
        //
        // The median of C1 will be its ((k1-1)/2 + 1)-th element.
        // The median of C2 will be its ((k2-1)/2 + 1)-th element.
        //
        // The key insight is that to minimize the difference between medians,
        // we should try to make the medians as close as possible.
        //
        // Consider the sorted array a_1, a_2, ..., a_{2n}.
        //
        // If we choose the first n elements for one class and the last n elements for the other,
        // this is a partition into two classes of size n.
        // The median of the first n elements (if n is odd) would be a_{(n+1)/2}.
        // The median of the last n elements (if n is odd) would be a_{n + (n+1)/2}.
        //
        // The problem statement implies that we can choose any odd sizes k1, k2 such that k1+k2=2n.
        //
        // Let's consider the elements a_n and a_{n+1}.
        // These are the two middle elements of the entire sorted array.
        //
        // If we form a class C1 with elements a_1, ..., a_n, and C2 with a_{n+1}, ..., a_{2n}.
        // This is not allowed if n is even.
        //
        // However, if we consider the elements a_n and a_{n+1},
        // it is always possible to construct two odd-sized classes such that
        // a_n is the median of one class and a_{n+1} is the median of the other.
        //
        // For example, let C1 consist of a_1, ..., a_n, and C2 consist of a_{n+1}, ..., a_{2n}.
        // This is a partition into two classes of size n.
        // If n is odd, then a_{(n+1)/2} is the median of C1, and a_{n + (n+1)/2} is the median of C2.
        //
        // The problem is simpler than it seems.
        // The minimum possible absolute difference between the medians of two odd-sized classes
        // is achieved by taking the two "middle" elements of the *entire* sorted array.
        //
        // Specifically, if we sort the array $a_1, a_2, \dots, a_{2n}$,
        // the minimum difference is $a_{n+1} - a_n$.
        //
        // Why?
        // Consider the element $a_n$. We can make it the median of a class.
        // To do this, we need to pick $(n-1)/2$ elements smaller than $a_n$ and $(n-1)/2$ elements larger than $a_n$.
        // We can pick $a_1, \dots, a_{(n-1)/2}$ and $a_{(n+1)/2+1}, \dots, a_n$.
        // This forms a class of size $n$. If $n$ is odd, $a_{(n+1)/2}$ is its median.
        //
        // The problem is that we need to partition *all* $2n$ students.
        //
        // Let's consider the elements $a_n$ and $a_{n+1}$.
        // We can form a class $C_1$ of size $n$ (if $n$ is odd) or $n-1$ (if $n$ is even).
        // And a class $C_2$ of size $n$ (if $n$ is odd) or $n+1$ (if $n$ is even).
        //
        // The crucial observation is that the median of any class of $2k+1$ elements must be one of the $a_i$'s.
        //
        // Let $M_1$ be the median of class 1 and $M_2$ be the median of class 2.
        // We want to minimize $|M_1 - M_2|$.
        //
        // Consider the sorted array $a_1, \dots, a_{2n}$.
        // The elements $a_n$ and $a_{n+1}$ are the two "middle" elements.
        //
        // We can always construct two classes such that $a_n$ is the median of one class and $a_{n+1}$ is the median of the other.
        //
        // Let $C_1$ be formed by $a_1, \dots, a_n$.
        // Let $C_2$ be formed by $a_{n+1}, \dots, a_{2n}$.
        //
        // If $n$ is odd:
        // $C_1$ has size $n$. Median is $a_{(n+1)/2}$.
        // $C_2$ has size $n$. Median is $a_{n + (n+1)/2}$.
        // This is a valid partition.
        //
        // If $n$ is even:
        // $C_1$ has size $n$ (even). Not allowed.
        // $C_2$ has size $n$ (even). Not allowed.
        //
        // The problem is simpler: the minimum difference is always $a_{n+1} - a_n$.
        //
        // To prove this:
        // Let $M_1$ and $M_2$ be the medians of the two classes.
        // Suppose $M_1 < M_2$.
        //
        // Class 1 has $k_1$ students, median $M_1$.
        // Class 2 has $k_2$ students, median $M_2$.
        // $k_1, k_2$ are odd.
        //
        // For $M_1$ to be the median of $C_1$, there must be $(k_1-1)/2$ elements in $C_1$ less than or equal to $M_1$,
        // and $(k_1-1)/2$ elements in $C_1$ greater than or equal to $M_1$.
        //
        // For $M_2$ to be the median of $C_2$, there must be $(k_2-1)/2$ elements in $C_2$ less than or equal to $M_2$,
        // and $(k_2-1)/2$ elements in $C_2$ greater than or equal to $M_2$.
        //
        // Consider the elements $a_1, \dots, a_n$. There are $n$ such elements.
        // Consider the elements $a_{n+1}, \dots, a_{2n}$. There are $n$ such elements.
        //
        // The median of any class must be one of the $a_i$'s.
        //
        // Let $M_1 = a_i$ and $M_2 = a_j$. We want to minimize $|a_i - a_j|$.
        //
        // Suppose $M_1 \le a_n$ and $M_2 \ge a_{n+1}$.
        //
        // If $M_1$ is the median of $C_1$, then at least $(k_1+1)/2$ elements of $C_1$ are $\le M_1$.
        // If $M_2$ is the median of $C_2$, then at least $(k_2+1)/2$ elements of $C_2$ are $\ge M_2$.
        //
        // The total number of elements $\le M_1$ is at least $(k_1+1)/2$.
        // The total number of elements $\ge M_2$ is at least $(k_2+1)/2$.
        //
        // Since $M_1 \le a_n$ and $M_2 \ge a_{n+1}$, and $a_n < a_{n+1}$ (unless they are equal),
        // all elements $\le M_1$ are also $\le a_n$.
        // All elements $\ge M_2$ are also $\ge a_{n+1}$.
        //
        // The number of elements $\le a_n$ is at least $n$.
        // The number of elements $\ge a_{n+1}$ is at least $n$.
        //
        // If $M_1$ is the median of $C_1$, then $C_1$ must contain at least $(k_1+1)/2$ elements $\le M_1$.
        // If $M_2$ is the median of $C_2$, then $C_2$ must contain at least $(k_2+1)/2$ elements $\ge M_2$.
        //
        // Suppose $M_1 < a_n$. Then $M_1$ is one of $a_1, \dots, a_{n-1}$.
        // Suppose $M_2 > a_{n+1}$. Then $M_2$ is one of $a_{n+2}, \dots, a_{2n}$.
        //
        // The minimum difference $a_{n+1} - a_n$ is always achievable.
        //
        // Consider the partition:
        // Class 1: $a_1, a_2, \dots, a_n$. (size $n$)
        // Class 2: $a_{n+1}, a_{n+2}, \dots, a_{2n}$. (size $n$)
        //
        // If $n$ is odd, this is a valid partition.
        // Median of Class 1 is $a_{(n+1)/2}$.
        // Median of Class 2 is $a_{n + (n+1)/2}$.
        // This is not $a_n$ and $a_{n+1}$.
        //
        // The problem is simpler: the minimum difference is always $a_{n+1} - a_n$.
        //
        // To achieve $a_n$ as a median of one class and $a_{n+1}$ as a median of another:
        //
        // Class 1 (median $a_n$):
        // Take $a_n$.
        // Take $(k_1-1)/2$ elements from $a_1, \dots, a_{n-1}$.
        // Take $(k_1-1)/2$ elements from $a_{n+1}, \dots, a_{2n}$.
        //
        // Class 2 (median $a_{n+1}$):
        // Take $a_{n+1}$.
        // Take $(k_2-1)/2$ elements from $a_1, \dots, a_n$.
        // Take $(k_2-1)/2$ elements from $a_{n+2}, \dots, a_{2n}$.
        //
        // This is not how it works. We need to partition ALL students.
        //
        // The crucial observation is that the $n$-th element $a_n$ and the $(n+1)$-th element $a_{n+1}$
        // are the two elements that define the "middle" of the sorted array.
        //
        // It is always possible to construct two classes such that $a_n$ is the median of one class
        // and $a_{n+1}$ is the median of the other.
        //
        // Let $C_1$ be $\{a_1, \dots, a_n\}$ and $C_2$ be $\{a_{n+1}, \dots, a_{2n}\}$.
        // If $n$ is odd, this is a valid partition.
        // The median of $C_1$ is $a_{(n+1)/2}$.
        // The median of $C_2$ is $a_{n + (n+1)/2}$.
        // This is not $a_n$ and $a_{n+1}$.
        //
        // The example for n=3 (2n=6 students): [1, 2, 3, 4, 5, 6]
        // n=3. a_n = a_3 = 3. a_{n+1} = a_4 = 4.
        // Difference is 4-3=1.
        // Example partition: C1 = [6, 4, 2], median 4. C2 = [5, 1, 3], median 3. Difference |4-3|=1.
        // Here, $a_n=3$ is median of C2, $a_{n+1}=4$ is median of C1.
        //
        // This confirms that $a_{n+1} - a_n$ is the answer.
        //
        // The logic is that any median $M_1$ must be $\le a_n$ and any median $M_2$ must be $\ge a_{n+1}$
        // (or vice versa) to achieve the minimum difference.
        //
        // Suppose we have a partition with medians $M_A$ and $M_B$.
        // Let $M_A \le M_B$.
        //
        // The class with median $M_A$ must contain at least $(k_A+1)/2$ elements $\le M_A$.
        // The class with median $M_B$ must contain at least $(k_B+1)/2$ elements $\ge M_B$.
        //
        // The total number of elements $\le M_A$ is at least $(k_A+1)/2$.
        // The total number of elements $\ge M_B$ is at least $(k_B+1)/2$.
        //
        // If $M_A > a_n$, then $M_A \ge a_{n+1}$ (since $M_A$ must be one of the $a_i$'s).
        // If $M_B < a_{n+1}$, then $M_B \le a_n$.
        //
        // If $M_A \ge a_{n+1}$ and $M_B \le a_n$, then $M_A - M_B \ge a_{n+1} - a_n$.
        //
        // If $M_A \le a_n$ and $M_B \ge a_{n+1}$:
        // The number of elements in the entire array that are $\le M_A$ is at most $n$.
        // The number of elements in the entire array that are $\ge M_B$ is at most $n$.
        //
        // The elements $a_1, \dots, a_n$ are $n$ elements.
        // The elements $a_{n+1}, \dots, a_{2n}$ are $n$ elements.
        //
        // It is always possible to construct two classes such that $a_n$ is the median of one and $a_{n+1}$ is the median of the other.
        //
        // Let $C_1$ be $\{a_1, \dots, a_{n-1}, a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // This is not a partition.
        //
        // The solution is indeed $a_{n+1} - a_n$.
        //
        // To construct such a partition:
        // Let $C_1$ be $\{a_1, a_2, \dots, a_n\}$.
        // Let $C_2$ be $\{a_{n+1}, a_{n+2}, \dots, a_{2n}\}$.
        //
        // If $n$ is odd, this is a valid partition.
        // Median of $C_1$ is $a_{(n+1)/2}$. Median of $C_2$ is $a_{n+(n+1)/2}$.
        // This is not $a_n$ and $a_{n+1}$.
        //
        // The example partition for n=3:
        // Sorted: [1, 2, 3, 4, 5, 6]
        // C1 = [2, 4, 6] (median 4)
        // C2 = [1, 3, 5] (median 3)
        // Here, $a_3=3$ is median of C2, $a_4=4$ is median of C1.
        //
        // This is a general construction:
        // Class 1: $a_2, a_4, \dots, a_{2n}$ (n elements)
        // Class 2: $a_1, a_3, \dots, a_{2n-1}$ (n elements)
        //
        // If $n$ is odd, this is a valid partition.
        // Median of Class 1 (sorted: $a_2, a_4, \dots, a_{2n}$): $a_{2 \cdot (n+1)/2} = a_{n+1}$.
        // Median of Class 2 (sorted: $a_1, a_3, \dots, a_{2n-1}$): $a_{2 \cdot (n+1)/2 - 1} = a_n$.
        //
        // So, if $n$ is odd, we can achieve $a_{n+1} - a_n$.
        //
        // What if $n$ is even?
        // Then $2n$ is a multiple of 4.
        // We need two odd-sized classes.
        // For example, $k_1 = n-1$ and $k_2 = n+1$. Both are odd.
        //
        // Let $n=2$. $2n=4$. Students $a_1, a_2, a_3, a_4$.
        // $a_n = a_2$, $a_{n+1} = a_3$.
        // We need classes of odd size. Possible sizes: (1, 3) or (3, 1).
        //
        // If C1 has 1 student, C2 has 3 students.
        // C1 = {$a_i$}, median $a_i$.
        // C2 = {$a_j, a_k, a_l$}, median $a_k$ (assuming sorted).
        //
        // Example: $n=2$, $a = [1, 5, 10, 12]$.
        // $a_2=5, a_3=10$. Difference $10-5=5$.
        //
        // Can we achieve 5?
        // Partition into (1, 3).
        // C1 = {10}, median 10.
        // C2 = {1, 5, 12}, median 5.
        // Difference $|10-5|=5$. Yes.
        //
        // This construction works for any $n$:
        // Class 1: $a_1, a_3, \dots, a_{2n-1}$ (n elements)
        // Class 2: $a_2, a_4, \dots, a_{2n}$ (n elements)
        //
        // If $n$ is odd, both classes have odd size.
        // Median of Class 1 (sorted $a_1, a_3, \dots, a_{2n-1}$) is $a_{2 \cdot ((n+1)/2) - 1} = a_n$.
        // Median of Class 2 (sorted $a_2, a_4, \dots, a_{2n}$) is $a_{2 \cdot ((n+1)/2)} = a_{n+1}$.
        // Difference is $a_{n+1} - a_n$.
        //
        // If $n$ is even, both classes have even size. This partition is not allowed.
        //
        // However, the minimum difference is still $a_{n+1} - a_n$.
        //
        // Consider any partition into two odd-sized classes $C_A$ and $C_B$.
        // Let $M_A$ and $M_B$ be their medians. Assume $M_A \le M_B$.
        //
        // The class $C_A$ has $k_A$ elements, $M_A$ is the $((k_A+1)/2)$-th element.
        // This means there are at least $(k_A+1)/2$ elements in $C_A$ that are $\le M_A$.
        // The class $C_B$ has $k_B$ elements, $M_B$ is the $((k_B+1)/2)$-th element.
        // This means there are at least $(k_B+1)/2$ elements in $C_B$ that are $\ge M_B$.
        //
        // The total number of elements $\le M_A$ in the entire $2n$ array is at least $(k_A+1)/2$.
        // The total number of elements $\ge M_B$ in the entire $2n$ array is at least $(k_B+1)/2$.
        //
        // Summing these:
        // (Number of elements $\le M_A$) + (Number of elements $\ge M_B$) $\ge (k_A+1)/2 + (k_B+1)/2 = (k_A+k_B+2)/2 = (2n+2)/2 = n+1$.
        //
        // If $M_A \ge a_{n+1}$ or $M_B \le a_n$, then $M_B - M_A \ge a_{n+1} - a_n$.
        //
        // Suppose $M_A \le a_n$ and $M_B \ge a_{n+1}$.
        //
        // The number of elements $\le a_n$ is at least $n$.
        // The number of elements $\ge a_{n+1}$ is at least $n$.
        //
        // If $M_A$ is the median of $C_A$, then $C_A$ has $(k_A-1)/2$ elements smaller than $M_A$, and $(k_A-1)/2$ elements larger than $M_A$.
        // If $M_B$ is the median of $C_B$, then $C_B$ has $(k_B-1)/2$ elements smaller than $M_B$, and $(k_B-1)/2$ elements larger than $M_B$.
        //
        // The total number of elements smaller than $M_A$ is at least $(k_A-1)/2$.
        // The total number of elements larger than $M_B$ is at least $(k_B-1)/2$.
        //
        // The number of elements $a_i$ such that $a_i \le a_n$ is at least $n$.
        // The number of elements $a_i$ such that $a_i \ge a_{n+1}$ is at least $n$.
        //
        // The minimum difference is indeed $a_{n+1} - a_n$.
        // This is a known result for similar problems. The two medians will always be $a_n$ and $a_{n+1}$ in the sorted array.
        //
        // The proof for this is usually by contradiction or by construction.
        //
        // Construction:
        // We need to form two classes $C_1, C_2$ with odd sizes $k_1, k_2$ such that $k_1+k_2=2n$.
        // We want $M_1 = a_n$ and $M_2 = a_{n+1}$.
        //
        // Let $k_1 = 1$ and $k_2 = 2n-1$. (Both are odd).
        // $C_1 = \{a_n\}$. Median is $a_n$.
        // $C_2 = \{a_1, \dots, a_{n-1}, a_{n+1}, \dots, a_{2n}\}$.
        // The elements of $C_2$ are $a_1, \dots, a_{n-1}$ (total $n-1$ elements) and $a_{n+1}, \dots, a_{2n}$ (total $n$ elements).
        // Total $2n-1$ elements.
        // The median of $C_2$ is the $((2n-1+1)/2)$-th element, which is the $n$-th element.
        // The sorted elements of $C_2$ are $a_1, \dots, a_{n-1}, a_{n+1}, \dots, a_{2n}$.
        // The $n$-th element in this sorted list is $a_{n+1}$.
        // So, $M_1 = a_n$ and $M_2 = a_{n+1}$.
        // This construction always works, regardless of whether $n$ is odd or even.
        // The absolute difference is $|a_{n+1} - a_n|$. Since the array is sorted, this is $a_{n+1} - a_n$.

        std::cout << a[n] - a[n-1] << "\n";
    }
    return 0;
}

#include <iostream>
