#include <numeric>
#include <string>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_post_sum = total_sum / k;
    std::vector<int> s_values;
    long long current_post_sum = 0;
    int current_post_videos_count = 0;
    int posts_formed = 0;

    for (int i = 0; i < n; ++i) {
        current_post_sum += a[i];
        current_post_videos_count++;

        if (current_post_sum == target_post_sum) {
            s_values.push_back(current_post_videos_count);
            current_post_sum = 0;
            current_post_videos_count = 0;
            posts_formed++;
        } else if (current_post_sum > target_post_sum) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_formed == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix with the last element, as it's the minimum
    // price encountered when looking from the right at index n-1.
    int min_suffix = a[n - 1];

    // Iterate from the second to last element backwards
    for (int i = n - 2; i >= 0; --i) {
        // If the current price is greater than the minimum price found to its right,
        // then it's a bad price.
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If the current price is not greater than min_suffix,
            // it means it's either equal or smaller.
            // In either case, this price becomes the new minimum for elements to its left.
            min_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << std::endl;
}

