#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int low = 1;
    int high = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between low and high values.
    // Example: k=2, high=3. Sequence: 1, 3, 2. Differences: |1-3|=2, |3-2|=1.
    // Example: k=3, high=4. Sequence: 1, 4, 2, 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1.
    // Example: k=4, high=5. Sequence: 1, 5, 2, 4, 3. Differences: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1.

    bool use_low = true;
    for (int i = 0; i <= k; ++i) {
        if (use_low) {
            std::cout << low++ << " ";
        } else {
            std::cout << high-- << " ";
        }
        use_low = !use_low;
    }

    // After generating k distinct differences, the remaining numbers
    // must be appended in increasing order to ensure they only produce
    // a difference of 1 (which is already among the k distinct differences
    // if k >= 1).
    // The last number printed was either low-1 or high+1.
    // If use_low is true, it means the last number printed was high, and high was decremented.
    // So the next number to print in increasing order is high+1.
    // If use_low is false, it means the last number printed was low, and low was incremented.
    // So the next number to print in increasing order is low.

    // The numbers used so far are from 1 to k+1.
    // The next available number is k+2.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

