            // The cost is `n_stairs_val * (n_stairs_val + 1) / 2`.

            long long n_stairs_val = 1; // Number of stairs for the current nice staircase (1, 3, 7, ...)
            long long cost_of_current_nice_staircase = 1; // Cost for n_stairs_val stairs

            while (x >= cost_of_current_nice_staircase) {
