                count++;

                // Calculate the next nice staircase's properties
                // Next number of stairs: n_stairs_val_next = 2 * n_stairs_val + 1
                // Next cost: cost_next = n_stairs_val_next * (n_stairs_val_next + 1) / 2
                // This simplifies to (2 * n_stairs_val + 1) * (n_stairs_val + 1)

                // Check for overflow before calculating next cost
                // n_stairs_val can go up to 2^31 - 1 (approx 2*10^9)
                // n_stairs_val + 1 can be 2^31
                // (2 * n_stairs_val + 1) can be 2^32 - 1
                // Product can be (2^32 - 1) * 2^31 which is approx 2^63, fits in long long.
