                    }
                }

                long long next_n_stairs_val = 2 * n_stairs_val + 1;
                long long next_cost_numerator_part1 = next_n_stairs_val;
                long long next_cost_numerator_part2 = next_n_stairs_val + 1;

                // Check for overflow before multiplication
                // next_cost_numerator_part2 is (2 * n_stairs_val + 2)
                // next_cost_numerator_part1 is (2 * n_stairs_val + 1)
                // We need to calculate (next_cost_numerator_part1 * next_cost_numerator_part2) / 2
                // This is equivalent to (2 * n_stairs_val + 1) * (n_stairs_val + 1)
                // If (n_stairs_val + 1) > LLONG_MAX / (2 * n_stairs_val + 1), then overflow.
                // Since n_stairs_val is always positive, (2 * n_stairs_val + 1) is at least 1.
                // The largest n_stairs_val we can have is (1LL << 32) - 1.
                // In this case, n_stairs_val + 1 = 1LL << 32.
                // 2 * n_stairs_val + 1 = (1LL << 33) - 1.
                // (1LL << 32) * ((1LL << 33) - 1) would overflow.
                // So, we need to check if `n_stairs_val + 1` is too large.
                // If `n_stairs_val + 1` is `1LL << 32`, then `(2 * n_stairs_val + 1)` is `(1LL << 33) - 1`.
                // The product `(1LL << 32) * ((1LL << 33) - 1)` will overflow.
                // So, if `n_stairs_val + 1` is `1LL << 32`, we must stop.
                // This means if `n_stairs_val` is `(1LL << 32) - 1`, we must stop.
                // The check `if (n_stairs_val == (1LL << 32) - 1)` handles this.
                // For smaller values, `(n_stairs_val + 1)` will be at most `1LL << 31`.
                // `(2 * n_stairs_val + 1)` will be at most `(1LL << 32) - 1`.
                // The product `(1LL << 31) * ((1LL << 32) - 1)` is `(2^63 - 2^31)`, which fits.
                // So the overflow check `if (n_stairs_val == (1LL << 32) - 1)` is sufficient.

                n_stairs_val = next_n_stairs_val;
                cost_of_current_nice_staircase = n_stairs_val * (n_stairs_val + 1) / 2;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

