    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (result.length() == k) {
            break;
        }

        if (c == '(') {
            // If we still need open brackets and adding one won't make us exceed k/2 total open
            if (open_count < k / 2) {
                result += c;
                open_count++;
                balance++;
            }
        } else { // c == ')'
            // If we still need close brackets and adding one won't make balance negative
            // and adding one won't make us exceed k/2 total close
            if (close_count < k / 2 && balance > 0) {
                result += c;
                close_count++;
                balance--;
            }
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This is the suffix that starts decreasing.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j...i-1] is non-increasing.
    // This is the suffix that starts increasing after the non-decreasing part.
    int j = i;
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing.
    // If j is 0, then a[0...i-1] is non-increasing, and a[i...n-1] is non-decreasing.
    // This means the array looks like non-increasing part followed by non-decreasing part.
    // The "valley" is at index j.

    std::cout << j << std::endl;
}

