    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        if (n <= 2) { // For n=2, the only subsequence of length >= 2 is p itself.
            std::cout << n << "\n";
            for (int i = 0; i < n; ++i) {
                std::cout << p[i] << (i == n - 1 ? "" : " ");
            }
            std::cout << "\n";
            continue;
        }

        std::vector<int> result_subsequence;
        result_subsequence.push_back(p[0]);

        for (int i = 1; i < n - 1; ++i) {
            // Check if p[i] is a local extremum (peak or valley)
            // A peak: p[i-1] < p[i] and p[i] > p[i+1]
            // A valley: p[i-1] > p[i] and p[i] < p[i+1]
            if ((p[i] > p[i-1] && p[i] > p[i+1]) || (p[i] < p[i-1] && p[i] < p[i+1])) {
                result_subsequence.push_back(p[i]);
            }
        }
        result_subsequence.push_back(p[n-1]);

        std::cout << result_subsequence.size() << "\n";
        for (size_t i = 0; i < result_subsequence.size(); ++i) {
            std::cout << result_subsequence[i] << (i == result_subsequence.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
                             // If last_r_pos = i, it means the frog is at cell i.
                             // The distance to the next 'R' or n+1 is calculated from last_r_pos.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The distance from the last 'R' (or 0) to this 'R' is (i+1) - (last_r_pos + 1) + 1
                // which simplifies to (i+1) - last_r_pos.
                // Example: last_r_pos = -1 (at 0), current 'R' at s[0] (cell 1). Gap = 1 - (-1) = 2.
                // Example: last_r_pos = 0 (at cell 1), current 'R' at s[2] (cell 3). Gap = 3 - 1 = 2.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1) + 1);
                last_r_pos = i;
            }
        }
        // After iterating through the string, consider the gap from the last 'R' to n+1.
        // If last_r_pos = -1, it means no 'R' was found, so the only jump is from 0 to n+1.
        // The distance is (n+1) - 0 = n+1.
        // If last_r_pos = i, it means the last 'R' was at cell i+1.
        // The distance from cell i+1 to cell n+1 is (n+1) - (i+1) = n - i.
        max_gap = std::max(max_gap, (n + 1) - (last_r_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

