// Function to check if a sub-array is a permutation
// It checks if all numbers from 1 to length are present exactly once.
bool is_permutation(const std::vector<int>& arr, int start_idx, int length) {
    if (length == 0) {
        return true; // An empty sequence can be considered a permutation of length 0
    }
    std::vector<bool> seen(length + 1, false);
    int max_val = 0;
    for (int i = 0; i < length; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > length || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == length; // All numbers from 1 to length must be present
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix_is_perm[i] = true if a[0...i-1] is a permutation of length i
    std::vector<bool> prefix_is_perm(n + 1, false);
    if (n > 0) { // Handle n=0 case if it were possible, but constraints say n >= 2
        std::vector<bool> seen_prefix(n + 1, false); // Max possible value is n-1, but length can be n
        int current_max_prefix = 0;
        bool prefix_valid = true;
        for (int i = 0; i < n; ++i) {
            int val = a[i];
            if (val <= 0 || val > (i + 1) || seen_prefix[val]) {
                prefix_valid = false;
            }
            if (prefix_valid) {
                seen_prefix[val] = true;
                if (val > current_max_prefix) {
                    current_max_prefix = val;
                }
                if (current_max_prefix == (i + 1)) {
                    prefix_is_perm[i + 1] = true;
                }
            }
        }
    }

    // Precompute suffix_is_perm[i] = true if a[i...n-1] is a permutation of length n-i
    std::vector<bool> suffix_is_perm(n + 1, false); // suffix_is_perm[i] means suffix starting at index i
    if (n > 0) {
        std::vector<bool> seen_suffix(n + 1, false); // Max possible value is n-1, but length can be n
        int current_max_suffix = 0;
        bool suffix_valid = true;
        for (int i = n - 1; i >= 0; --i) {
            int val = a[i];
            int current_suffix_len = n - i;
            if (val <= 0 || val > current_suffix_len || seen_suffix[val]) {
                suffix_valid = false;
            }
            if (suffix_valid) {
                seen_suffix[val] = true;
                if (val > current_max_suffix) {
                    current_max_suffix = val;
                }
                if (current_max_suffix == current_suffix_len) {
                    suffix_is_perm[i] = true;
                }
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can be from 1 to n-1
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l1]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

