void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // Fill p_i for i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i are distinct when increasing
                // But good to check for robustness
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be some number less than q_i
            // and not yet used. We need to pick the smallest available number
            // to maximize chances of finding a solution.
            // The numbers available are those from 1 to n that are not in used_numbers.
            // We need to find the smallest number 'x' such that x < q_i and x is not in used_numbers.
            // This is equivalent to finding the smallest number 'x' such that x is not in used_numbers.
            // If this 'x' is greater than or equal to q_i, then no such p_i exists.
            // We can iterate from 1 upwards to find the smallest unused number.
            // A more efficient way is to keep track of available numbers.
            // For this problem, we can iterate from 1 to n and find the first unused number.
            // However, a simpler approach is to fill the 'gaps' later.
            // Let's mark p[i] as 0 for now and fill it with available numbers later.
            p[i] = 0; // Placeholder for numbers to be filled
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Collect all numbers from 1 to n that have not been used yet
    std::vector<int> available_numbers;
    for (int i = 1; i <= n; ++i) {
        if (used_numbers.find(i) == used_numbers.end()) {
            available_numbers.push_back(i);
        }
    }
    std::sort(available_numbers.rbegin(), available_numbers.rend()); // Sort in descending order for easy pop_back

    // Fill the placeholders (p[i] == 0)
    for (int i = 1; i < n; ++i) {
        if (p[i] == 0) {
            if (available_numbers.empty()) {
                possible = false; // Not enough numbers to fill
                break;
            }
            int num_to_assign = available_numbers.back();
            available_numbers.pop_back();

            if (num_to_assign >= q[i]) {
                // If the smallest available number is not less than q_i,
                // then we cannot satisfy the condition p_i < q_i.
                possible = false;
                break;
            }
            p[i] = num_to_assign;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

