#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        current_sum += a[i];
        current_xor_sum ^= a[i];
    }

    // If the array is already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // We need to append elements.
    // Let S be current_sum and X be current_xor_sum.
    // We want to find b1, b2, ... such that (S + sum(b_i)) = 2 * (X ^ xor(b_i)).
    // This is equivalent to (S + sum(b_i)) - 2 * (X ^ xor(b_i)) = 0.

    // Strategy: Append two elements.
    // Let the first appended element be X (current_xor_sum).
    // New sum S' = S + X
    // New XOR sum X' = X ^ X = 0
    // Now we need to append a second element 'y' such that:
    // (S + X + y) = 2 * (0 ^ y)
    // S + X + y = 2 * y
    // S + X = y
    // So, the second element 'y' should be S + X.

    // Let's verify this strategy:
    // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum
    // New sum: S_new = current_sum + b1 + b2
    //          S_new = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //          S_new = 2 * current_sum + 2 * current_xor_sum
    // New XOR sum: X_new = current_xor_sum ^ b1 ^ b2
    //              X_new = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //              X_new = 0 ^ (current_sum + current_xor_sum)
    //              X_new = current_sum + current_xor_sum
    // Check condition: S_new == 2 * X_new
    // (2 * current_sum + 2 * current_xor_sum) == 2 * (current_sum + current_xor_sum)
    // This is always true.

    // The problem states that appended elements don't have to be different.
    // The values can be up to 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

