            // Each 'a' to its left will eventually interact with this 'b'.
            // When an 'a' interacts with this 'b' (i.e., 'ab' -> 'bba'),
            // that 'a' effectively "jumps over" this 'b' and becomes 'a' followed by two 'b's.
            // The number of 'a's currently accumulated (count_a) represents
            // the number of 'a's that are to the left of the current 'b'
            // and have not yet been processed (i.e., have not formed 'ab' with a 'b' further right).
            // Each of these 'count_a' 'a's will eventually form an 'ab' with this 'b'.
            // When 'ab' -> 'bba', the 'a' effectively moves past the 'b'.
            // The number of steps for this 'b' is equal to the number of 'a's to its left.
            // After this 'b' is processed, it effectively doubles the number of 'a's
            // that will interact with subsequent 'b's to its left.
            // This is because each 'a' that passes this 'b' (count_a)
            // will generate a new 'b' (from 'ab' -> 'bba').
            // So, for the next 'b' to the left, it will see the original 'a's
            // plus the new 'b's generated by the current 'b'.
            // The number of 'a's that will interact with the next 'b' to the left
            // effectively doubles for each 'b' encountered.
            // So, count_a becomes (count_a * 2) % mod.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it adds to the count of 'a's that are
            // available to form 'ab' with 'b's to its left.
            // This 'a' itself is one such 'a'.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

