#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int k = 0; k <= 9; ++k) {
        std::vector<char> s1_digits;
        std::vector<char> s2_digits;
        bool possible_k = true;

        for (int i = 0; i < n; ++i) {
            if (s[i] < (k + '0')) {
                result[i] = '1';
                s1_digits.push_back(s[i]);
            } else if (s[i] > (k + '0')) {
                result[i] = '2';
                s2_digits.push_back(s[i]);
            } else { // s[i] == (k + '0')
                // This digit can be either 1 or 2.
                // If it's the first 'k' we encounter, assign it to 2.
                // If it's not the first 'k', assign it to 1.
                // This strategy ensures that all 'k's assigned to 1 come before 'k's assigned to 2.
                // And the 'k' assigned to 2 will be the first digit of S2 if S2 starts with k.
                // Or it will be after all S1 digits if S1 ends with k.
                if (s2_digits.empty() || s2_digits.back() != (k + '0')) { // If no 'k' has been assigned to S2 yet
                    result[i] = '2';
                    s2_digits.push_back(s[i]);
                } else { // A 'k' has already been assigned to S2
                    result[i] = '1';
                    s1_digits.push_back(s[i]);
                }
            }
        }

        // Check if S1 is sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if S2 is sorted
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if last of S1 <= first of S2
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_k = false;
            }
        }

        if (possible_k) {
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

