    // Case 1: b = 1
    // If b = 1, then mod(x, 1) is always 0.
    // The condition mod(x, b) != 0 is never met.
    // So, there are no nice integers. The sum is 0.
    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    long long sum_r_val = (b - 1);
    sum_r_val %= MOD;
    long long b_mod = b % MOD;
    sum_r_val = (sum_r_val * b_mod) % MOD;

    // Modular inverse of 2 for division
    // (MOD + 1) / 2 for MOD = 10^9 + 7
    long long inv2 = 500000004; 
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // sum_k_term = b * (sum_{k=1 to a} k) + a
    // sum_k_term = b * (a * (a+1) / 2) + a

    long long sum_k_part1 = a;
    sum_k_part1 %= MOD;
    long long a_plus_1 = (a + 1);
    a_plus_1 %= MOD;
    sum_k_part1 = (sum_k_part1 * a_plus_1) % MOD;
    sum_k_part1 = (sum_k_part1 * inv2) % MOD; // (a * (a+1) / 2)

    sum_k_part1 = (sum_k_part1 * b_mod) % MOD; // b * (a * (a+1) / 2)

    long long sum_k_part2 = a;
    sum_k_part2 %= MOD; // a

    long long sum_k_term_val = (sum_k_part1 + sum_k_part2) % MOD;

    // Total sum = sum_r_val * sum_k_term_val
    long long total_sum = (sum_r_val * sum_k_term_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> L(n);
    std::deque<int> dq;

    for (int i = 0; i < n; ++i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_val = (dq.empty() ? 0 : L[dq.back()]);
        long long prev_idx_h = (dq.empty() ? 0 : h[dq.back()]);

        L[i] = std::min(h[i], prev_val + (i - (dq.empty() ? -1 : dq.back())));
        dq.push_back(i);
    }

    std::vector<long long> R(n);
    dq.clear();

    for (int i = n - 1; i >= 0; --i) {
        while (!dq.empty() && h[dq.back()] >= h[i]) {
            dq.pop_back();
        }
        long long prev_val = (dq.empty() ? 0 : R[dq.back()]);
        long long prev_idx_h = (dq.empty() ? 0 : h[dq.back()]);

        R[i] = std::min(h[i], prev_val + ((dq.empty() ? n : dq.back()) - i));
        dq.push_back(i);
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(L[i], R[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

