int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // This operation is only needed if n > 1.
    // If n = 1, we handle it in the third operation.
    if (n > 1) {
        std::cout << 1 << " " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = a[i] % n;
            long long to_add = (remainder == 0) ? 0 : (n - remainder);
            std::cout << to_add << (i == n - 2 ? "" : " ");
            a[i] += to_add; // Update a[i] for subsequent operations
        }
        std::cout << "\n";
    } else { // n == 1
        // If n=1, this operation is on segment [1,0], which is invalid.
        // We can output a dummy operation that does nothing, or just skip it.
        // The problem statement says "exactly three times".
        // For n=1, we can use [1,1] for the first operation, add 0.
        // Then [1,1] for the second, add 0.
        // Then [1,1] for the third, add -a[0].
        // This satisfies the "exactly three times" constraint.
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
    }

    // Operation 2: Make a[n-1] divisible by n
    // This operation is always on segment [n, n].
    std::cout << n << " " << n << "\n";
    long long remainder_n_minus_1 = a[n - 1] % n;
    long long to_add_n_minus_1 = (remainder_n_minus_1 == 0) ? 0 : (n - remainder_n_minus_1);
    std::cout << to_add_n_minus_1 << "\n";
    a[n - 1] += to_add_n_minus_1; // Update a[n-1]

    // Operation 3: Make all elements zero
    // All elements a[i] are now multiples of n.
    // We can select the segment [1, n] and add -a[i] to each a[i].
    std::cout << 1 << " " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // We need to track the effect of operations on two specific inputs: 0 and 1023.
    // 1023 is 0b1111111111 (all 10 bits are 1).
    // By observing the output for 0 and 1023, we can deduce the effect on any bit.
    // Let's call the current value for input 0 as `val_0` and for input 1023 as `val_1023`.
    int val_0 = 0;
    int val_1023 = 1023; // All 10 bits are 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val_0 &= x;
            val_1023 &= x;
        } else if (op_char == '|') {
            val_0 |= x;
            val_1023 |= x;
        } else if (op_char == '^') {
            val_0 ^= x;
            val_1023 ^= x;
        }
    }

    // Now, for each bit position (0 to 9), we can determine its final transformation.
    // Let `b_j` be the j-th bit of the original input.
    // Let `f(b_j)` be the j-th bit of the final output.
    //
    // We know:
    // `f(0)` is the j-th bit of `val_0`.
    // `f(1)` is the j-th bit of `val_1023`.
    //
    // There are four possible transformations for each bit:
    // 1. `f(b_j) = 0` (always 0)
    //    This happens if `f(0) = 0` and `f(1) = 0`.
    // 2. `f(b_j) = 1` (always 1)
    //    This happens if `f(0) = 1` and `f(1) = 1`.
    // 3. `f(b_j) = b_j` (identity)
    //    This happens if `f(0) = 0` and `f(1) = 1`.
    // 4. `f(b_j) = 1 - b_j` (flip, equivalent to `b_j ^ 1`)
    //    This happens if `f(0) = 1` and `f(1) = 0`.

    // We want to find three constants: `and_const`, `or_const`, `xor_const`
    // such that `((input & and_const) | or_const) ^ xor_const`
    // produces the same result.
    //
    // Initialize these constants:
    // `and_const` should initially be all 1s (1023) so it doesn't restrict bits.
    // `or_const` should initially be all 0s (0) so it doesn't set bits.
    // `xor_const` should initially be all 0s (0) so it doesn't flip bits.
    int final_and_const = 1023; // All bits 1
    int final_or_const = 0;     // All bits 0
    int final_xor_const = 0;    // All bits 0

    for (int j = 0; j < 10; ++j) { // Iterate through bits 0 to 9
        int bit_val_0 = (val_0 >> j) & 1;
        int bit_val_1023 = (val_1023 >> j) & 1;

        if (bit_val_0 == 0 && bit_val_1023 == 0) {
            // `f(b_j) = 0`.
            // To achieve this with `((b_j & A) | O) ^ X`:
            // We need `A_j = 0` to force `b_j & A_j` to 0.
            // Then `(0 | O_j) ^ X_j` must be 0.
            // If `O_j = 0`, then `0 ^ X_j = 0` implies `X_j = 0`.
            // If `O_j = 1`, then `1 ^ X_j = 0` implies `X_j = 1`.
            // The simplest way is to set `A_j = 0`.
            final_and_const &= ~(1 << j); // Set j-th bit of and_const to 0
        } else if (bit_val_0 == 1 && bit_val_1023 == 1) {
            // `f(b_j) = 1`.
            // We need `((b_j & A_j) | O_j) ^ X_j = 1`.
            // The simplest way is to set `O_j = 1`.
            final_or_const |= (1 << j); // Set j-th bit of or_const to 1
        } else if (bit_val_0 == 0 && bit_val_1023 == 1) {
            // `f(b_j) = b_j`. (Identity)
            // We need `((b_j & A_j) | O_j) ^ X_j = b_j`.
            // The simplest way is to keep `A_j = 1`, `O_j = 0`, `X_j = 0`.
            // This means `((b_j & 1) | 0) ^ 0 = b_j`.
            // No change needed for `final_and_const`, `final_or_const`, `final_xor_const` for this bit.
        } else { // bit_val_0 == 1 && bit_val_1023 == 0
            // `f(b_j) = 1 - b_j`. (Flip)
            // We need `((b_j & A_j) | O_j) ^ X_j = 1 - b_j`.
            // The simplest way is to keep `A_j = 1`, `O_j = 0`, `X_j = 1`.
            // This means `((b_j & 1) | 0) ^ 1 = b_j ^ 1`.
            final_xor_const |= (1 << j); // Set j-th bit of xor_const to 1
        }
    }

    // Construct the output program.
    // We need to output at most 5 lines.
    // The strategy above uses at most 3 operations: AND, OR, XOR.
    // The order matters: AND first, then OR, then XOR.
    // This is because `((x & A) | O) ^ X` is the canonical form for any bitwise function.
    //
    // If `final_and_const` is 1023 (all 1s), the AND operation is redundant.
    // If `final_or_const` is 0 (all 0s), the OR operation is redundant.
    // If `final_xor_const` is 0 (all 0s), the XOR operation is redundant.

    std::vector<std::pair<char, int>> program;
    if (final_and_const != 1023) {
        program.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) {
        program.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) {
        program.push_back({'^', final_xor_const});
    }

    std::cout << program.size() << "\n";
    for (const auto& op : program) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

// Function to find prime factors of a number
// Returns a vector of unique prime factors
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // If p is divisible by q, we need to find a divisor x of p
        // such that x is not divisible by q.
        // To maximize x, we should divide p by the smallest possible factor
        // that makes it not divisible by q.
        // This means we need to remove just enough prime factors from p
        // such that for at least one prime factor f of q,
        // the power of f in x is less than the power of f in q.

        // Get unique prime factors of q
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 0;

        // For each unique prime factor f of q
        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q
            // or until it's no longer divisible by f.
            while (current_p % q == 0) {
                current_p /= f;
            }
            // current_p is now a divisor of p that is not divisible by q.
            // We want the maximum such current_p.
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<int> fixed_char(k, -1); // -1: unknown, 0: must be '0', 1: must be '1'
    bool possible = true;

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (fixed_char[i % k] == 1) {
                possible = false;
                break;
            }
            fixed_char[i % k] = 0;
        } else if (s[i] == '1') {
            if (fixed_char[i % k] == 0) {
                possible = false;
                break;
            }
            fixed_char[i % k] = 1;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    int count0 = 0;
    int count1 = 0;
    int count_q = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_char[i] == 0) {
            count0++;
        } else if (fixed_char[i] == 1) {
            count1++;
        } else { // fixed_char[i] == -1, means it's a '?'
            count_q++;
        }
    }

    if (count0 > k / 2 || count1 > k / 2) {
        possible = false;
    } else {
        // We need to fill (k/2 - count0) zeros and (k/2 - count1) ones using '?'s.
        // The total number of '?'s available is count_q.
        // The total number of characters we need to fill is (k/2 - count0) + (k/2 - count1).
        // This sum must be equal to count_q.
        // (k/2 - count0) + (k/2 - count1) = k - count0 - count1.
        // Since count_q = k - count0 - count1, this condition is always met if count0 <= k/2 and count1 <= k/2.
        // So, if count0 <= k/2 and count1 <= k/2, it's always possible to fill the '?'s.
        possible = true;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // Adjust to 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false); // Tracks vertices currently in the graph

    // Process vertices in reverse order of removal (i.e., addition order)
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added back

        active_vertices[k] = true; // Mark k as active

        // Floyd-Warshall update step: consider k as an intermediate vertex
        // Only update paths involving active vertices
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                // Path i -> k -> j
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if needed, though problem implies all paths exist
                    dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                }
            }
        }

        // Also update paths involving k as source or destination
        // This is crucial because k itself is a new active vertex
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                // Path i -> k -> j (already covered above, but good to be explicit)
                if (dist[i][k] != -1 && dist[k][j] != -1) {
                    dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                }
                // Path k -> i -> j (using i as intermediate for paths starting at k)
                if (dist[k][i] != -1 && dist[i][j] != -1) {
                    dist[k][j] = std::min(dist[k][j], dist[k][i] + dist[i][j]);
                }
                // Path i -> j -> k (using j as intermediate for paths ending at k)
                if (dist[i][j] != -1 && dist[j][k] != -1) {
                    dist[i][k] = std::min(dist[i][k], dist[i][j] + dist[j][k]);
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of calculation)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

