    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // Skip a_ii which is 0
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p_i is n.
        // Otherwise, p_i is max_val_in_row.
        // This logic is based on the observation that if p_i is not n,
        // then there is some p_j > p_i, so min(p_i, p_j) = p_i.
        // The maximum of min(p_i, p_k) for k != i will be p_i itself.
        // If p_i is n, then min(n, p_j) = p_j for all j != i.
        // The maximum of these p_j values will be n-1.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive number

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        if (X == 1) { // Special case for X=1, k=0 (2^0-1=0, but we need 1 element)
            k = 0;
        } else {
            k = std::floor(std::log2(X + 1));
        }

        // If 2^k - 1 is exactly X, we can use k elements.
        // If 2^k - 1 < X, we use k elements and then process the remainder.
        // If 2^k - 1 > X, it means k was too large. This happens if X+1 is not a power of 2.
        // In this case, we need to find the largest k such that 2^k - 1 <= X.
        // The floor(log2(X+1)) already gives this k.
        // For example, if X=10, X+1=11, log2(11) approx 3.45, floor is 3.
        // 2^3-1 = 7. We use 3 elements. X becomes 10-7=3.
        // Next, X=3, X+1=4, log2(4)=2, floor is 2.
        // 2^2-1 = 3. We use 2 elements. X becomes 3-3=0.
        // Total elements: 3 + 2 = 5.
        // This strategy works.

        long long num_elements_for_k = k + 1; // We add k+1 elements to the array
                                             // The first k elements will be 'current_val'
                                             // The (k+1)-th element will be 'current_val + d'
                                             // This creates 2^k subsequences of 'current_val'
                                             // and 1 subsequence of 'current_val + d'
                                             // Total 2^k subsequences.
                                             // The number of subsequences formed by k identical elements is 2^k-1.
                                             // The number of subsequences formed by k identical elements and one distinct element is 2^k.
                                             // Let's re-evaluate.
                                             // If we add 'k' identical elements, say 'A', we get 2^k-1 subsequences.
                                             // If we add 'k' identical elements 'A' and one element 'B' such that B-A >= d,
                                             // then the subsequences containing both A and B are removed.
                                             // The remaining subsequences are those containing only A's (2^k-1) and those containing only B (1).
                                             // Total 2^k.
                                             // So, if we want to add 2^k subsequences, we can add k identical elements and one element far away.
                                             // The number of elements to add is k+1.
                                             // The number of subsequences contributed is 2^k.

        // The number of subsequences we want to contribute is X.
        // We want to find the largest k such that 2^k <= X.
        // This is k = floor(log2(X)).
        // If X=10, k=floor(log2(10))=3. 2^3=8.
        // We add 3 identical elements (current_val) and one element (current_val + d).
        // This contributes 2^3 = 8 subsequences.
        // X becomes 10-8=2.
        // Next, X=2, k=floor(log2(2))=1. 2^1=2.
        // We add 1 identical element (current_val') and one element (current_val' + d).
        // This contributes 2^1 = 2 subsequences.
        // X becomes 2-2=0.
        // This strategy seems correct.

        // Let's refine k: we want to find the largest k such that 2^k <= X.
        // This is k = floor(log2(X)).
        // If X=1, k=0. 2^0=1.
        // If X=10, k=3. 2^3=8.
        // If X=4, k=2. 2^2=4.

        long long current_k = 0;
        if (X > 0) { // log2(0) is undefined, log2(1) is 0
            current_k = std::floor(std::log2(X));
        }

        // Add current_k identical elements of value `current_val`
        for (int i = 0; i < current_k; ++i) {
            result_array.push_back(current_val);
        }

        // Subtract the contributed subsequences
        X -= (1LL << current_k);

        // Prepare for the next block of elements
        // The next block of elements must be sufficiently far from the current block
        // to ensure that subsequences mixing elements from different blocks are removed.
        // We add d to current_val, then add 1 to ensure it's strictly greater than current_val + d - 1.
        // This ensures that current_val_next - current_val >= d.
        current_val += d + 1;

        // Check for overflow
        if (current_val >= 1000000000000000000LL) { // 10^18
            // This case should ideally not be reached if X is within limits and d is positive.
            // The maximum number of elements is 10^4.
            // Max current_val would be roughly 1 + (10^4) * (10^9 + 1) which is too large.
            // However, the number of distinct values is at most 60 (log2(10^9)).
            // So current_val will be 1 + 60 * (d+1).
            // 1 + 60 * (10^9 + 1) is approx 6 * 10^10, which is < 10^18.
            // So overflow for current_val is not an issue.
        }
    }

    // The problem states that the number of elements in the output array should not be more than 10^4.
    // The maximum value of X is 10^9.
    // The maximum k is floor(log2(10^9)) = 29.
    // In the worst case, X is a sum of powers of 2.
    // E.g., X = 2^29 + 2^28 + ... + 2^0. This would be 30 blocks.
    // Each block adds at most 29 elements.
    // So, total elements would be at most 30 * 29 = 870.
    // This is well within the 10^4 limit.

    std::cout << result_array.size() << "\n";
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply median smoothing once
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    if (n < 3) { // Should not happen based on constraints (n >= 3)
        return a;
    }
    std::vector<int> b(n);
    b[0] = a[0];
    b[n - 1] = a[n - 1];
    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        b[i] = (sum >= 2) ? 1 : 0;
    }
    return b;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Constraints say n >= 3, but good to be robust
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Find the first 0-1 transition from left
    int first_one_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            first_one_idx = i;
            break;
        }
    }

    // Find the last 1-0 transition from right
    int last_zero_idx = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            last_zero_idx = i;
            break;
        }
    }

    if (first_one_idx == -1 || last_zero_idx == -1 || first_one_idx > last_zero_idx) {
        // Sequence is all 0s or all 1s, or already stable (e.g., 000111)
        // In these cases, the sequence is already stable.
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Calculate max_k
    int max_k = 0;
    int current_len = 0;
    for (int i = first_one_idx; i <= last_zero_idx; ++i) {
        if (a[i] == 0) {
            current_len++;
        } else {
            max_k = std::max(max_k, (current_len + 1) / 2);
            current_len = 0;
        }
    }
    max_k = std::max(max_k, (current_len + 1) / 2); // For the last segment of zeros

    // Apply smoothing max_k times
    std::vector<int> current_seq = a;
    for (int k = 0; k < max_k; ++k) {
        current_seq = apply_median_smoothing(current_seq);
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

