#include <iostream>
#include <vector>
#include <numeric> // For std::iota

struct Child {
    long long v, d, p;
    int original_index;
    bool in_queue; // To mark if child is still in line or has run away
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].in_queue = true;
    }

    std::vector<int> cured_children_indices;

    // This loop iterates through the children in their original order.
    // A child is processed if they are still in the queue.
    for (int i = 0; i < n; ++i) {
        if (!children[i].in_queue) {
            continue; // This child has already run away
        }

        // Child i goes to the doctor
        cured_children_indices.push_back(children[i].original_index);
        children[i].in_queue = false; // Child i is now cured, no longer in queue

        long long current_v_cry = children[i].v;
        long long chain_d_cry = 0; // Accumulates d values from children running away

        // Apply confidence reduction to subsequent children
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_queue) {
                continue; // This child has already run away
            }

            // Apply chain reaction cry first
            if (chain_d_cry > 0) {
                children[j].p -= chain_d_cry;
            }

            // Apply current child's v_cry
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--; // v_cry decreases for children further down the line
            }

            // Check if child j's confidence dropped below zero
            if (children[j].p < 0) {
                children[j].in_queue = false; // Child j runs away
                chain_d_cry += children[j].d; // Add child j's d to the chain reaction
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

