int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // If m ones are placed, they divide the string into m+1 potential blocks of zeros.
        // To minimize the number of all-zero substrings, we want to distribute
        // the zeros as evenly as possible among these m+1 blocks.
        // This means each block will have floor(num_zeros / (m+1)) zeros,
        // and some blocks will have one extra zero.

        // Number of blocks that will have (num_zeros / (m+1)) zeros
        long long k_small = (m + 1) - (num_zeros % (m + 1));
        long long len_small = num_zeros / (m + 1);

        // Number of blocks that will have (num_zeros / (m+1)) + 1 zeros
        long long k_large = num_zeros % (m + 1);
        long long len_large = num_zeros / (m + 1) + 1;

        // Calculate the number of all-zero substrings from these blocks
        long long all_zero_substrings = 0;
        if (len_small > 0) { // Only add if block length is positive
            all_zero_substrings += k_small * (len_small * (len_small + 1) / 2);
        }
        if (len_large > 0) { // Only add if block length is positive
            all_zero_substrings += k_large * (len_large * (len_large + 1) / 2);
        }

        // The maximum f(s) is total_substrings - minimum_all_zero_substrings
        long long max_f_s = total_substrings - all_zero_substrings;
        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_j to a very large positive value.
    // b_j represents the maximum possible initial value for a_j.
    // If a_j + current_delta_j <= m_i, then a_j <= m_i - current_delta_j.
    // So, a_j must be less than or equal to min(m_i - current_delta_j) over all relevant type 2 ops.
    std::vector<long long> b(n, std::numeric_limits<long long>::max());

    // Calculate b_j values
    std::vector<long long> current_delta(n, 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Initialize a_j_prime to b_j. This is our candidate initial array.
    std::vector<long long> a_prime(n);
    for (int i = 0; i < n; ++i) {
        a_prime[i] = b[i];
    }

    // Verify the candidate array a_prime
    std::vector<long long> current_a(n);
    for (int i = 0; i < n; ++i) {
        current_a[i] = a_prime[i];
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_prime[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

