    int count_n = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_z = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'z') {
            count_z++;
        }
    }

    // To form "one": requires 'o', 'n', 'e'
    // To form "zero": requires 'z', 'e', 'r', 'o'

    // Maximize '1's first
    int num_ones = 0;
    if (count_o > 0 && count_n > 0 && count_e > 0) {
        num_ones = std::min({count_o, count_n, count_e});
    }

    // Deduct characters used for '1's
    count_o -= num_ones;
    count_n -= num_ones;
    count_e -= num_ones;

    // Now form '0's with remaining characters
    int num_zeros = 0;
    if (count_z > 0 && count_e > 0 && count_r > 0 && count_o > 0) {
        num_zeros = std::min({count_z, count_e, count_r, count_o});
    }

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << "1";
        first_digit = false;
    }
    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << "0";
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

