int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else if (l == 2 && r == 2) { // Edge case for l=r=2, divisor is 2
        std::cout << 2 << std::endl;
    } else if (l == 3 && r == 3) { // Edge case for l=r=3, divisor is 3
        std::cout << 3 << std::endl;
    } else {
        // For any range [l, r] where r >= l+1, the number 2 will always be a divisor
        // for at least floor(r/2) - floor((l-1)/2) numbers.
        // If r >= 2*l, then 2 is guaranteed to be the most frequent.
        // Example: [3, 6]. Multiples of 2: {4, 6} (count 2). Multiples of 3: {3, 6} (count 2).
        // In this case, 2 is a valid answer.
        // The problem asks for *any* of them if there are multiple answers.
        // The number 2 is the most frequent divisor for any sufficiently large range.
        // If r < 2*l, then it's possible that some other number k (where k >= l)
        // appears once (if k is in [l, r]).
        // However, the question asks for the integer that we wrote down the maximum number of times.
        // The number 2 will always be a divisor for at least one number if r >= 2.
        // If l=2, r=3, 2 appears once (for 2), 3 appears once (for 3). Output 2.
        // If l=3, r=4, 2 appears once (for 4), 3 appears once (for 3). Output 2.
        // If l=3, r=5, 2 appears once (for 4), 3 appears once (for 3), 5 appears once (for 5). Output 2.
        // If l=3, r=6, 2 appears twice (for 4, 6), 3 appears twice (for 3, 6). Output 2.
        // The number 2 is always a strong candidate.
        // The only case where 2 might not be the answer is if l=r, where the only divisor is l itself.
        // But we handled l=r already.
        // For l < r, 2 will always be a divisor for at least one number (if r >= 2).
        // And for any k > 2, the count of multiples of k will be less than or equal to the count of multiples of 2.
        // Specifically, count(k) = floor(r/k) - floor((l-1)/k)
        // count(2) = floor(r/2) - floor((l-1)/2)
        // Since k > 2, r/k < r/2 and (l-1)/k < (l-1)/2.
        // This implies count(k) <= count(2).
        // Therefore, 2 is always an optimal answer for l < r.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // The flags `has_pos_one` and `has_neg_one` reflect the state of elements
            // available to modify elements at indices < i.
            // So, if a[i] is 1 or -1, it contributes to these flags for elements to its left.
            // But for elements to its right, it's already processed.
            // The flags are updated as we iterate from right to left.
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. This requires a[k]=1 for some k < i.
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. This requires a[k]=-1 for some k < i.
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update flags for elements to the left of current `i`.
        // If a[i] was 1, it can be used to increase elements at indices < i.
        // If a[i] was -1, it can be used to decrease elements at indices < i.
        // This logic is slightly off. The flags `has_pos_one` and `has_neg_one`
        // should represent if there is a 1 or -1 *at an index less than or equal to the current index*.
        // When we process `a[i]`, we need to know if there's a 1 or -1 at `k < i`.
        // So, the flags should be updated *after* checking `a[i]` but *before* moving to `a[i-1]`.
        // Let's re-think the flag update.
        // The flags `has_pos_one` and `has_neg_one` should track if there's a 1 or -1
        // *among a[0]...a[i-1]*.
        // So, when we are at index `i`, we need to know if `a[0...i-1]` contains 1 or -1.
        // This means we should iterate from left to right, or maintain prefix sums of flags.

        // Let's re-evaluate the logic for flags.
        // When checking a[i], we need to know if there's a 1 or -1 at an index `k < i`.
        // So, `has_pos_one` should be true if any `a[0...i-1]` is 1.
        // And `has_neg_one` should be true if any `a[0...i-1]` is -1.

        // Let's restart the loop logic.
    }

    // Corrected logic: Iterate from left to right.
    // `current_has_pos_one` and `current_has_neg_one` track if a 1 or -1
    // has been encountered *so far* (at indices < current_i).
    has_pos_one = false; // Tracks if a[k]=1 for k < i
    has_neg_one = false; // Tracks if a[k]=-1 for k < i

    for (int i = 0; i < n; ++i) {
        if (a[i] == b[i]) {
            // No operation needed for this element.
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. Requires a[k]=1 for some k < i.
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. Requires a[k]=-1 for some k < i.
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update flags for the *next* iteration (for index i+1).
        // These flags will represent if a 1 or -1 exists in a[0...i].
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

