        while (true) {
            long long cost_of_k_staircase = k * (k + 1) / 2;
            if (current_cost + cost_of_k_staircase <= x) {
                current_cost += cost_of_k_staircase;
                count++;
                k = 2 * k + 1; // Next nice staircase has 2k+1 stairs
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

