void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i must be unique if it's a new max
                // and q_i > q_{i-1} implies q_i was not q_{i-1}
                // and q_{i-1} was either p_{i-1} or an earlier p_j
                // But for safety, check if q_i is already used.
                // This case implies an invalid q input, but the problem guarantees valid q properties.
                // However, it's good to be robust.
                possible = false;
                break;
            }
            p[i] = q[i];
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be some number x such that x <= q_i
            // and x has not been used yet. To maximize chances of finding a solution,
            // we should pick the smallest available number.
            int current_max_val = q[i];
            int candidate = 1;
            while (candidate <= current_max_val && used_numbers.count(candidate)) {
                candidate++;
            }

            if (candidate > current_max_val) {
                // No available number less than or equal to current_max_val
                possible = false;
                break;
            }
            p[i] = candidate;
            used_numbers.insert(candidate);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        // Final check: ensure all numbers from 1 to n are used exactly once.
        // This is implicitly handled by the construction if 'possible' is true,
        // because we always pick the smallest available number.
        // If n numbers are picked and all are distinct and <= n, then they must be 1..n.
        // The only way 'possible' could be true but not all 1..n are used is if
        // some p_i was chosen > n, but p_i is always <= q_i <= n.
        // So, if 'possible' is true, the permutation is valid.
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

