void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    result.reserve(n);

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // We maintain the minimum and maximum indices (leftmost and rightmost)
        // that contain all numbers from 1 to (m-1).
        // To include 'm', we update current_min_idx and current_max_idx
        // to encompass pos[m].

        if (m == 1) {
            // current_min_idx and current_max_idx are already initialized to pos[1]
        } else {
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);
        }

        // A number m is beautiful if the segment [current_min_idx, current_max_idx]
        // which contains all numbers from 1 to m, has a length exactly m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

