    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;
    int i = 0;
    while (i < n) {
        if (a[i] != b[i]) {
            // Mismatch at index i
            // Check if there's an adjacent mismatch that can be swapped
            if (i + 1 < n && a[i+1] != b[i+1] && a[i] != a[i+1]) {
                // Found adjacent mismatches of different types:
                // (a[i] != b[i]) and (a[i+1] != b[i+1])
                // and (a[i] != a[i+1]) implies (a[i] == b[i+1]) and (a[i+1] == b[i])
                // Example: a="01", b="10" -> a[i]=0, b[i]=1; a[i+1]=1, b[i+1]=0
                // Swapping a[i] and a[i+1] makes a="10", which matches b.
                // Cost of swap is |i - (i+1)| = 1.
                total_cost += 1;
                i += 2; // Both positions i and i+1 are resolved
            } else {
                // No adjacent mismatch of different type, or no adjacent mismatch at all.
                // Or adjacent mismatch of same type (e.g., a="00", b="11").
                // In this case, we must flip a[i]. Cost is 1.
                total_cost += 1;
                i += 1; // Position i is resolved
            }
        } else {
            // No mismatch at index i, move to the next position
            i += 1;
        }
    }

    std::cout << total_cost << std::endl;

    return 0;
}

