// Function to determine if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: (-inf, -1]
    // Final product must be negative and magnitude >= 1.
    // This requires an odd number of negative factors.
    // And at least one factor with magnitude >= 1, or a combination that results in magnitude >= 1.

    // Case 1: Total number of negative toys (A+B) is odd.
    // This means the final product will be negative.
    if ((A + B) % 2 == 1) {
        // To be in Box 1, the magnitude must be >= 1.
        // If there's at least one toy from Box 1 or Box 4, we can potentially achieve magnitude >= 1.
        // If all toys are from Box 2 and Box 3, the magnitude will always be < 1.
        // So, if A+D > 0, it's possible.
        if (A + D > 0) {
            return true;
        }
        // If A+D == 0, all initial toys are from B and C.
        // The product of any number of toys from B and C will have magnitude < 1.
        // So, if A+D == 0, it's impossible to get to Box 1.
        return false;
    }
    // Case 2: Total number of negative toys (A+B) is even.
    // This means the final product will be positive.
    // So, it's impossible to end up in Box 1.
    return false;
}

// Function to determine if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: (-1, 0)
    // Final product must be negative and magnitude < 1.
    // This requires an odd number of negative factors.
    // And the final magnitude must be < 1.

    // Case 1: Total number of negative toys (A+B) is odd.
    // This means the final product will be negative.
    if ((A + B) % 2 == 1) {
        // To be in Box 2, the magnitude must be < 1.
        // This is always possible if A+D > 0 by carefully choosing values.
        // Example: -100 * 0.001 * 0.001 = -0.1
        // If A+D > 0, we can always pick values such that the final product is < 1 in magnitude.
        // For example, if we have a large magnitude toy (from A or D), we can pair it with many small magnitude toys (from B or C)
        // to reduce its magnitude.
        // The only way it's impossible is if all toys are from A or D, and we can't reduce the magnitude.
        // But we can always pick values like -1.000001 and -0.000001 to get 0.000001.
        // The question is if we can *force* it to be < 1.
        // If A+D > 0, we can always choose values such that the final product has magnitude < 1.
        // For example, if we have a toy with value X from A or D, and we have B+C toys from B or C.
        // We can assign values like 0.000001 to all B and C toys.
        // Then X * (0.000001)^(B+C) will be very small.
        // So, if A+D > 0, it's possible.
        if (A + D > 0) {
            return true;
        }
        // If A+D == 0, all initial toys are from B and C.
        // The product of any number of toys from B and C will have magnitude < 1.
        // So, if A+D == 0, and (A+B) is odd (meaning B is odd), it's possible.
        return true;
    }
    // Case 2: Total number of negative toys (A+B) is even.
    // This means the final product will be positive.
    // So, it's impossible to end up in Box 2.
    return false;
}

// Function to determine if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: (0, 1)
    // Final product must be positive and magnitude < 1.
    // This requires an even number of negative factors.
    // And the final magnitude must be < 1.

    // Case 1: Total number of negative toys (A+B) is even.
    // This means the final product will be positive.
    if ((A + B) % 2 == 0) {
        // To be in Box 3, the magnitude must be < 1.
        // Similar to Box 2 logic, if A+D > 0, we can always pick values such that the final product has magnitude < 1.
        // For example, if we have a toy with value X from A or D, and we have B+C toys from B or C.
        // We can assign values like 0.000001 to all B and C toys.
        // Then X * (0.000001)^(B+C) will be very small.
        // So, if A+D > 0, it's possible.
        if (A + D > 0) {
            return true;
        }
        // If A+D == 0, all initial toys are from B and C.
        // The product of any number of toys from B and C will have magnitude < 1.
        // So, if A+D == 0, and (A+B) is even (meaning B is even), it's possible.
        return true;
    }
    // Case 2: Total number of negative toys (A+B) is odd.
    // This means the final product will be negative.
    // So, it's impossible to end up in Box 3.
    return false;
}

// Function to determine if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: [1, inf)
    // Final product must be positive and magnitude >= 1.
    // This requires an even number of negative factors.
    // And at least one factor with magnitude >= 1, or a combination that results in magnitude >= 1.

    // Case 1: Total number of negative toys (A+B) is even.
    // This means the final product will be positive.
    if ((A + B) % 2 == 0) {
        // To be in Box 4, the magnitude must be >= 1.
        // If there's at least one toy from Box 1 or Box 4, we can potentially achieve magnitude >= 1.
        // If all toys are from Box 2 and Box 3, the magnitude will always be < 1.
        // So, if A+D > 0, it's possible.
        if (A + D > 0) {
            return true;
        }
        // If A+D == 0, all initial toys are from B and C.
        // The product of any number of toys from B and C will have magnitude < 1.
        // So, if A+D == 0, it's impossible to get to Box 4.
        return false;
    }
    // Case 2: Total number of negative toys (A+B) is odd.
    // This means the final product will be negative.
    // So, it's impossible to end up in Box 4.
    return false;
}

