    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        // Special case: Only one toy initially.
        // The super toy is that single toy.
        if (A + B + C + D == 1) {
            std::cout << (A == 1 ? "Ya" : "Tidak") << " "
                      << (B == 1 ? "Ya" : "Tidak") << " "
                      << (C == 1 ? "Ya" : "Tidak") << " "
                      << (D == 1 ? "Ya" : "Tidak") << "\n";
            continue;
        }

        // General case: More than one toy.
        // The logic for each box is derived from parity of negative numbers and presence of large/small magnitude numbers.
        // The key insight is that if there's at least one toy with magnitude >= 1 (from A or D),
        // we can always construct a scenario to make the final product's magnitude either < 1 or >= 1,
        // by carefully choosing values for toys in B and C (e.g., very close to 0 or very close to 1).
        // If all toys are from B and C, the final product's magnitude will always be < 1.

        std::cout << (can_be_box1(A, B, C, D) ? "Ya" : "Tidak") << " "
                  << (can_be_box2(A, B, C, D) ? "Ya" : "Tidak") << " "
                  << (can_be_box3(A, B, C, D) ? "Ya" : "Tidak") << " "
                  << (can_be_box4(A, B, C, D) ? "Ya" : "Tidak") << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will track the rightmost point for the current left_ptr

    for (int left_ptr = 0; left_ptr < n; ++left_ptr) {
        // Move right_ptr forward until x[right_ptr] - x[left_ptr] > d
        // or until right_ptr reaches the end of the array.
        // The condition is x[right_ptr] <= x[left_ptr] + d
        while (right_ptr < n && x[right_ptr] - x[left_ptr] <= d) {
            right_ptr++;
        }

        // At this point, all points from x[left_ptr] to x[right_ptr - 1]
        // satisfy the condition with x[left_ptr].
        // We need to choose two distinct points from the range (left_ptr, right_ptr - 1].
        // The number of available points in this range is (right_ptr - 1) - (left_ptr + 1) + 1
        // which simplifies to right_ptr - 1 - left_ptr.
        // Let m = right_ptr - 1 - left_ptr. These are the points x_j and x_k.
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m is m * (m - 1) / 2.

        // The number of points available to be x_j or x_k (excluding x_left_ptr itself)
        // is (right_ptr - 1) - left_ptr.
        // Let's call this number 'num_candidates'.
        // num_candidates = (index of last valid point) - (index of current point)
        // num_candidates = (right_ptr - 1) - left_ptr
        // If num_candidates < 2, we cannot form a triplet.

        long long num_candidates = (long long)(right_ptr - 1) - left_ptr;

        if (num_candidates >= 2) {
            count += num_candidates * (num_candidates - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

