#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Operations for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Operations for elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Operations for elements to the right of the median
    // These elements must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<ElementB> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareA);
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    std::vector<long long> result_a(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (b_elements[i].value) should be paired with
        // the (m-1-i)-th smallest A value (a_elements[m-1-i].value)
        // to maximize F(A', B) = A' / (B+1)
        // This means the i-th smallest B value is paired with the i-th largest A value.
        // The original index of this B value is b_elements[i].original_index.
        // The value of A that should go into this position is a_elements[m - 1 - i].value.
        result_a[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a subarray is a permutation of 1 to len
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0
    }
    if (len > arr.size() - start_idx) {
        return false; // Not enough elements for the given length
    }

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    bool current_is_perm = true;
    int distinct_count = 0;

    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val > n || val <= 0 || seen_prefix[val]) {
            current_is_perm = false;
        } else {
            seen_prefix[val] = true;
            distinct_count++;
        }
        if (val > current_max) {
            current_max = val;
        }

        if (current_is_perm && distinct_count == (i + 1) && current_max == (i + 1)) {
            prefix_is_perm[i + 1] = true;
        }
    }

    std::vector<int> suffix_max(n);
    std::vector<bool> suffix_is_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    current_max = 0;
    current_is_perm = true;
    distinct_count = 0;

    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        int len = n - i;
        if (val > n || val <= 0 || seen_suffix[val]) {
            current_is_perm = false;
        } else {
            seen_suffix[val] = true;
            distinct_count++;
        }
        if (val > current_max) {
            current_max = val;
        }

        if (current_is_perm && distinct_count == len && current_max == len) {
            suffix_is_perm[len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

