int calculate_score(const std::string& s) {
    int score = 0;
    if (s.empty()) {
        return 0;
    }
    if (s[0] == 'W') {
        score += 1;
    }
    for (size_t i = 1; i < s.length(); ++i) {
        if (s[i] == 'W') {
            if (s[i - 1] == 'W') {
                score += 2;
            } else {
                score += 1;
            }
        }
    }
    return score;
}

int main() {
