            continue;
        }

        if (initial_wins + k >= n) { // Can make all games 'W'
            std::cout << 2 * n - 1 << "\n";
            continue;
        }

        // Strategy:
        // 1. Convert existing 'W's to 'W's (0 cost, already done)
        // 2. Convert 'L's to 'W's to connect existing 'W' segments (cost 1 per 'L')
        // 3. Convert 'L's to 'W's at the ends or to create new 'W' segments (cost 1 per 'L')

        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        if (first_W == -1) { // All 'L's initially
            // Change k 'L's to 'W's. Best to make them consecutive.
            // If k=0, score is 0.
            // If k>0, score is 1 for first W, 2 for subsequent Ws.
            // So, k wins give 1 + 2*(k-1) = 2k-1 points.
            std::cout << std::max(0, 2 * k - 1) << "\n";
            continue;
        }

        // Calculate gaps between 'W's
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int current_score = calculate_score(s);
        int changes_made = 0;

        // Fill in gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                changes_made += gap_len;
                current_score += 2 * gap_len + 1; // Each L becomes W, connects two Ws, adds 2 points. The first L in a gap connects two Ws, adding 2 points. Subsequent Ls also add 2 points.
                                                  // No, this is wrong. If we fill a gap of length `g`, we change `g` 'L's to 'W's.
                                                  // The `g` 'L's were giving 0 points.
                                                  // Now they are `g` 'W's. The first 'W' in the gap connects to a previous 'W', giving 2 points.
                                                  // The remaining `g-1` 'W's also connect to previous 'W's, giving 2 points each.
                                                  // So, `g` 'W's give `2*g` points.
                                                  // The score increases by `2*g`.
            } else {
                break;
            }
        }

        // Now k changes remain. Use them to extend from ends or create new wins.
        // Extending from ends is always better than creating new isolated wins.
        // Each 'L' changed to 'W' at the ends (adjacent to an existing 'W') adds 2 points.
        // Each 'L' changed to 'W' at the beginning (before first_W) adds 1 point if it's the first, then 2 points for subsequent.
        // Each 'L' changed to 'W' at the end (after last_W) adds 2 points.

        // Points from changing L to W:
        // If it connects to a W: +2 points
        // If it's the first W: +1 point
        // If it's a W after an L: +1 point

        // The current score is `calculate_score(s)` after filling gaps.
        // The `initial_wins` count is for the original string.
        // After filling gaps, the number of wins is `initial_wins + changes_made`.
        // The score from `initial_wins` is `calculate_score(s)`.
        // The score from `changes_made` (filling gaps) is `2 * changes_made`.
        // So, the score after filling gaps is `calculate_score(s) + 2 * changes_made`.

        // Let's recalculate the score based on the modified string conceptually.
        // The initial score is `calculate_score(s)`.
        // When we fill a gap of length `g`, we change `g` 'L's to 'W's.
        // These `g` 'W's are now surrounded by 'W's (or have a 'W' before them).
        // Each of these `g` 'W's will contribute 2 points. So, `2*g` points are added.
        // The `changes_made` variable correctly tracks the number of 'L's converted to 'W's.
        // So, `current_score` is `calculate_score(s)` + `2 * changes_made`.

        // Now, use remaining `k` changes.
        // These changes can be used to:
        // 1. Convert 'L's before `first_W` to 'W's.
        // 2. Convert 'L's after `last_W` to 'W's.
        // 3. Convert 'L's inside gaps that were not fully filled. (This is handled by `gaps` logic)

        // The `current_score` already reflects the score from original 'W's and filled gaps.
        // All 'W's that were part of the original string or filled gaps are now consecutive.
        // The effective string now looks like: `L...L W...W L...L W...W ... W...W L...L`
        // After filling gaps, it's `L...L WWWWWWWW L...L`.
        // The `first_W` and `last_W` are still relevant for the original string.
        // But after filling gaps, the "effective" first W is still `first_W` and "effective" last W is `last_W`.
        // The number of 'W's in the main block (from `first_W` to `last_W`, including filled gaps) is `(last_W - first_W + 1) - (total_L_in_gaps - changes_made)`.
        // This is getting complicated. Let's simplify.

        // The score is `1` for the first 'W' and `2` for every subsequent 'W'.
        // Total 'W's = `initial_wins + changes_made + k_remaining`.
        // If `total_W` is 0, score is 0.
        // If `total_W` is > 0, score is `1 + 2 * (total_W - 1)`.
        // This formula applies if all 'W's are consecutive.
        // By filling gaps, we make 'W's consecutive.
        // The `first_W` and `last_W` define the range of the "main block" of wins.
        // `initial_wins` is the count of 'W's in the original string.
        // `changes_made` is the count of 'L's converted to 'W's to fill gaps.
        // `k` is the remaining changes. These can be used to extend the block of 'W's.
        // Each of these `k` changes will convert an 'L' to a 'W'.
        // If this 'W' is adjacent to an existing 'W', it adds 2 points.
        // If it's the first 'W' in the entire sequence, it adds 1 point.

        // Let's count the total number of 'W's we can achieve.
        // `total_W_count = initial_wins + changes_made + k`.
        // If `total_W_count == 0`, score is 0.
        // If `total_W_count > 0`, the maximum score is `1 + 2 * (total_W_count - 1)`.
        // This is because we can always arrange `total_W_count` wins to be consecutive.
        // We have `initial_wins` 'W's.
        // We use `changes_made` to fill gaps.
        // We use `k` to extend the block of 'W's.
        // The total number of 'W's will be `initial_wins + changes_made + k`.
        // The maximum score for `X` consecutive 'W's is `2*X - 1` (if X > 0).
        // So, the answer is `std::max(0, 2 * (initial_wins + changes_made + k) - 1)`.

        // Let's re-evaluate the example 1: 5 2, WLWLL
        // initial_wins = 2 (s[0], s[2])
