        } else { // All 'L's initially
            std::cout << std::max(0, 2 * k - 1) << "\n";
            continue;
        }

        // Fill gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                score += 2 * gap_len; // Each L in gap becomes W, adds 2 points because it's surrounded by Ws
            } else {
                // Cannot fill this gap. We can use remaining k to fill part of it.
                // If we fill `k` 'L's in this gap, they will be adjacent to a 'W'.
                // Each of these `k` 'L's will become 'W' and add 2 points.
                score += 2 * k;
                k = 0;
                break;
            }
        }

        // Use remaining k for 'L's outside the first_W to last_W block
        // These are 'L's before first_W or after last_W.
        // Each such 'L' converted to 'W' will add 2 points if it's adjacent to an existing 'W'.
        // Or 1 point if it's the first 'W' in the entire sequence.
        // Since we already have `first_W` and `last_W`, any new 'W's will be adjacent to existing 'W's.
        // So, each remaining `k` change adds 2 points.
        score += 2 * k;

        std::cout << score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // If current_sum == 2 * current_xor_sum, the array is already good.
    // We can output 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // We need to append elements b1, b2, ..., bk (k <= 3)
    // such that (current_sum + sum(b_i)) == 2 * (current_xor_sum ^ xor(b_i)).

    // Strategy: Append two elements.
    // Let the two elements be X and S + X.
    // New XOR sum: current_xor_sum ^ X ^ (S + X)
    // New sum: current_sum + X + (S + X)
    // This strategy is not general enough.

    // Let's try to append two elements: current_xor_sum and current_sum + current_xor_sum.
    // Let X = current_xor_sum
    // Let S = current_sum
    // Appended elements: b1 = X, b2 = S + X.
    // New XOR sum: X' = X ^ b1 ^ b2 = X ^ X ^ (S + X) = S + X
    // New sum: S' = S + b1 + b2 = S + X + (S + X) = 2S + 2X
    // We need S' = 2 * X'
    // So, 2S + 2X = 2 * (S + X)
    // This is always true!
    // The elements to append are current_xor_sum and current_sum + current_xor_sum.
    // The problem states that appended elements can be up to 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

