                                   // N=3: Chanek takes 1. N=2. Opponent's turn. Opponent takes 2. Chanek gets 1.
                                   // N=3: Chanek takes 1. N=2. Opponent takes 1. N=1. Chanek takes 1. Opponent takes 0. Chanek gets 2.
                                   // So Chanek takes 1.
                chanek_score += 1;
