                //     A number X is a power of 2 if (X > 0) and ((X & (X - 1)) == 0).
                //     If N/2 is a power of 2 (and N/2 > 2, i.e., N >= 8):
                //       Take 1. (e.g., N=8, N/2=4. Take 1. N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek gets 1+3+1=5.
                //       If Chanek took 4: N=4. Opponent takes 2. N=2. Chanek takes 2. Chanek gets 4+2=6.
                //       So for N=8, Chanek takes 4. The rule "take 1" for N/2 being power of 2 is wrong.

                // Let's re-evaluate the optimal strategy for Chanek when N is even.
                // Chanek wants to maximize his score.
                // Option A: Take 1. Remaining N-1. Opponent plays on N-1.
                // Option B: Take N/2. Remaining N/2. Opponent plays on N/2.

                // Consider N=4:
                //   Take 1: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek gets 1+1=2.
                //   Take 2: N=2. Opponent takes 2. Chanek gets 2.
                //   Both give 2. Chanek takes 2.

                // Consider N=6:
                //   Take 1: N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 2. Chanek gets 1+2=3.
                //   Take 3: N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek gets 3+1=4.
                //   Chanek takes 3.

                // Consider N=8:
                //   Take 1: N=7. Opponent takes 1. N=6. Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. Chanek gets 1+3+1=5.
                //   Take 4: N=4. Opponent takes 2. N=2. Chanek takes 2. Chanek gets 4+2=6.
                //   Chanek takes 4.

                // It seems Chanek always takes N/2 if N is even and N > 2.
                // Let's test this hypothesis.
                // If N is odd, Chanek takes 1. N becomes even.
                // If N is even, Chanek takes N/2. N becomes N/2.

                // This is a simple greedy strategy. Let's trace it.
                // N=5:
                // C: N=5 (odd). Take 1. Chanek=1. N=4.
                // O: N=4 (even). Take 4/2=2. Opponent=2. N=2.
                // C: N=2 (even). Take 2/2=1. Chanek=1+1=2. N=1.
                // O: N=1 (odd). Take 1. Opponent=2+1=3. N=0.
                // Chanek gets 2. This matches example.

                // N=6:
                // C: N=6 (even). Take 6/2=3. Chanek=3. N=3.
                // O: N=3 (odd). Take 1. Opponent=1. N=2.
                // C: N=2 (even). Take 2/2=1. Chanek=3+1=4. N=1.
                // O: N=1 (odd). Take 1. Opponent=1+1=2. N=0.
                // Chanek gets 4. This matches example.

                // This simple greedy strategy seems to work for the examples.
                // Let's consider the edge case where N/2 is 1 (i.e., N=2).
                // C: N=2 (even). Take 2/2=1. Chanek=1. N=1.
                // O: N=1 (odd). Take 1. Opponent=1. N=0.
                // Chanek gets 1.
                // If Chanek took 2: Chanek=2. N=0. Chanek gets 2.
                // So for N=2, Chanek should take 2.
                // The rule "take N/2" is only if N/2 > 1.
                // If N=2, Chanek takes 2.

                // Refined greedy strategy:
                // If N=1, Chanek takes 1.
                // If N=2, Chanek takes 2.
                // If N is odd and N > 2, Chanek takes 1.
                // If N is even and N > 2, Chanek takes N/2.

                // Let's re-trace N=2:
                // C: N=2. Take 2. Chanek=2. N=0.
                // Chanek gets 2. Correct.

                // Let's re-trace N=1:
                // C: N=1. Take 1. Chanek=1. N=0.
                // Chanek gets 1. Correct.

                // This strategy seems robust.
                // The only remaining question is if N is even and N/2 is a power of 2 (N=2^k, k>=3),
                // is it always better to take N/2 than 1?
                // Let N = 2^k, k >= 3.
                // Option A: Take 1. Chanek gets 1. N becomes 2^k - 1 (odd).
                //   Opponent takes 1. N becomes 2^k - 2 (even).
                //   Chanek plays on 2^k - 2.
                // Option B: Take N/2. Chanek gets N/2. N becomes N/2 = 2^(k-1) (even).
                //   Opponent plays on 2^(k-1).

                // This is a known game theory problem. The optimal strategy for the first player
                // when N is even and N/2 is a power of 2 (N=2^k, k>=3) is to take 1.
                // This is because taking N/2 leaves the opponent with a power of 2, which is a "good" state for the opponent.
                // Taking 1 leaves the opponent with an odd number, which is a "bad" state for the opponent.

                // Let's re-evaluate N=8 (N/2=4, which is 2^2).
                // C: N=8.
                //   Option 1: Take 1. Chanek gets 1. N=7.
                //     O: N=7 (odd). Take 1. Opponent gets 1. N=6.
                //     C: N=6 (even). Take 3. Chanek gets 3. N=3.
                //     O: N=3 (odd). Take 1. Opponent gets 1. N=2.
                //     C: N=2 (even). Take 2. Chanek gets 2. N=0.
                //     Total Chanek: 1+3+2 = 6.
                //     Total Opponent: 1+1 = 2.
                //   Option 2: Take 4. Chanek gets 4. N=4.
                //     O: N=4 (even). Take 2. Opponent gets 2. N=2.
                //     C: N=2 (even). Take 2. Chanek gets 2. N=0.
                //     Total Chanek: 4+2 = 6.
                //     Total Opponent: 2.
                // In this case, both options give Chanek 6. So taking 4 is fine.

                // Let's check N=16 (N/2=8, which is 2^3).
                // C: N=16.
                //   Option 1: Take 1. Chanek gets 1. N=15.
                //     O: N=15 (odd). Take 1. Opponent gets 1. N=14.
                //     C: N=14 (even). Take 7. Chanek gets 7. N=7.
                //     O: N=7 (odd). Take 1. Opponent gets 1. N=6.
                //     C: N=6 (even). Take 3. Chanek gets 3. N=3.
                //     O: N=3 (odd). Take 1. Opponent gets 1. N=2.
                //     C: N=2 (even). Take 2. Chanek gets 2. N=0.
                //     Total Chanek: 1+7+3+2 = 13.
                //     Total Opponent: 1+1+1 = 3.
                //   Option 2: Take 8. Chanek gets 8. N=8.
                //     O: N=8 (even). Take 4. Opponent gets 4. N=4.
                //     C: N=4 (even). Take 2. Chanek gets 2. N=2.
                //     O: N=2 (even). Take 2. Opponent gets 2. N=0.
                //     Total Chanek: 8+2 = 10.
                //     Total Opponent: 4+2 = 6.
                // Here, taking 1 (Chanek gets 13) is better than taking 8 (Chanek gets 10).
                // So, if N is even and N/2 is a power of 2 (N=2^k, k>=3), Chanek should take 1.

                // Final refined strategy:
                if (n % 2 != 0) { // N is odd
                    chanek_score += 1;
                    n -= 1;
                } else { // N is even
                    if (n == 2) { // Special case for N=2
                        chanek_score += 2;
                        n = 0;
                    } else {
                        long long half_n = n / 2;
                        // Check if half_n is a power of 2 and half_n > 2 (i.e., N >= 8 and N is a power of 2)
                        // A number X is a power of 2 if (X > 0) and ((X & (X - 1)) == 0).
                        if ((half_n > 2) && ((half_n & (half_n - 1)) == 0)) {
                            // N is 2^k for k >= 3. Take 1.
                            chanek_score += 1;
                            n -= 1;
                        } else {
                            // Otherwise, take N/2.
                            chanek_score += half_n;
                            n = half_n;
                        }
                    }
                }
            }
        } else {
            // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2
                    n = 0;
                } else {
                    long long half_n = n / 2;
                    // Check if half_n is a power of 2 and half_n > 2 (i.e., N >= 8 and N is a power of 2)
                    if ((half_n > 2) && ((half_n & (half_n - 1)) == 0)) {
                        // N is 2^k for k >= 3. Opponent takes 1.
                        n -= 1;
                    } else {
                        // Otherwise, opponent takes N/2.
                        n = half_n;
                    }
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_score;
}

