#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long a_count = 0;
    long long mod = 1000000007;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // that eventually passes this 'b' will contribute to steps.
            // The number of 'a's currently accumulated (a_count)
            // represents the number of 'a's that will eventually pass this 'b'.
            // Each such 'a' passing this 'b' adds a_count steps.
            // The 'a's themselves also double their contribution for future 'b's.
            total_steps = (total_steps + a_count) % mod;
            a_count = (a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it adds to the count of 'a's
            // that are waiting to pass 'b's to their right.
            // This 'a' itself will contribute 1 step for each 'b' it passes.
            // So, we increment a_count.
            a_count = (a_count + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all 1s

    // If s[i] is '0', then w[i-x] and w[i+x] must be '0'
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if this w can produce s
    std::string s_prime(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    if (s_prime == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

