void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> p(n);
    int split_digit = -1;

    // Try to find a split digit 'k' (0-9)
    // All digits < k go to color 1
    // All digits > k go to color 2
    // Digits == k are tricky.
    // We want to find the largest 'k' such that all 'k's can be split.
    // The first 'k's go to color 1, the remaining 'k's go to color 2.
    // This implies that the first 'k's must appear before the remaining 'k's.

    for (int k = 0; k <= 9; ++k) {
        int last1_val = -1; // Last digit placed in color 1
        int last2_val = -1; // Last digit placed in color 2
        bool possible_k = true;
        int first_k_in_2 = -1; // Index of the first digit 'k' assigned to color 2

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < k) {
                if (digit < last1_val) { // Violates non-decreasing for color 1
                    possible_k = false;
                    break;
                }
                p[i] = 1;
                last1_val = digit;
            } else if (digit > k) {
                if (digit < last2_val) { // Violates non-decreasing for color 2
                    possible_k = false;
                    break;
                }
                p[i] = 2;
                last2_val = digit;
            } else { // digit == k
                // If we haven't assigned any 'k' to color 2 yet,
                // we can try to assign it to color 1 if it maintains non-decreasing.
                // Or assign it to color 2 if it maintains non-decreasing.
                // To maximize the chance of success, we greedily assign 'k' to color 1
                // as long as it's valid. Once we assign a 'k' to color 2, all subsequent 'k's must go to color 2.
                if (first_k_in_2 == -1) { // No 'k' has been assigned to color 2 yet
                    if (digit >= last1_val) { // Can assign to color 1
                        p[i] = 1;
                        last1_val = digit;
                    } else { // Cannot assign to color 1, must assign to color 2
                        if (digit < last2_val) { // Violates non-decreasing for color 2
                            possible_k = false;
                            break;
                        }
                        p[i] = 2;
                        last2_val = digit;
                        first_k_in_2 = i; // Mark that we started assigning 'k's to color 2
                    }
                } else { // We have already assigned a 'k' to color 2, so this 'k' must also go to color 2
                    if (digit < last2_val) { // Violates non-decreasing for color 2
                        possible_k = false;
                        break;
                    }
                    p[i] = 2;
                    last2_val = digit;
                }
            }
        }

        if (possible_k) {
            // Check the final condition: last digit of D1 <= first digit of D2
            int final_last1 = -1;
            int final_first2 = 10; // Digits are 0-9, so 10 is larger than any digit

            bool found_last1 = false;
            for (int i = 0; i < n; ++i) {
                if (p[i] == 1) {
                    final_last1 = s[i] - '0';
                    found_last1 = true;
                }
            }

            bool found_first2 = false;
            for (int i = 0; i < n; ++i) {
                if (p[i] == 2) {
                    final_first2 = s[i] - '0';
                    found_first2 = true;
                    break;
                }
            }

            if (found_last1 && found_first2 && final_last1 > final_first2) {
                // This k is not valid because the merge point is violated.
                // This can happen if all digits < k are assigned to 1, and all digits > k are assigned to 2,
                // and some k's are assigned to 1 and some to 2.
                // Example: 12345, k=3. p = 11122. last1=3, first2=3. OK.
                // Example: 132, k=2. p = 121. last1=2, first2=3. OK.
                // Example: 312, k=2. p = 211. last1=2, first2=3. OK.
                // Example: 213, k=2. p = 122. last1=2, first2=1. NOT OK.
                // The logic for assigning 'k's already ensures that if a 'k' is assigned to 1,
                // it must be >= last1_val. If a 'k' is assigned to 2, it must be >= last2_val.
                // The only remaining check is the merge point.
                // If final_last1 > final_first2, this k is invalid.
                // This check is crucial.
                possible_k = false;
            }
        }

        if (possible_k) {
            for (int i = 0; i < n; ++i) {
                std::cout << p[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

