#include <iostream>
#include <algorithm>
#include <vector>

void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 0 means cannot move left (x-1). So target X must be >= current x.
        // This means the robot can only reach points (X, Y) where X >= x.
        // So, the overall target X must be at least x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }
        // f3 = 0 means cannot move right (x+1). So target X must be <= current x.
        // This means the robot can only reach points (X, Y) where X <= x.
        // So, the overall target X must be at most x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }
        // f4 = 0 means cannot move down (y-1). So target Y must be >= current y.
        // This means the robot can only reach points (X, Y) where Y >= y.
        // So, the overall target Y must be at least y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
        // f2 = 0 means cannot move up (y+1). So target Y must be <= current y.
        // This means the robot can only reach points (X, Y) where Y <= y.
        // So, the overall target Y must be at most y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. The problem guarantees that if a point exists,
        // one exists within [-10^5, 10^5].
        // We can pick any point in the valid range, e.g., (min_x, min_y).
        // We need to clamp min_x and min_y to the guaranteed range.
        // The problem statement says "Both X and Y should not exceed 10^5 by absolute value".
        // This implies that if min_x is, say, 10^6, but a valid point exists,
        // then there must be a valid point within [-10^5, 10^5].
        // The current min_x/max_x/min_y/max_y are derived from robot constraints.
        // If min_x is greater than 10^5, it means all valid X are greater than 10^5.
        // But the problem guarantees that if a solution exists, one is within [-10^5, 10^5].
        // This implies that min_x will not exceed 10^5 if a solution exists.
        // Similarly for max_x, min_y, max_y.
        // So, we can just output min_x and min_y directly.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

