    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: sum_r = (b-1) * b / 2
    // This needs to be calculated modulo MOD.
    // Since b-1 and b are consecutive, one is even.
    // So (b-1)*b is always even, and division by 2 is exact.
    // We need to find the modular inverse of 2 for division.
    // (MOD + 1) / 2 is the modular inverse of 2 for MOD = 10^9 + 7.
    // (10^9 + 7 + 1) / 2 = (10^9 + 8) / 2 = 500000004.
    long long inv2 = 500000004;

    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // Handle b=1 case where b-1=0
    sum_r_term %= MOD;

    long long b_mod = b % MOD;

    long long sum_r = (sum_r_term * b_mod) % MOD;
    sum_r = (sum_r * inv2) % MOD;

    // Sum of (k*b + 1) from k=1 to a:
    // sum_k = sum_{k=1 to a} (k*b + 1)
    // sum_k = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_k = b * (a * (a+1) / 2) + a

    long long sum_k_part1_term1 = a % MOD;
    long long sum_k_part1_term2 = (a + 1) % MOD;

    long long sum_k_part1 = (sum_k_part1_term1 * sum_k_part1_term2) % MOD;
    sum_k_part1 = (sum_k_part1 * inv2) % MOD;
    sum_k_part1 = (sum_k_part1 * b_mod) % MOD;

    long long sum_k_part2 = a % MOD;

    long long sum_k = (sum_k_part1 + sum_k_part2) % MOD;

    // Total sum = sum_r * sum_k
    long long total_sum = (sum_r * sum_k) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

