int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Dummy operation (add 0)
        std::cout << "1 1\n";
        std::cout << "0\n";

        // Operation 3: Dummy operation (add 0)
        std::cout << "1 1\n";
        std::cout << "0\n";
    } else {
        // Operation 1: Make a[0]...a[n-2] divisible by n
        // For each a[i] (0 <= i < n-1), we want to add x_i such that (a[i] + x_i) % n == 0.
        // x_i must be a multiple of n-1.
        // This is not directly possible. We need to make a[i] % n == 0.
        // Let's use the property that we can make a[i] % (r-l+1) == 0.

        // Operation 1: For elements a[0] to a[n-2]
        // Select segment [1, n-1]. Length is n-1.
        // For each a[i] in this segment, we want to add b_i such that (a[i] + b_i) % (n-1) == 0.
        // We can choose b_i = ( (n-1) - (a[i] % (n-1)) ) % (n-1).
        // This makes a[i] + b_i a multiple of (n-1).
        // Then we can add a multiple of (n-1) to make it 0.
        // No, this is not correct. We need to make a[i] % n == 0.

        // Strategy:
        // 1. Make a[0]...a[n-2] multiples of n.
        //    Segment [1, n-1]. Length is n-1.
        //    For each a[i] (0 <= i < n-1), we want to add b_i such that (a[i] + b_i) % n == 0.
        //    And b_i must be a multiple of (n-1).
        //    This is possible if gcd(n, n-1) = 1. Which is always true.
        //    We need to find b_i such that b_i = k * (n-1) and a[i] + b_i = m * n.
        //    a[i] + k * (n-1) = m * n
        //    a[i] + k * n - k = m * n
        //    a[i] - k = (m - k) * n
        //    So, a[i] - k must be a multiple of n.
        //    This means k % n == a[i] % n.
        //    We can choose k = a[i] % n. If a[i] % n is negative, add n.
        //    So, k = (a[i] % n + n) % n.
        //    Then b_i = k * (n-1).
        //    After this operation, a[i] becomes a[i] + b_i, which is a multiple of n.

        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = (a[i] % n + n) % n; // a[i] % n, ensuring positive
            long long k = remainder;
            long long b_i = k * (n - 1);
            std::cout << b_i << (i == n - 2 ? "" : " ");
            a[i] += b_i; // Update a[i]
        }
        std::cout << "\n";

        // Now a[0]...a[n-2] are all multiples of n.
        // a[n-1] is unchanged.

        // Operation 2: Make a[n-1] a multiple of n.
        // Select segment [n, n]. Length is 1.
        // For a[n-1], we want to add b_{n-1} such that (a[n-1] + b_{n-1}) % n == 0.
        // b_{n-1} must be a multiple of 1.
        // We can choose b_{n-1} = ( (n - (a[n-1] % n)) % n ).
        // No, we need to make it a multiple of n.
        // We can choose b_{n-1} = (n - (a[n-1] % n + n) % n) % n.
        // This makes a[n-1] + b_{n-1} a multiple of n.
        // This is not enough. We need to make it 0.
        // We can add any multiple of 1. So we can add -a[n-1].
        // But we need to make it a multiple of n first.

        // Let's rethink.
        // We need to make all a[i] zero.
        // The key is that we can change a[i] to a[i] + k * len.
        // This means a[i] % len remains the same.
        // So, if we want a[i] to become 0, we need a[i] % len == 0.

        // A common strategy for this type of problem:
        // 1. Make all elements a multiple of N.
        // 2. Then zero them out.

        // Operation 1: Make all a[i] (0 <= i < n-1) multiples of n.
        // Segment [1, n-1]. Length is n-1.
        // For each a[i] (0 <= i < n-1), we want to add b_i such that a[i] + b_i is a multiple of n.
        // And b_i must be a multiple of (n-1).
        // We need a[i] + b_i = K * n.
        // b_i = k * (n-1).
        // a[i] + k * (n-1) = K * n
        // a[i] + k*n - k = K * n
        // a[i] - k = (K-k) * n
        // So, a[i] - k must be a multiple of n.
        // This means k % n == a[i] % n.
        // Let k = (a[i] % n + n) % n.
        // Then b_i = k * (n-1).
        // This b_i is a multiple of (n-1).
        // And a[i] + b_i = a[i] + ((a[i] % n + n) % n) * (n-1)
        //                 = a[i] + (a[i] % n) * (n-1) (if a[i] % n is positive)
        //                 = a[i] + (a[i] % n) * n - (a[i] % n)
        //                 = (a[i] - (a[i] % n)) + (a[i] % n) * n
        // This is a multiple of n.
        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = (a[i] % n + n) % n;
            long long k = remainder;
            long long b_i = k * (n - 1);
            std::cout << b_i << (i == n - 2 ? "" : " ");
            a[i] += b_i;
        }
        std::cout << "\n";

        // Now a[0]...a[n-2] are multiples of n.
        // a[n-1] is unchanged.

        // Operation 2: Make a[n-1] a multiple of n.
        // Segment [n, n]. Length is 1.
        // For a[n-1], we want to add b_{n-1} such that a[n-1] + b_{n-1} is a multiple of n.
        // b_{n-1} must be a multiple of 1.
        // We can choose b_{n-1} = (n - (a[n-1] % n + n) % n) % n.
        // This makes a[n-1] + b_{n-1} a multiple of n.
        // This is not enough. We need to make it 0.
        // We can add any multiple of 1. So we can add -a[n-1].
        // This makes a[n-1] zero.
        std::cout << n << " " << n << "\n";
        std::cout << -a[n-1] << "\n";
        a[n-1] = 0;

        // Now all a[i] (0 <= i < n-1) are multiples of n.
        // And a[n-1] is 0.

        // Operation 3: Zero out a[0]...a[n-2].
        // Segment [1, n]. Length is n.
        // For each a[i] (0 <= i < n-1), it's already a multiple of n.
        // We want to add b_i such that a[i] + b_i = 0.
        // b_i must be a multiple of n.
        // Since a[i] is already a multiple of n, we can choose b_i = -a[i].
        // For a[n-1], it's already 0. We add 0.
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

