#include <iostream>
#include <algorithm> // For std::min and std::max

long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    // Total number of substrings is n * (n + 1) / 2
    // We want to maximize f(s), which means minimizing the number of substrings consisting only of '0's.
    // The number of '0's is n - m.
    // To minimize substrings of '0's, we need to distribute the '0's as evenly as possible.
    // The 'm' ones divide the string into m+1 potential blocks of zeros.
    // For example, 0...0 1 0...0 1 ... 1 0...0
    // We have n-m zeros to distribute among m+1 blocks.
    // Let k be the number of zeros in each block.
    // We want to make the lengths of these blocks as equal as possible.
    // Number of zeros: n_zeros = n - m.
    // Number of blocks for zeros: n_blocks = m + 1.

    long long n_zeros = n - m;

    // If n_zeros is 0, there are no '0's, so no substrings of '0's.
    // f(s) = n * (n + 1) / 2. This is handled by the general formula.
    // If m == n, then n_zeros = 0. The loop below for 'a' and 'b' will correctly calculate 0.

    // Calculate the base number of zeros per block and the remainder.
    long long k = n_zeros / (m + 1); // Minimum number of zeros in a block
    long long r = n_zeros % (m + 1); // Number of blocks that get one extra zero

    // So, 'r' blocks will have (k+1) zeros, and (m+1 - r) blocks will have 'k' zeros.
    // The number of substrings of '0's contributed by a block of length L is L * (L + 1) / 2.
    // We need to sum this for all blocks.

    long long sum_zero_substrings = 0;

    // Blocks with (k+1) zeros
    if (k + 1 > 0) { // Only count if block has actual zeros
        sum_zero_substrings += r * ((k + 1) * (k + 2) / 2);
    }

    // Blocks with k zeros
    if (k > 0) { // Only count if block has actual zeros
        sum_zero_substrings += (m + 1 - r) * (k * (k + 1) / 2);
    }

    // Total substrings = n * (n + 1) / 2
    // Max f(s) = Total substrings - Min substrings of '0's
    long long total_substrings = n * (n + 1) / 2;

    return total_substrings - sum_zero_substrings;
}

