void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left segment (jars 1 to n)
    // Balance: +1 for strawberry (1), -1 for blueberry (2)
    // left_balances[k] stores the balance of jars a[n-k]...a[n-1]
    // i.e., balance of the last k jars of the left segment
    // left_balances[0] = 0 (empty prefix)
    // left_balances[1] = balance of a[n-1]
    // left_balances[k] = balance of a[n-k]...a[n-1]
    std::map<int, int> left_balances; // balance -> count of jars removed from left
    left_balances[0] = 0; // 0 jars removed from left, balance 0

    int current_balance = 0;
    for (int k = 0; k < n; ++k) {
        // Iterate from a[n-1] down to a[0]
        // This corresponds to removing jars from the left side: a[0], a[1], ..., a[k-1]
        // and considering the remaining suffix of the left segment: a[k], ..., a[n-1]
        // No, this is not correct.
        // We are considering the jars *remaining* in the left segment.
        // If we remove `i` jars from the left (a[0]...a[i-1]), the remaining jars are a[i]...a[n-1].
        // The balance of these remaining jars is what we need.
        // Let's re-evaluate.
        // We need the balance of the suffix of the left segment: a[i]...a[n-1].
        // The number of jars removed from the left is `i`.
        // The length of the suffix is `n-i`.
        // Let's compute prefix sums from right to left for the left segment.
        // `left_prefix_sums[k]` will be the balance of `a[n-k]...a[n-1]`.
        // `k` is the number of jars *remaining* in the left segment.
        // `n-k` is the number of jars *removed* from the left segment.
        // So, `left_balances[balance_of_a[n-k]...a[n-1]] = n-k`.
        // This map stores `balance_of_remaining_left_segment -> jars_removed_from_left`.

        // Let's use a simpler approach for the left segment:
        // `left_prefix_sums[k]` = balance of `a[0]...a[k-1]`
        // `left_prefix_sums[0] = 0`
        // `left_prefix_sums[k]` = balance of `a[0]...a[k-1]`
        // The total balance of the left segment `a[0]...a[n-1]` is `left_prefix_sums[n]`.
        // If we remove `i` jars from the left (a[0]...a[i-1]), the remaining jars are `a[i]...a[n-1]`.
        // The balance of these remaining jars is `left_prefix_sums[n] - left_prefix_sums[i]`.
        // The number of jars removed is `i`.
        // We want to store `balance_of_remaining_left_segment -> jars_removed_from_left`.
        // So, `left_map[left_prefix_sums[n] - left_prefix_sums[i]] = i`.
        // We need to iterate `i` from `0` to `n`.

        // Let's define `balance_val(jar_type)` as `1` if `jar_type == 1` and `-1` if `jar_type == 2`.
        // `left_prefix_balances[k]` = balance of `a[0]...a[k-1]`
        std::vector<int> left_prefix_balances(n + 1, 0);
        for (int i = 0; i < n; ++i) {
            left_prefix_balances[i + 1] = left_prefix_balances[i] + (a[i] == 1 ? 1 : -1);
        }

        // `left_map[balance_of_remaining_left_segment] = jars_removed_from_left`
        // Iterate `i` from `0` to `n` (number of jars removed from left)
        // Remaining jars are `a[i]...a[n-1]`.
        // Balance of remaining jars = `left_prefix_balances[n] - left_prefix_balances[i]`.
        // We want to store the minimum `i` for each balance.
        for (int i = 0; i <= n; ++i) {
            int balance_of_remaining = left_prefix_balances[n] - left_prefix_balances[i];
            if (left_balances.find(balance_of_remaining) == left_balances.end()) {
                left_balances[balance_of_remaining] = i;
            } else {
                left_balances[balance_of_remaining] = std::min(left_balances[balance_of_remaining], i);
            }
        }
    }

    // Calculate prefix sums for the right segment (jars n+1 to 2n)
    // `right_prefix_balances[k]` = balance of `a[2n-1]...a[2n-k]` (from right to left)
    // `right_prefix_balances[0] = 0`
    // `right_prefix_balances[k]` = balance of `a[2n-1]...a[2n-k]`
