    for (int k = 0; k <= n; ++k) { // k is the number of jars remaining in the right segment
        int balance_of_remaining = right_segment_prefix_balances[k];
        int jars_removed_from_right = n - k;
        if (right_balances.find(balance_of_remaining) == right_balances.end()) {
            right_balances[balance_of_remaining] = jars_removed_from_right;
        } else {
            right_balances[balance_of_remaining] = std::min(right_balances[balance_of_remaining], jars_removed_from_right);
        }
    }

    int min_jars_removed = 2 * n; // Max possible jars removed

    // Iterate through all possible balances for the remaining left segment
    // For each `left_balance` and its corresponding `jars_removed_from_left`,
    // we need the right segment to have a balance of `-left_balance`.
    for (auto const& [left_bal, jars_l] : left_balances) {
        int target_right_bal = -left_bal;
        if (right_balances.count(target_right_bal)) {
            int jars_r = right_balances[target_right_bal];
            min_jars_removed = std::min(min_jars_removed, jars_l + jars_r);
        }
    }

    std::cout << min_jars_removed << std::endl;
}

