        // The standard Floyd-Warshall `for k, for i, for j` is the correct structure.
        // Here, `k` is the vertex being added.
        // So, the loops should be:
        // for (int i = 0; i < n; ++i) {
        //     for (int j = 0; j < n; ++j) {
        //         if (active[i] && active[j]) {
        //             // Update dist[i][j] using k as intermediate
        //             if (dist[i][k] != -1 && dist[k][j] != -1) {
        //                 if (dist[i][j] == -1 || dist[i][j] > dist[i][k] + dist[k][j]) {
        //                     dist[i][j] = dist[i][k] + dist[k][j];
        //                 }
        //             }
        //         }
        //     }
        // }
        // This is the correct way to update `dist[i][j]` for all active `i, j` using `k` as an intermediate.
        // The `dist[i][k]` and `dist[k][j]` values are already shortest paths using previously active vertices.
        // So, this single set of loops is sufficient.

        // Calculate sum of shortest paths for currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                if (dist[i][j] != -1) { // Only sum reachable pairs
                    current_sum += dist[i][j];
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in forward order
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply median smoothing once
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    std::vector<int> b(n);
    if (n == 0) return b;

    b[0] = a[0];
    if (n > 1) {
        b[n - 1] = a[n - 1];
    }

    for (int i = 1; i < n - 1; ++i) {
        // Median of three 0s and 1s is 1 if sum >= 2, else 0
        b[i] = (a[i - 1] + a[i] + a[i + 1] >= 2) ? 1 : 0;
    }
    return b;
}

// Function to check if a sequence is stable
bool is_stable(const std::vector<int>& a) {
    return a == apply_median_smoothing(a);
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable by definition
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Find the first 0-1 transition from left
    int first_transition_01 = -1;
    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 0 && a[i + 1] == 1) {
            first_transition_01 = i;
            break;
        }
    }

    // Find the first 1-0 transition from right
    int first_transition_10 = -1;
    for (int i = n - 1; i > 0; --i) {
        if (a[i - 1] == 1 && a[i] == 0) {
            first_transition_10 = i;
            break;
        }
    }

    if (first_transition_01 == -1 && first_transition_10 == -1) {
        // Sequence is all 0s or all 1s, already stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Calculate max_k
    int max_k = 0;
    if (first_transition_01 != -1 && first_transition_10 != -1) {
        max_k = std::max(0, (first_transition_10 - first_transition_01 - 1) / 2);
    }

    // Apply smoothing max_k times
    std::vector<int> current_a = a;
    for (int k = 0; k < max_k; ++k) {
        current_a = apply_median_smoothing(current_a);
    }

    std::cout << max_k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << current_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

