        long long current_head_pos = h[h_idx];
        long long head_left_reach = current_head_pos - T;
        long long head_right_reach = current_head_pos + T;

        // If the current head cannot reach the current target track p[p_idx]
        // even if it moves left as much as possible, then this head cannot cover p[p_idx].
        // We need to find a head that can cover p[p_idx].
        // Since heads are sorted and p are sorted, if h[h_idx] is too far right,
        // then h[h_idx+1] will also be too far right.
        // This implies that if p[p_idx] > head_right_reach, this head cannot cover p[p_idx].
        // We need to find a head that can cover p[p_idx].
        // The current head h[h_idx] can cover p[p_idx] if p[p_idx] is within [head_left_reach, head_right_reach].
        // If p[p_idx] is to the left of head_left_reach, this head cannot cover it.
        // We need to advance p_idx until it's within reach or we run out of p.
        // Or, more simply, if p[p_idx] is not covered by this head, we move to the next head.

        // Find the first p[p_idx] that this head can potentially cover.
        // This is implicitly handled by the greedy approach:
        // If p[p_idx] is already covered by a previous head, p_idx would have advanced.
        // If p[p_idx] is not covered, we try to cover it with the current head.

        // The current head h[h_idx] can cover tracks in [h[h_idx] - T, h[h_idx] + T].
        // We want to cover p[p_idx] with this head.
        // If p[p_idx] is to the right of h[h_idx] + T, this head cannot cover p[p_idx].
        // If p[p_idx] is to the left of h[h_idx] - T, this head cannot cover p[p_idx].
        // In this case, we need to use a different head for p[p_idx].
        // However, the greedy strategy is to use the current head to cover p[p_idx]
        // if it's possible, and then cover as many subsequent tracks as possible.

        // The key insight for the greedy approach:
        // For the current target track p[p_idx] that needs to be covered,
        // we must use the "leftmost available head" that can cover it.
        // If h[h_idx] is the current head, and p[p_idx] is the current target track:
        // If p[p_idx] is to the right of h[h_idx] + T, then h[h_idx] cannot cover p[p_idx].
        // Since h is sorted, h[h_idx+1]... will also be to the right of p[p_idx] (or further right).
        // This means we need to use a head that is to the right of h[h_idx].
        // This is not quite right. The heads can move.

        // Let's re-evaluate the greedy strategy for interval covering.
        // We have a set of points (p_j) to cover.
        // We have a set of intervals (h_i - T, h_i + T) that heads can cover.
        // We want to use minimum number of heads to cover all p_j.
        // This is not exactly minimum number of heads, but rather, can N heads cover all p_j.

        // A more robust greedy approach for `check(T)`:
        // Iterate through the heads. For each head, determine the maximum range it can cover.
        // If the current head `h[h_idx]` can cover `p[p_idx]`, then it can cover `p[p_idx]`
        // and all subsequent `p_j` such that `p_j <= h[h_idx] + T`.
        // The head can also move left. So it can cover `p[p_idx]` and all subsequent `p_j`
        // such that `p_j` is within `[p[p_idx], p[p_idx] + (T - abs(p[p_idx] - h[h_idx]))]`.
        // This is complicated.

        // A simpler greedy approach:
        // For each head `h[h_idx]`, we want to cover `p[p_idx]` and as many subsequent `p` tracks as possible.
        // The head `h[h_idx]` can cover the range `[h[h_idx] - T, h[h_idx] + T]`.
        // If `p[p_idx]` is to the right of `h[h_idx] + T`, then this head cannot cover `p[p_idx]`.
        // We must use a head `h[k]` where `k > h_idx` to cover `p[p_idx]`.
        // This means `h[h_idx]` is "wasted" or used for something else (which is not optimal for covering `p[p_idx]`).
        // So, if `p[p_idx] > h[h_idx] + T`, this `check(T)` fails. (This is wrong, we can use a later head).

        // Correct greedy strategy for `check(T)`:
        // We iterate through the heads `h_idx` from `0` to `n-1`.
        // For each head `h[h_idx]`, we try to cover the current `p[p_idx]` (if `p_idx < m`).
        // If `p[p_idx]` is already covered by a previous head (i.e., `p[p_idx]` is to the left of `h[h_idx] - T`),
        // we advance `p_idx` until `p[p_idx]` is not covered or `p_idx == m`.
        // If `p_idx == m`, all tracks are covered.
        // If `p[p_idx]` is not covered, we use `h[h_idx]` to cover it.
        // The head `h[h_idx]` can cover `p[p_idx]` if `abs(h[h_idx] - p[p_idx]) <= T`.
        // If it can, then it can cover the range `[p[p_idx], p[p_idx] + (T - abs(h[h_idx] - p[p_idx]))]`.
        // This is the maximum rightward reach for this head if it covers `p[p_idx]`.
        // Let `max_reach = p[p_idx] + (T - std::abs(h[h_idx] - p[p_idx]))`.
        // We then advance `p_idx` as long as `p[p_idx] <= max_reach`.

        // This greedy strategy is correct for interval covering.
        // `p_idx` is the index of the first track that still needs to be covered.
        // `h_idx` is the index of the current head we are considering.

        // If `p_idx` is already at `m`, all tracks are covered.
        if (p_idx == m) {
            return true;
        }

        // Calculate the range this head can cover if it moves optimally to cover p[p_idx].
        // The head h[h_idx] can cover any track in [h[h_idx] - T, h[h_idx] + T].
        // If p[p_idx] is to the left of h[h_idx] - T, this head cannot cover p[p_idx]
        // without moving further left than its maximum left reach.
        // In this case, this head is too far right to cover p[p_idx].
        // We must use a head h[k] with k < h_idx (which is not possible as we iterate h_idx)
        // or p[p_idx] must have been covered by a previous head.
        // This means if p[p_idx] < h[h_idx] - T, then this `check(T)` fails.
        // This is because we are trying to cover p[p_idx] with the current head.
        // If it's too far left, no subsequent head can cover it either.
        // So, if p[p_idx] < h[h_idx] - T, then this `check(T)` fails.
        // This is the crucial part.

        // If p[p_idx] is to the left of h[h_idx] - T, then h[h_idx] cannot cover p[p_idx].
        // Since h is sorted, any h[k] for k > h_idx will be even further right,
        // so they also cannot cover p[p_idx].
        // This means p[p_idx] cannot be covered by any remaining head.
        // So, if p[p_idx] < h[h_idx] - T, then it's impossible.
        // This is the condition for failure.
        if (p[p_idx] < h[h_idx] - T) {
            return false;
        }

        // If we reach here, it means h[h_idx] - T <= p[p_idx].
        // This head can potentially cover p[p_idx].
        // The head h[h_idx] can cover the interval [h[h_idx] - T, h[h_idx] + T].
        // We want to cover p[p_idx] and as many subsequent tracks as possible.
        // The rightmost track this head can cover is h[h_idx] + T.
        // We advance p_idx as long as p[p_idx] is within this head's reach.
        while (p_idx < m && p[p_idx] <= h[h_idx] + T) {
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible time: distance from first head to last track, or last head to first track.
    // A loose upper bound: (max_p - min_h) or (max_h - min_p)
    // Max value of p or h is 10^10. So max diff is 10^10.
    // A single head might need to cover a range of 2 * 10^10.
    // So T can be up to 2 * 10^10.
    long long high = 20000000000LL; // 2 * 10^10

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_if_input_is_0 = 0; // Represents the state of bits if input bit is 0
    int current_val_if_input_is_1 = 1023; // Represents the state of bits if input bit is 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_if_input_is_0 &= x;
            current_val_if_input_is_1 &= x;
        } else if (op_char == '|') {
            current_val_if_input_is_0 |= x;
            current_val_if_input_is_1 |= x;
        } else if (op_char == '^') {
            current_val_if_input_is_0 ^= x;
            current_val_if_input_is_1 ^= x;
        }
    }

    int final_and_mask = 1023; // Value for '&' operation
    int final_or_mask = 0;    // Value for '|' operation
    int final_xor_mask = 0;   // Value for '^' operation

    for (int bit = 0; bit < 10; ++bit) {
        int bit_mask = (1 << bit);
        int bit_0_result = (current_val_if_input_is_0 & bit_mask) >> bit;
        int bit_1_result = (current_val_if_input_is_1 & bit_mask) >> bit;

        if (bit_0_result == 0 && bit_1_result == 0) {
            // Input 0 -> 0, Input 1 -> 0
            // This means the bit must be forced to 0.
            // Achieved by: & 0
            final_and_mask &= (~bit_mask);
        } else if (bit_0_result == 1 && bit_1_result == 1) {
            // Input 0 -> 1, Input 1 -> 1
            // This means the bit must be forced to 1.
            // Achieved by: | 1
            final_or_mask |= bit_mask;
        } else if (bit_0_result == 0 && bit_1_result == 1) {
            // Input 0 -> 0, Input 1 -> 1
            // This means the bit is unchanged.
            // Achieved by: & 1, | 0, ^ 0
            // No change needed for this bit in final_and_mask, final_or_mask, final_xor_mask
        } else { // bit_0_result == 1 && bit_1_result == 0
            // Input 0 -> 1, Input 1 -> 0
            // This means the bit is flipped.
            // Achieved by: ^ 1
            final_xor_mask |= bit_mask;
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit needs to be forced to 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit needs to be forced to 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit needs to be flipped
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

